-- Poems batch 334
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('c57b5544-f6d7-47bc-af4e-000ac4b07912','次韵輝卿感春  其二','呂南公','宋','宋诗','song-poetry','','[]','欲寫春愁上粉牋，只凝幽思恨遥天。',64,'全唐诗/poet.song.58000.json','["欲寫春愁上粉牋，只凝幽思恨遥天。", "塵埃漫蠹霞書字，日月終虧錦瑟弦。", "夜聽子規欹醉枕，曉看新燕立疏烟。", "冷灰殘燭相遭慣，觸撥東風不記年。"]'),
('37663144-73bc-4877-a361-0b2697993cf4','次韵輝卿感春  其三','呂南公','宋','宋诗','song-poetry','','[]','聞說羣芳初滿園，未能尋賞恨參天。',64,'全唐诗/poet.song.58000.json','["聞說羣芳初滿園，未能尋賞恨參天。", "風豪雨橫傷鶑蝶，酒冷詩荒負管弦。", "屐齒有時臨蘚徑，馬頭何日破晴烟。", "誰何贈我寬懷語，每道新年似舊年。"]'),
('41eb94ea-183f-4cc5-9e18-f1f5e84d1337','熙寧六年再至鄧氏北軒感而書壁','呂南公','宋','宋诗','song-poetry','','[]','窗扉暮闔曉還開，乞食寒儒去復來。',64,'全唐诗/poet.song.58000.json','["窗扉暮闔曉還開，乞食寒儒去復來。", "土木不妨人冷落，詩書能使客低徊。", "言如鸚鵡今徒爾，宿似夫不亦得哉。", "但識浮生皆寄託，莫從河漢論涓埃。"]'),
('f92dbef9-845f-47de-81e1-151b84a88b98','寄從義法曹教授','呂南公','宋','宋诗','song-poetry','','[]','軍學先生骨氣清，每嫌盃酒亂襟靈。',64,'全唐诗/poet.song.58000.json','["軍學先生骨氣清，每嫌盃酒亂襟靈。", "譏排只是攻三雅，熟爛除非是六經。", "榴榼日虛塵拂拂，兔毫宵運燭熒熒。", "俸錢添得真何用，好贈滎陽買綠醽。"]'),
('6d5a7ccc-c9a6-4110-8a15-5b8ddf2b9e82','奉酬范十七見寄二首  其一','呂南公','宋','宋诗','song-poetry','','[]','接人坐語送人行，兩飯逡巡晚鼓鳴。',64,'全唐诗/poet.song.58000.json','["接人坐語送人行，兩飯逡巡晚鼓鳴。", "遇社有何歡次第，過春多是病心情。", "消磨白日無云補，計算流年但暗驚。", "苦雨寂寥還一醉，夢魂依舊背嚴城。"]'),
('46a3f932-55b2-4c93-81af-96b0d95758bc','奉酬范十七見寄二首  其二','呂南公','宋','宋诗','song-poetry','','[]','一紙新詩入北城，起予聊復醉魂驚。',64,'全唐诗/poet.song.58000.json','["一紙新詩入北城，起予聊復醉魂驚。", "低心苦淡吾徒事，轉眼炎凉此世情。", "六月未須論止息，三年方看大飛鳴。", "錙銖社肉休過問，幸有鰍蔬且爛羹。"]'),
('f1b67ac8-4493-4163-abae-0d91551773e8','再和  其一','呂南公','宋','宋诗','song-poetry','','[]','浮桁門外樹如城，歸路迢迢夢易驚。',64,'全唐诗/poet.song.58000.json','["浮桁門外樹如城，歸路迢迢夢易驚。", "嗟我衰遲從旅食，感君存問有詩情。", "牡丹不在儒宮種，杜宇偏當靜夜鳴。", "勞費主公憐苦淡，駝蹄時勸一盃羹。"]'),
('3096353a-6101-436a-825f-199eeac4bb0f','再和  其二','呂南公','宋','宋诗','song-poetry','','[]','幾欲相尋出郭行，念君家雁不能鳴。',64,'全唐诗/poet.song.58000.json','["幾欲相尋出郭行，念君家雁不能鳴。", "逢杯得醉常常事，漸老多慈種種情。", "荏苒又聞寒食近，牽纏空作暮春驚。", "祇應已入東風笑，愁思長於萬里城。"]'),
('7fb3710c-43d1-4421-bc58-09a084cc2998','次韵酬亨父見寄','呂南公','宋','宋诗','song-poetry','','[]','醉墨淋灕詩屢酬，浮蛆上下酒新篘。',64,'全唐诗/poet.song.58000.json','["醉墨淋灕詩屢酬，浮蛆上下酒新篘。", "人生有此自可樂，世事無窮何足憂。", "端是覽輝同鸑鷟，不應專宿傚夫不。", "嗟予久負思山興，空得公詩展復謳。"]'),
('15561909-7c88-4dc4-bb66-6e312b9a484b','和酬天休','呂南公','宋','宋诗','song-poetry','','[]','故人邂逅早鶑時，一別經秋燕盡歸。',64,'全唐诗/poet.song.58000.json','["故人邂逅早鶑時，一別經秋燕盡歸。", "已是苦貧看客懶，更堪長病出門稀。", "何曾富貴來如夢，但覺光陰去似飛。", "欲酌清樽相解釋，莫嫌窮巷瓦盃微。"]'),
('0dc074eb-4004-42cf-8794-a21b2022c60e','酬何威中','呂南公','宋','宋诗','song-poetry','','[]','十年經畫鑿坏逃，只爲乖違不爲高。',64,'全唐诗/poet.song.58000.json','["十年經畫鑿坏逃，只爲乖違不爲高。", "盡力未能成飽煖，致身那解立勳勞。", "已從酒盞忘千慮，羞看貪人校一毛。", "游舊惟君尚相記，每將新句訪耕皋。"]'),
('c8c7ed8e-dde4-43e9-b4f4-b06295a08d70','和酬伯華','呂南公','宋','宋诗','song-poetry','','[]','襄陽耆舊足高風，不識州城有德公。',64,'全唐诗/poet.song.58000.json','["襄陽耆舊足高風，不識州城有德公。", "器業我應居衆後，姓名今恥達宸聰。", "文章末技知何用，衣食殘年嘆屢空。", "朋友贈言當儆戒，恨君虛美一篇中。"]'),
('a364b68e-f208-4880-8935-f857e815e478','道先賢良以其到郡未及相見遽寄四韵謹以酬之','呂南公','宋','宋诗','song-poetry','','[]','山人還是入闉闍，自笑窮心失本初。',64,'全唐诗/poet.song.58000.json','["山人還是入闉闍，自笑窮心失本初。", "鄭相舊憐窮禦寇，秦王新伏勇相如。", "衣裘破敝身謀拙，齒髮凋殘世味疏。", "人正棄捐吾獨取，似君風誼更誰歟。"]'),
('acbf51c7-36d2-40dc-812d-9a51eecd6502','酬次道京還見寄詩二首  其一','呂南公','宋','宋诗','song-poetry','','[]','會得吾生只汎浮，莫將耕釣異公侯。',64,'全唐诗/poet.song.58000.json','["會得吾生只汎浮，莫將耕釣異公侯。", "文章高去乃青史，富貴極來皆白頭。", "至樂如今惟强飲，最賢從古是無求。", "荷源磜上楓林葉，又過元豐第六秋。"]'),
('5e34b4e7-fedd-417b-acbf-f16b4db1edb2','酬次道京還見寄詩二首  其二','呂南公','宋','宋诗','song-poetry','','[]','平昔賢他馬少游，有官何必至封侯。',64,'全唐诗/poet.song.58000.json','["平昔賢他馬少游，有官何必至封侯。", "天如大雨當揮手，命合高眠亦到頭。", "幽澗魚肥堪煮炙，豐年酒賤易追求。", "恨君門館無酣伴，枉共癡兒對一秋。"]'),
('80aef457-7b76-4025-be6d-58b97f27327d','酬西閣書事','呂南公','宋','宋诗','song-poetry','','[]','西山閣上綵衣人，過得三冬似九春。',64,'全唐诗/poet.song.58000.json','["西山閣上綵衣人，過得三冬似九春。", "長恨作詩無客和，更緣中酒被妻嗔。", "有官未入功名境，多暇仍思寂寞濱。", "文雅一時傳萬世，却應能此是榮親。"]'),
('27b7b276-1c93-49af-b662-c5ea3956ed15','朝曦閣詩爲李道正賦','呂南公','宋','宋诗','song-poetry','','[]','道人開閣破東廂，慣看朝曦亦坐忘。',64,'全唐诗/poet.song.58000.json','["道人開閣破東廂，慣看朝曦亦坐忘。", "但見長時似車蓋，不知何處是扶桑。", "雲歸後崦陰無迹，水過前渠響自忙。", "雨露縱然能惡作，未妨微白到書床。"]'),
('c86869da-3971-450e-bf6f-34e6151fd1bb','至凌雲山却寄平仲','呂南公','宋','宋诗','song-poetry','','[]','建業歸來路二千，一舟輕借死梯緣。',64,'全唐诗/poet.song.58000.json','["建業歸來路二千，一舟輕借死梯緣。", "貴池亭下風如鼓，采石江頭浪拍天。", "險與陽侯成憤友，幸從魚腹脫腥涎。", "只今親舊知憐否，尚有餘生亦偶然。"]'),
('96ac142d-7bbf-4182-8682-68b65534fc1c','九月七日偶書','呂南公','宋','宋诗','song-poetry','','[]','愁裏光陰不覺忙，忽聞時節近重陽。',64,'全唐诗/poet.song.58000.json','["愁裏光陰不覺忙，忽聞時節近重陽。", "絕無閒藥擬衰疾，纔檢舊衣防早霜。", "未必此生專冷落，漫因往事巧思量。", "呼僮閒賞籬邊菊，併括憂端付一觴。"]'),
('73b568f0-e22f-490a-a296-8d0eed0e5115','伏睹教場後庭新移梅樹輒賦小詩呈獻內翰太中','呂南公','宋','宋诗','song-poetry','','[]','中庭移植氣蕭蕭，無數芳華壓翠條。',64,'全唐诗/poet.song.58000.json','["中庭移植氣蕭蕭，無數芳華壓翠條。", "田地縱然非舊壤，冰霜猶可見孤標。", "人間歲月何曾老，物外馨香猝未銷。", "故有明年佳實在，鉶羹滋味看和調。"]'),
('955e182b-45d4-4566-8947-3ffde69cce66','聞仙都李道士下世  其一','呂南公','宋','宋诗','song-poetry','','[]','布褐毛冠七十秋，爲誰浮汎爲誰休。',64,'全唐诗/poet.song.58000.json','["布褐毛冠七十秋，爲誰浮汎爲誰休。", "但曾計日防三鬼，不慣携琴謁五侯。", "詩卷在前聊養目，酒尊從此罷銷憂。", "七星杉下朝曦閣，香火應教弟子修。"]'),
('c70b7ab3-5452-4142-b4d7-bda88866d237','聞仙都李道士下世  其二','呂南公','宋','宋诗','song-poetry','','[]','長憶初能戴幅巾，仙都門外學游人。',64,'全唐诗/poet.song.58000.json','["長憶初能戴幅巾，仙都門外學游人。", "科場未數金門賦，襟袖空餘紫陌塵。", "平世選賢終法令，暮年如我但寒貧。", "惟師不信文章誤，只道遭逢有屈伸。"]'),
('3d1eb0c9-8210-4657-bb98-8261df7c995f','聞仙都李道士下世  其三','呂南公','宋','宋诗','song-poetry','','[]','九月霪霖穀欲登，稻芽連穗水漫塍。',64,'全唐诗/poet.song.58000.json','["九月霪霖穀欲登，稻芽連穗水漫塍。", "無方解我心愁寂，更欲聞師近寢興。", "紙尾忽傳成異物，棺中還恐已飛昇。", "羲和睡熟泥塗惡，絮酒尋澆歎未能。"]'),
('3ced35c3-1cb8-49a5-967d-64e518b76589','寄江州沈尊師','呂南公','宋','宋诗','song-poetry','','[]','洞天一別七春風，長夢桃花爛漫紅。',64,'全唐诗/poet.song.58000.json','["洞天一別七春風，長夢桃花爛漫紅。", "不得雲雷相借助，且因文學守貧窮。", "曾尋物外無窮意，已覺人間萬事空。", "便作野夫纔是分，祇嗟凡骨誤仙翁。"]'),
('601acb68-0b31-40a1-9610-b7b373d715e5','橘林居士題載溪館壁','呂南公','宋','宋诗','song-poetry','','[]','雲凍月籠影，風生水澀寒。',24,'全唐诗/poet.song.58000.json','["雲凍月籠影，風生水澀寒。", "故人真似雪，何必到門闌。"]'),
('860716d6-994d-4a09-b740-4ff3fd628d95','寄茶李侍禁','呂南公','宋','宋诗','song-poetry','','[]','東塞將軍日月閒，五兵不試坐雲間。',32,'全唐诗/poet.song.58000.json','["東塞將軍日月閒，五兵不試坐雲間。", "却因睡思侵書卷，送與茶甌解壯顔。"]'),
('d03dbc90-2881-4754-84c2-112063283ef4','過虎林渡','呂南公','宋','宋诗','song-poetry','','[]','淮南行盡到江南，野渡風高送晚帆。',32,'全唐诗/poet.song.58000.json','["淮南行盡到江南，野渡風高送晚帆。", "五五長亭莫迴首，向來窮淚已盈衫。"]'),
('f454000b-bf55-4857-a538-12c6625b6028','戲題白鶴觀','呂南公','宋','宋诗','song-poetry','','[]','八月風高宇宙清，銀河秋浪到天聲。',32,'全唐诗/poet.song.58000.json','["八月風高宇宙清，銀河秋浪到天聲。", "門前合有仙槎過，會待參隨上玉京。"]'),
('7fbc630a-c90f-4dcf-a73f-9ab5868a62c9','戲題妙靈觀怪松','呂南公','宋','宋诗','song-poetry','','[]','二十年前看怒龍，鱗鬐半已召雷風。',32,'全唐诗/poet.song.58000.json','["二十年前看怒龍，鱗鬐半已召雷風。", "至今未拂層霄去，可是懷文與我同。"]'),
('db3d1120-79c2-4792-83df-14750d59afe7','曉雨','呂南公','宋','宋诗','song-poetry','','[]','曉雨彭彭發舊泥，田家拆壁備朝炊。',32,'全唐诗/poet.song.58000.json','["曉雨彭彭發舊泥，田家拆壁備朝炊。", "無數星辰一輪月，夜來空似欲晴時。"]'),
('609cadda-e8c4-428b-835e-5f7f0f86c938','重過福興院  其一','呂南公','宋','宋诗','song-poetry','','[]','重過山寺借床眠，屈指前遊已七年。',32,'全唐诗/poet.song.58000.json','["重過山寺借床眠，屈指前遊已七年。", "文字轉工身轉困，被僧相問却悽然。"]'),
('4edd2625-93dc-4d12-b731-5570018f4ff1','重過福興院  其二','呂南公','宋','宋诗','song-poetry','','[]','乞錢謀食總悠悠，兩事平生話亦羞。',32,'全唐诗/poet.song.58000.json','["乞錢謀食總悠悠，兩事平生話亦羞。", "何意茂林脩竹下，今年還得一迴遊。"]'),
('3365afd7-9d8d-4b34-bfa0-cd2636b1fb12','和道先雨中栽花  其一','呂南公','宋','宋诗','song-poetry','','[]','二月前頭雨意迴，移花趁雨破青苔。',32,'全唐诗/poet.song.58000.json','["二月前頭雨意迴，移花趁雨破青苔。", "芳根得地春工敏，定有新英次第開。"]'),
('23f428a2-67f0-413c-b3d3-887f6588ace8','和道先雨中栽花  其二','呂南公','宋','宋诗','song-poetry','','[]','旋封旋築带霏微，贏得澆瓶不用携。',32,'全唐诗/poet.song.58000.json','["旋封旋築带霏微，贏得澆瓶不用携。", "衆草自今常避地，主人來繞漸成蹊。"]'),
('c206db3a-f07f-49af-bca6-b05f5ef3ae45','題藥錄','呂南公','宋','宋诗','song-poetry','','[]','華佗氣絕釣臺側，扁鵲墳荒浚水邊。',32,'全唐诗/poet.song.58000.json','["華佗氣絕釣臺側，扁鵲墳荒浚水邊。", "末俗好財無妙智，此書何日似魚筌。"]'),
('18437f80-16c0-4525-bd25-882f9f74af4a','茶鐺','呂南公','宋','宋诗','song-poetry','','[]','賓榻蕭蕭午戶開，松枝火盡半寒灰。',32,'全唐诗/poet.song.58000.json','["賓榻蕭蕭午戶開，松枝火盡半寒灰。", "主人欲就遊仙夢，休願煎茶醒睡來。"]'),
('259b2e5b-132d-45a7-ad41-ed491f31cf6c','風雨','呂南公','宋','宋诗','song-poetry','','[]','風雨蕭蕭夜漏沈，北窗燈影見傷心。',32,'全唐诗/poet.song.58000.json','["風雨蕭蕭夜漏沈，北窗燈影見傷心。", "從今莫更言滄海，只合思量此恨深。"]'),
('07e61d2c-fbc6-45c4-b285-92b937f84115','有見','呂南公','宋','宋诗','song-poetry','','[]','賣藥諸生體調狂，塵埃空助老來忙。',32,'全唐诗/poet.song.58000.json','["賣藥諸生體調狂，塵埃空助老來忙。", "壺中自少閒天地，豈是今無費長房。"]'),
('3f799308-c664-4cbb-aa11-7aa32dc51b2e','曉日','呂南公','宋','宋诗','song-poetry','','[]','曉日曈曈上紙窗，小爐文火近縑緗。',32,'全唐诗/poet.song.58000.json','["曉日曈曈上紙窗，小爐文火近縑緗。", "衝愁滿盞扶頭酒，笑殺醫師第一方。"]'),
