('277fed1b-bab9-4607-a6d2-759d14da02f4','魏勃','呂南公','宋','宋诗','song-poetry','','[]','雖發齊兵未不臣，問時何用便銷魂。',32,'全唐诗/poet.song.58000.json','["雖發齊兵未不臣，問時何用便銷魂。", "一生才勇都纖小，可怪區區掃相門。"]'),
('390c16f4-e31d-4d33-b081-03788e634ec9','禰衡','呂南公','宋','宋诗','song-poetry','','[]','世亂無人及禰衡，眼看豺虎似蚊蠅。',32,'全唐诗/poet.song.58000.json','["世亂無人及禰衡，眼看豺虎似蚊蠅。", "喬玄荀彧皆儒雅，至死何曾曉愛憎。"]'),
('bfc3b624-a1f2-4312-9d83-a2eede93ee18','覆船山','呂南公','宋','宋诗','song-poetry','','[]','山似舟航壓衆坡，靜爲平地動爲波。',32,'全唐诗/poet.song.58000.json','["山似舟航壓衆坡，靜爲平地動爲波。", "桅檣不藉瞻烏首，爭奈風帆百尺何。"]'),
('77600aa3-f3d6-4ce2-b5b5-3c1444e64a63','過武陵翁題其屋壁  其一','呂南公','宋','宋诗','song-poetry','','[]','十年騎馬走紅塵，非敢求爲富貴人。',32,'全唐诗/poet.song.58000.json','["十年騎馬走紅塵，非敢求爲富貴人。", "只願似他龔處士，不餘不欠一閒身。"]'),
('411415c1-f1ad-4b24-b683-e934c567ef8f','過武陵翁題其屋壁  其二','呂南公','宋','宋诗','song-poetry','','[]','綠竹林邊白髮翁，面顔猶似壯時紅。',32,'全唐诗/poet.song.58000.json','["綠竹林邊白髮翁，面顔猶似壯時紅。", "朝來賣藥錢多少，又閃閒愁入醉中。"]'),
('6d4d6dc8-5f2a-43f7-b618-672742b8a5fd','廢井','呂南公','宋','宋诗','song-poetry','','[]','清不能常濁有餘，轆轤音絕甃苔枯。',32,'全唐诗/poet.song.58000.json','["清不能常濁有餘，轆轤音絕甃苔枯。", "荒凉欲就羣蛙問，今有觀天坐客無。"]'),
('0e85e804-6c9b-48c5-8f36-4500632bdd36','見廣度院紫荆一株先開','呂南公','宋','宋诗','song-poetry','','[]','滿樹新英待發時，東風先動向陽枝。',32,'全唐诗/poet.song.58000.json','["滿樹新英待發時，東風先動向陽枝。", "同根若是生疑怪，爲道開遲謝亦遲。"]'),
('cc4b2f56-b516-4cf7-981e-a96bb37f0c89','蘭溪驛','呂南公','宋','宋诗','song-poetry','','[]','驛亭何處近蘭溪，行盡蓮華日暮時。',32,'全唐诗/poet.song.58000.json','["驛亭何處近蘭溪，行盡蓮華日暮時。", "春雨發香無分見，斷腸頻誦杜郎詩。"]'),
('64814974-836d-4621-96ee-4fefee88275b','惡客','呂南公','宋','宋诗','song-poetry','','[]','惡客無端捨舊山，坐令千慮險相關。',32,'全唐诗/poet.song.58000.json','["惡客無端捨舊山，坐令千慮險相關。", "青燈白日貧兼病，聽著農桑更厚顔。"]'),
