('a4e1ec24-8e61-4689-ace1-c328a4745276','夜擬李義山四更四點','呂南公','宋','宋诗','song-poetry','','[]','四更四點露成霜，箇裏愁人暗斷腸。',32,'全唐诗/poet.song.58000.json','["四更四點露成霜，箇裏愁人暗斷腸。", "鼓角未喧聞鼻鼾，北風窗戶月荒凉。"]'),
('d960b007-8597-4c29-b75d-69626e193924','反李義山人欲篇','呂南公','宋','宋诗','song-poetry','','[]','藥囊易中荆卿背，匕首難傷趙政胸。',32,'全唐诗/poet.song.58000.json','["藥囊易中荆卿背，匕首難傷趙政胸。", "燕國無辜竟魚肉，可能人欲有天從。"]'),
('4f200f99-5dff-4210-affc-23c742131d8c','題圓上人宴靜軒','呂南公','宋','宋诗','song-poetry','','[]','宴安深靜屬居僧，一炷檀烟萬慮清。',32,'全唐诗/poet.song.58000.json','["宴安深靜屬居僧，一炷檀烟萬慮清。", "猶自笑他簷外鐸，風來未免鬭鳴聲。"]'),
('87e75664-a570-4158-a141-02e1bde28858','客到','呂南公','宋','宋诗','song-poetry','','[]','客到空齋說早春，嫩紅輕綠漸紛紛。',32,'全唐诗/poet.song.58000.json','["客到空齋說早春，嫩紅輕綠漸紛紛。", "寒人不預尋芳品，多謝東風許聽聞。"]'),
('8f4b6dae-d325-4c16-9cfb-ebcf9f8be108','答內翰太中觀插稻見寄','呂南公','宋','宋诗','song-poetry','','[]','睡過春深一月餘，綠秧黄犢負村居。',32,'全唐诗/poet.song.58000.json','["睡過春深一月餘，綠秧黄犢負村居。", "東風似恨歸耕晚，故遣藜床日枕書。"]'),
('936e0d15-de82-487a-a25b-bef7e1243303','楊朱','呂南公','宋','宋诗','song-poetry','','[]','戰國功名尺寸勞，先生持論異吾曹。',32,'全唐诗/poet.song.58000.json','["戰國功名尺寸勞，先生持論異吾曹。", "孟軻解辯承三聖，後世誰曾拔一毛。"]'),
('c31713f2-9778-406b-8221-5ca62207ac52','陳都曹座中出示諸公曲詞以四句酬之','呂南公','宋','宋诗','song-poetry','','[]','看盡新詞聽盡聲，未能高和耳徒傾。',32,'全唐诗/poet.song.58000.json','["看盡新詞聽盡聲，未能高和耳徒傾。", "聾身縱作岐山老，爭得聞他彩鳳鳴。"]'),
('7549bf08-3915-4c67-9064-bb67d845be3d','真輝閣','呂南公','宋','宋诗','song-poetry','','[]','會得真時真亦空，光輝何足更流通。',32,'全唐诗/poet.song.58000.json','["會得真時真亦空，光輝何足更流通。", "勸師不用嚴標榜，瞀者逢燈與暗同。"]'),
('e0f48136-67ce-4066-b94d-ba20d52d9623','安昌縣侯','呂南公','宋','宋诗','song-poetry','','[]','能說齊論與魯論，世儒希合便紛紛。',32,'全唐诗/poet.song.58000.json','["能說齊論與魯論，世儒希合便紛紛。", "何曾後學皆傳信，祇有姦名萬古聞。"]'),
('484d6f75-0000-473a-905c-aff56c4f37d3','小檻','呂南公','宋','宋诗','song-poetry','','[]','小檻幽花已破香，此心無處避韶光。',32,'全唐诗/poet.song.58000.json','["小檻幽花已破香，此心無處避韶光。", "年年惡作傷春客，穩爲東風細斷腸。"]'),
('9e2ad5c9-c304-4cd5-bb61-521925212a86','楊八送筍以四句謝之時在湖口','呂南公','宋','宋诗','song-poetry','','[]','殺却盧家十五龍，野人盤饌當時豐。',32,'全唐诗/poet.song.58000.json','["殺却盧家十五龍，野人盤饌當時豐。", "湖干少得中林味，此日鄉心轉不同。"]'),
('b19d9ba6-59d4-4624-b307-5624db07d809','讀白司馬江州詩','呂南公','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','四年司馬滯江邊，几杖茅堂自說閑。',32,'全唐诗/poet.song.58000.json','["四年司馬滯江邊，几杖茅堂自說閑。", "倘使金鑾不遷謫，知君未暇愛廬山。"]'),
('c240841e-dfcf-4293-ac0b-43a1d3fc64a2','獻陳和叔內翰','呂南公','宋','宋诗','song-poetry','','[]','留滯周南事可嗟，東風三度見梅花。',64,'全唐诗/poet.song.58000.json','["留滯周南事可嗟，東風三度見梅花。", "巖廊未引經綸手，山國頻聽早晚衙。", "酒爲憂民傾日月，詩從思退寫烟霞。", "賓籌更有林中士，誰及船齋太守家。"]'),
('fb1cc952-440b-4943-b4cf-ad31c2b56d9b','九月二十三日過黄家嶺望行春門有感','呂南公','宋','宋诗','song-poetry','','[]','閒雲泛淡水浮浮，秋色陰時刺眼愁。',64,'全唐诗/poet.song.58000.json','["閒雲泛淡水浮浮，秋色陰時刺眼愁。", "十載未成三窟計，一身長带百年憂。", "逢人語笑非良味，洒面塵埃豈自由。", "望見故山歸不得，小欄高檻更迴頭。"]'),
('a7cd8e1a-8ce5-4dbc-9098-add9a625164e','五賢堂','呂南公','宋','宋诗','song-poetry','','[]','漢唐相望向千年，此地追崇祇五賢。',64,'全唐诗/poet.song.58000.json','["漢唐相望向千年，此地追崇祇五賢。", "器業不同流俗淺，聲容終得後人傳。", "壁間碑版敲新墨，砌下莓苔長野錢。", "何似淫祠專禍福，歌吹士女日諠闐。"]'),
('462200f3-4142-4fed-bece-fd9216d4d8c4','句','呂南公','宋','宋诗','song-poetry','','[]','溪田橋畔駝鞍嶺，猶記當年志未平。',16,'全唐诗/poet.song.58000.json','["溪田橋畔駝鞍嶺，猶記當年志未平。"]'),
('fed0df69-293c-47e4-a72a-2ddd0ab262b9','太父太師密國公賦詩江樓世稱名筆從姪子績得之以居肇緬思祖德且愛績之能繼志也爲賦一首','曾肇','宋','宋诗','song-poetry','','[]','當年太史謫仙翁，筆落江樓氣吐虹。',64,'全唐诗/poet.song.58000.json','["當年太史謫仙翁，筆落江樓氣吐虹。", "無復琴樽對鷗鳥，空遺松栢幾秋風。", "由來蘭玉生臺下，重見溪山入坐中。", "顧我豈能繩祖武，倚闌歸思附冥鴻。"]'),
('4349f81a-f070-4263-8a39-074e11ee5aa6','次兄子宣先生作高陽衆樂園成被命金陵易鎮韵','曾肇','宋','宋诗','song-poetry','','[]','文物河間信可嘉，風流江左亦堪誇。',64,'全唐诗/poet.song.58000.json','["文物河間信可嘉，風流江左亦堪誇。", "水南水北千竿竹，山後山前二月花。", "久愧迂儒懷郡紱，聊須雋老駐軍牙。", "兩州耆舊無多怪，魯衛從來是一家。"]'),
('f0e5afb7-c14d-4295-ad4d-b37c9bc8f590','遊石仙巖次兄子宣公韵','曾肇','宋','宋诗','song-poetry','','[]','塵埃華髮換朱顔，十載重來款故關。',64,'全唐诗/poet.song.58000.json','["塵埃華髮換朱顔，十載重來款故關。", "天下樓臺春寂寂，洞中鷄犬晝閑閑。", "苔深尚識曾題石，木老難尋舊戲環。", "未斷凡心却歸去，他年飛鳥會知還。"]'),
('511ed31d-1063-4901-b3ba-f858f30bfce9','族兄山莊','曾肇','宋','宋诗','song-poetry','','[]','宦路崎嶇寄此身，羨君築室離囂塵。',64,'全唐诗/poet.song.58000.json','["宦路崎嶇寄此身，羨君築室離囂塵。", "能將孝謹傳家法，何用聲名動世人。", "桑落百壺甯惜醉，竹竿千畝不憂貧。", "求田更欲依丘壠，來往他時願卜鄰。"]'),
('64f3d976-9483-4e30-9a90-5b3961a08b69','出門寄家','曾肇','宋','宋诗','song-poetry','','[]','出門日日念歸期，恐過歸期未得歸。',64,'全唐诗/poet.song.58000.json','["出門日日念歸期，恐過歸期未得歸。", "畫角數聲來別浦，孤帆一點背斜暉。", "行逢山樹秋前落，坐見江雲水上飛。", "盡是南人好風景，客心驚此却依依。"]'),
('3ca361b4-9e87-491b-b720-fd21ccd4addf','寄呂南公','曾肇','宋','宋诗','song-poetry','','[]','主人第一河南守，之子無雙江夏才。',64,'全唐诗/poet.song.58000.json','["主人第一河南守，之子無雙江夏才。", "會見吹噓上雲漢，可能憔悴隠蒿萊。", "風騷寓興垂金薤，翰墨傳家富玉杯。", "傾蓋相知勝白首，扁舟臨別重徘徊。"]'),
('77b0d925-df0e-47b6-ae11-32d96fe24d36','淮南道中','曾肇','宋','宋诗','song-poetry','','[]','四山蓊鬰氣朝隮，晚雨廉纖未有泥。',64,'全唐诗/poet.song.58000.json','["四山蓊鬰氣朝隮，晚雨廉纖未有泥。", "鴨綠幾尋塘水浸，鵝黄一段稻秧齊。", "幽花布地金錢小，野蔓縈林翠幄低。", "滿目淮南風景好，不堪時聽子規啼。"]'),
('c359ca97-4550-48ed-b182-23bed23c543d','海陵春雨日','曾肇','宋','宋诗','song-poetry','','[]','公事無多使客稀，雨時衙退吏人歸。',64,'全唐诗/poet.song.58000.json','["公事無多使客稀，雨時衙退吏人歸。", "沉烟一炷春陰重，畫角三聲晚照微。", "桑雉未馴慚報政，海鷗相近信忘機。", "只將宴坐收心念，懶向人間問是非。"]'),
('b851e18c-f828-4469-98a2-64ea084b6a41','南郭隠居','曾肇','宋','宋诗','song-poetry','','[]','南郭蕭條居士家，斷垣荒塹翳蓬麻。',64,'全唐诗/poet.song.58000.json','["南郭蕭條居士家，斷垣荒塹翳蓬麻。", "篔簹映水千竿直，略彴當門一徑斜。", "老有圖書忘世界，貧無杯酌送生涯。", "倘來軒冕何須貴，未勝牛衣駕鹿車。"]'),
('b72e4130-8803-4d9f-84ab-7afbe6526042','次後山陳師道見寄韵','曾肇','宋','宋诗','song-poetry','','[]','故人南北嘆乖離，忽把清詩慰所思。',64,'全唐诗/poet.song.58000.json','["故人南北嘆乖離，忽把清詩慰所思。", "松茂雪霜無改色，鷄鳴風雨不愆時。", "著書子已通蝌蚪，竊食吾方逐鸒斯。", "便欲去爲林下友，懶隨年少樂新知。"]'),
('693a0814-9b90-4941-9c35-3faec7ea6c15','京口甘露寺','曾肇','宋','宋诗','song-poetry','','[]','屈曲危樓倚半空，詩情無限景無窮。',64,'全唐诗/poet.song.58000.json','["屈曲危樓倚半空，詩情無限景無窮。", "江聲逆順潮來往，山色有無烟淡濃。", "風月滿樓供一覽，乾坤萬里豁雙瞳。", "片雲迥逐斜陽去，知落淮山第幾重。"]'),
('df6aa429-43ae-42b0-9107-79663254ea7d','元祐六年十月庚午駕自景陵宮移仗謁先聖孔子祠入門降輦步就小次由東階以升奠爵再拜禮官告成禮然後退幸太學詔博士皆升堂坐諸生兩廡下命國子祭酒豐稷講書無逸終篇因又幸武成王廟而還左丞相呂大防右丞相劉摯率百官皆從於是丞相賦詩以形容上德諸在位者皆屬和肇以禮官忝從諸大夫之後謹和詩一章','曾肇','宋','宋诗','song-poetry','','[]','琳館陪祠日未央，隆儒詔蹕至膠庠。',64,'全唐诗/poet.song.58000.json','["琳館陪祠日未央，隆儒詔蹕至膠庠。", "橋門億萬衣冠集，闕里三千弟子行。", "降輦橫經尊往聖，垂裳論道法前王。", "宗公歸美清風誦，穆若賡酬出廟堂。"]'),
('404f4080-7b8b-47a5-9bf5-d80750a05c9e','武夷山天柱峰','曾肇','宋','宋诗','song-poetry','','[]','燕越相望路八千，忽驚天柱落樽前。',32,'全唐诗/poet.song.58000.json','["燕越相望路八千，忽驚天柱落樽前。", "何如乞我雙鳬舄，飛上峰頭訪列仙。"]'),
('8d1afac0-e449-40d3-ab86-97532f6bf103','南昌繡谷山幽谷亭','曾肇','宋','宋诗','song-poetry','','[]','行盡車馬塵，踏見水石環。',24,'全唐诗/poet.song.58000.json','["行盡車馬塵，踏見水石環。", "誰爲千家縣，正在清華間。"]'),
('5b68f4cf-e9c4-47f8-be9e-8dff6455fc5f','滁州琅玡山茶仙亭','曾肇','宋','宋诗','song-poetry','','[]','山僧獨好事，爲我結茅茨。',24,'全唐诗/poet.song.58000.json','["山僧獨好事，爲我結茅茨。", "茶仙榜亭中，頗宗樊川詩。"]'),
('a52343e5-6453-4048-a77c-0e8990e3f733','靈壽同年兄再以杞屑分惠復成小詩以代善謔','曾肇','宋','宋诗','song-poetry','','[]','場屋十年長，鈴齋一笑歡。',48,'全唐诗/poet.song.58000.json','["場屋十年長，鈴齋一笑歡。", "微言師水薤，交分託金蘭。", "腹飽仙人杖，心存姹女丹。", "他時玉京路，同綴侍宸官。"]'),
('bb4a2645-a568-41e0-9c2a-475dc6689236','上王荆公墓','曾肇','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','天上龍胡斷，人間鵩鳥來。',48,'全唐诗/poet.song.58000.json','["天上龍胡斷，人間鵩鳥來。", "未應淮水竭，所惜泰山頹。", "華屋今非昔，佳城閉不開。", "白頭門下士，悵望有餘哀。"]'),
('1cf37882-9747-45c4-8fa6-61e02ef4bcc1','河間','曾肇','宋','宋诗','song-poetry','','[]','南北車書久混同，河間今有楚人風。',32,'全唐诗/poet.song.58000.json','["南北車書久混同，河間今有楚人風。", "獨慚太守非何武，已見州閭出兩龔。"]'),
('6bd4b6cf-c88a-4319-a5d5-3ac6ced84648','二賢堂  其一','曾肇','宋','宋诗','song-poetry','','[]','天驥精神鳳羽儀，青雲天路此委蛇。',64,'全唐诗/poet.song.58000.json','["天驥精神鳳羽儀，青雲天路此委蛇。", "由來道誼千鈞重，不獨文章一世師。", "史牒已傳三黜賦，騷人誰繼八哀詩。", "有時無命非今日，從古長沙賈傅悲。"]'),
('668fbe9c-94de-4fb2-bd42-3b7d12ec94ad','二賢堂  其二','曾肇','宋','宋诗','song-poetry','','[]','萬壑千巖花草香，醉翁此地昔徜徉。',64,'全唐诗/poet.song.58000.json','["萬壑千巖花草香，醉翁此地昔徜徉。", "不聞燕雀知鴻鵠，但見鴟梟笑鳳凰。", "平日聲名追屈賈，暮年勳業佐虞唐。", "神清洞府今何處，故事空留楚天傍。"]'),
('e0e7dc8b-296c-4586-bd28-8fa567aad460','鳳凰臺','曾肇','宋','宋诗','song-poetry','','[]','簫聲無復到層臺，畫棟空餘燕雀來。',32,'全唐诗/poet.song.58000.json','["簫聲無復到層臺，畫棟空餘燕雀來。", "我是鳳凰池上客，等閑汀鷺莫相猜。"]'),
('a02721c2-1b06-4639-b606-a9f52f777084','凌霄花','曾肇','宋','宋诗','song-poetry','','[]','凌波條體纖，柔枝葉上綴。',36,'全唐诗/poet.song.58000.json','["凌波條體纖，柔枝葉上綴。", "青青亂松樹，直幹遭蒙蔽。", "不有嚴霜威，焉能辨堅脆。"]'),
('51dec058-aeb2-4dcc-abaa-7395e1f192cc','紫薇花  其一','曾肇','宋','宋诗','song-poetry','','[]','堂前紫薇花，堂下紅藥砌。',24,'全唐诗/poet.song.58000.json','["堂前紫薇花，堂下紅藥砌。", "繁華天上春，偪仄人間世。"]'),
('4c01d11b-d09a-4923-8bb3-8944fa267d2c','紫薇花  其二','曾肇','宋','宋诗','song-poetry','','[]','明麗碧天霞，千茸紫綬花。',48,'全唐诗/poet.song.58000.json','["明麗碧天霞，千茸紫綬花。", "香開荀令宅，艷入孝王家。", "幾歲自榮辱，高情方嘆嗟。", "有人移上苑，猶足占年華。"]'),
('a4a57643-a0c8-467f-8b9f-1938eee53af9','靈壽木','曾肇','宋','宋诗','song-poetry','','[]','滇池藤赤人難到，太乙青藜事近誣。',32,'全唐诗/poet.song.58000.json','["滇池藤赤人難到，太乙青藜事近誣。", "林下搘來供燕息，省中携去寵師儒。"]'),
('ac82a2b8-c033-452c-a9ad-745857617621','薝蔔花','曾肇','宋','宋诗','song-poetry','','[]','林蘭擅孤芳，性與凡木異。',36,'全唐诗/poet.song.58000.json','["林蘭擅孤芳，性與凡木異。", "不受雪霰侵，自足中和氣。", "欲知清凈身，即此林間是。"]'),
('ce683bac-2648-4360-b17d-7750dc82ef5f','南豐軍山廟碑','曾肇','宋','宋诗','song-poetry','','[]','土膏起兮，泉流駛兮。',200,'全唐诗/poet.song.58000.json','["土膏起兮，泉流駛兮。", "牧徂於田，偕婦子兮。", "既耕且藝，耘且耔兮。", "一歲之功，在勤始兮。", "野無蟊螟，塘有水兮。", "非神之力，其誰使兮。", "我苞盈兮，我實成兮。", "揮鐮銍銍，風雨聲兮。", "囷倉露積，如坻京兮。", "遺𥟱滯穗，富鰥煢兮。", "飲食勸酬，銷忿爭兮。", "儻非神助，歲莫登兮。", "我有室家，神所祐兮。", "我有旌倪，神所壽兮。", "神之惠我，維其舊兮。", "上之報神，亦云厚兮。", "釃酒刑牲，殽杯豐兮。", "吹簫考鼓，聲逢逢兮。", "我民薦獻，無終窮兮。", "千秋萬歲，保斯宮兮。"]'),
('ba8bb70e-c2e8-4e59-964f-6762e4329ca0','題王晉卿所藏鄭虔著色山水圖','曾肇','宋','宋诗','song-poetry','','[]','曾訪江南鳥爪仙，誤隨塵網落人間。',32,'全唐诗/poet.song.58000.json','["曾訪江南鳥爪仙，誤隨塵網落人間。", "紅泉碧澗春風里，尚記麻源谷口山。"]'),
('4e8f334d-f7df-49bc-bcf2-3881429903ac','邇英閣侍讀筵作','曾肇','宋','宋诗','song-poetry','','[]','二閣從容訪古今，諸儒葵藿但傾心。',32,'全唐诗/poet.song.58000.json','["二閣從容訪古今，諸儒葵藿但傾心。", "君臣相對疑賓客，誰識昭陵用意深。"]'),
('74cf124e-063e-4c52-89a8-4a829e5233f0','邇英閣前槐後竹雙槐極高而柯葉拂地狀如龍蛇或謂之鳳尾槐','曾肇','宋','宋诗','song-poetry','','[]','鳳尾扶疏槐影寒，龍吟蕭瑟竹聲乾。',32,'全唐诗/poet.song.58000.json','["鳳尾扶疏槐影寒，龍吟蕭瑟竹聲乾。", "漢皇恭默尊儒學，不似公孫見不冠。"]'),
('b05d8309-83a0-4ec8-91b5-35ab97b9c24a','句  其一','曾肇','宋','宋诗','song-poetry','','[]','巖巖九門深，日舉費十萬。',72,'全唐诗/poet.song.58000.json','["巖巖九門深，日舉費十萬。", "忽于泥滓中，得列方丈案。", "腥鹹置齒牙，光彩生顧眄。", "從此辱虛名，歲先包橘獻。", "微生知幾何，得喪孰真贋。", "玉食有云補，刳腸非所患。"]'),
('b2f43f18-800f-4383-a99a-1cfbedb7f369','句  其二','曾肇','宋','宋诗','song-poetry','','[]','蜜雲新樣尤可喜，名出元豐聖天子。',16,'全唐诗/poet.song.58000.json','["蜜雲新樣尤可喜，名出元豐聖天子。"]'),
('f90e8bbb-5025-422d-8bab-bc86f17750a0','句  其三','曾肇','宋','宋诗','song-poetry','','[]','鼎湖弓劍仙游遠，渭水衣冠輦路新。',16,'全唐诗/poet.song.58000.json','["鼎湖弓劍仙游遠，渭水衣冠輦路新。"]'),
('49f439b2-010d-47d6-8e2b-38d2e98a8a01','句  其四','曾肇','宋','宋诗','song-poetry','','[]','階除翠色迷宮草，殿閣清陰老禁槐。',16,'全唐诗/poet.song.58000.json','["階除翠色迷宮草，殿閣清陰老禁槐。"]'),
('dcd65bc3-bdae-4f7d-a34e-6945cae97bdf','句  其五','曾肇','宋','宋诗','song-poetry','','[]','夜雨暗添西澗水，春風開遍北樓花。',16,'全唐诗/poet.song.58000.json','["夜雨暗添西澗水，春風開遍北樓花。"]'),
('b6486bc3-2a1d-4cdd-aefc-2a4bee6fe2db','句  其六','曾肇','宋','宋诗','song-poetry','','[]','飲罷流連未歸去，更來花下捧茶甌。',16,'全唐诗/poet.song.58000.json','["飲罷流連未歸去，更來花下捧茶甌。"]'),
('9f4cc13b-ca61-4824-99be-d7bdb78b721f','句  其七','曾肇','宋','宋诗','song-poetry','','[]','紫蒂黄苞破臘寒，清香旋逐角聲殘。',16,'全唐诗/poet.song.58000.json','["紫蒂黄苞破臘寒，清香旋逐角聲殘。"]'),
('87e7c951-dd4d-488e-984f-0bc9da6cd53c','句  其八','曾肇','宋','宋诗','song-poetry','','[]','一片朝雲粉面乾，雨餘仍带淚闌干。',16,'全唐诗/poet.song.58000.json','["一片朝雲粉面乾，雨餘仍带淚闌干。"]'),
('e3da84bc-ae65-4eb4-8970-8330fa371f30','句  其九','曾肇','宋','宋诗','song-poetry','','[]','團團桂叢孤，枝葉寒更媚。',36,'全唐诗/poet.song.58000.json','["團團桂叢孤，枝葉寒更媚。", "托根庭宇間，自有幽人致。", "何必問嫦娥，青雲借餘地。"]'),
('8842d130-ce27-4ab4-bb1b-11e642c57432','句  其一○','曾肇','宋','宋诗','song-poetry','','[]','國艷寧施粉，天香自染衣。',12,'全唐诗/poet.song.58000.json','["國艷寧施粉，天香自染衣。"]'),
('6a781acc-0147-4a43-8cbb-a8c0500c950f','句  其一一','曾肇','宋','宋诗','song-poetry','','[]','風雨離披枝葉瘦，可憐終不減清香。',16,'全唐诗/poet.song.58000.json','["風雨離披枝葉瘦，可憐終不減清香。"]'),
('9c8c3b81-d97a-41ae-ab2c-6a700ca4462a','句  其一二','曾肇','宋','宋诗','song-poetry','','[]','春蘭抱幽姿，無意生蒿艾。',12,'全唐诗/poet.song.58000.json','["春蘭抱幽姿，無意生蒿艾。"]'),
('cda2ec01-002c-4de4-9ce4-cc79992fd109','句  其一三','曾肇','宋','宋诗','song-poetry','','[]','文園渴疾正如酲，誰念流涎向側生。',16,'全唐诗/poet.song.58000.json','["文園渴疾正如酲，誰念流涎向側生。"]'),
('07e924a8-b2cf-4936-8e22-4057eadf4e8c','句  其一四','曾肇','宋','宋诗','song-poetry','','[]','蘭蕙香浮衿解後，雪冰膚在酒酣間。',16,'全唐诗/poet.song.58000.json','["蘭蕙香浮衿解後，雪冰膚在酒酣間。"]'),
('c72eef62-b03c-4943-a6a4-1098ae533d72','句  其一五','曾肇','宋','宋诗','song-poetry','','[]','童童雙棕櫚，葱蒨兩車蓋。',12,'全唐诗/poet.song.58000.json','["童童雙棕櫚，葱蒨兩車蓋。"]'),
('86e5ec83-a2dd-407e-92c3-f8a7d8d879ca','句  其一六','曾肇','宋','宋诗','song-poetry','','[]','雖非百尺材，歲晚好顔色。',12,'全唐诗/poet.song.58000.json','["雖非百尺材，歲晚好顔色。"]'),
('13fd4e76-3a90-4406-9027-fc4ac229b4a1','句  其一七','曾肇','宋','宋诗','song-poetry','','[]','婆娑兩佳木，生長在巖石。',24,'全唐诗/poet.song.58000.json','["婆娑兩佳木，生長在巖石。", "移植君子堂，初因醉翁識。"]'),
('8c08ee1a-5112-4127-9a51-ac1e60a3d7ef','句  其一八','曾肇','宋','宋诗','song-poetry','','[]','查侯得靈藥，言自八公來。',24,'全唐诗/poet.song.58000.json','["查侯得靈藥，言自八公來。", "當時雲中犬，千歲伏陳荄。"]'),
('79eb09bc-8006-4dc6-8781-142fdc878b68','句  其一九','曾肇','宋','宋诗','song-poetry','','[]','君不見莆陽學士蓬萊仙，製成月團飛上天。',35,'全唐诗/poet.song.58000.json','["君不見莆陽學士蓬萊仙，製成月團飛上天。", "南北自此俱歲貢，寸璧往往人間傳。"]'),
('b91043f4-bb2e-413c-92a7-a23c54c2b25f','句  其二○','曾肇','宋','宋诗','song-poetry','','[]','蘼蕪有香葉，采采乘清旦。',36,'全唐诗/poet.song.58000.json','["蘼蕪有香葉，采采乘清旦。", "山頭去婦思，堂下騷人怨。", "使君亦何爲，烹茶奉閒燕。"]'),
('1ee20e65-9ae3-45f5-91b5-d0dfdd3ea79c','雞鳴行','畢仲游','宋','宋诗','song-poetry','','[]','雞鳴問路行，挾馬渡溱洧。',96,'全唐诗/poet.song.58000.json','["雞鳴問路行，挾馬渡溱洧。", "老樹勢突兀，指點疑山觜。", "茅茨漸分明，牛馬猶昏翳。", "霜落路四平，星沉天若水。", "小民幸安樂，朝廷多賢士。", "食祿乃强顔，流連爲妻子。", "吾聞嵇阮輩，放蕩形骸弛。", "而我小縣中，區區又何理。"]'),
('749fecb8-1484-447a-a3e9-2fab37896cb2','自羅山入信陽再過金關道中作','畢仲游','宋','宋诗','song-poetry','','[]','陰林寂無風，鬼火自明滅。',48,'全唐诗/poet.song.58000.json','["陰林寂無風，鬼火自明滅。", "山泉怨何事，耳聲入嗚咽。", "青泥濺馬腹，黄葉沾人髮。", "半夜渡前溪，昏昏水中月。"]'),
('37e0f708-43dd-4a21-8d2e-9927232d7660','自山陽還至壽春道中有感','畢仲游','宋','宋诗','song-poetry','','[]','寒風切人骨，晴日淡無色。',48,'全唐诗/poet.song.58000.json','["寒風切人骨，晴日淡無色。", "千里今又還，何時許安宅。", "此身方齟齬，此地尤反側。", "安得羽翼生，高飛離楚澤。"]'),
('69e61f5c-9ee2-4c92-94b9-a139d8b255b1','潁河夜泛','畢仲游','宋','宋诗','song-poetry','','[]','提携俯清流，自適固閒燕。',120,'全唐诗/poet.song.58000.json','["提携俯清流，自適固閒燕。", "深行豈不好，路遠怯縈轉。", "撐舟上孤渚，星月燦水面。", "目力不自收，隨波起花眩。", "誰家種禾黍，綠色壓秋甸。", "樹密雲更深，雲昏山不見。", "盃盤任狼籍，起坐有餘戀。", "幸偶東山儒，况逢京國彥。", "何人發高詠，滿坐清風遍。", "顧我童子吟，奚能愧雕篆。"]'),
('655e564d-0b82-4157-8354-bf48043ef602','從范龍圖月下泛舟','畢仲游','宋','宋诗','song-poetry','','[]','年豐閭里安，歲晚生事歇。',144,'全唐诗/poet.song.58000.json','["年豐閭里安，歲晚生事歇。", "官池公載酒，痛飲消日月。", "迫冬上青林，山氣凋人髮。", "坐若江海遊，樓船中夜發。", "冷光飛太虛，照我盤中蕨。", "清影落潭心，逃遁蛟龍沒。", "如窮河源邈，相見崑崙崒。", "怪石鈎我衣，嵌空盡山骨。", "上賓富佳詠，音動黿鼉窟。", "涌溢詞有源，倒恐三江竭。", "公懷滄洲趣，一夕夢南越。", "別有諫諍姿，屹如韋補闕。"]'),
('be93c98f-ce16-407d-8ff7-5849c7abe6ac','五更','畢仲游','宋','宋诗','song-poetry','','[]','五更不成夢，起坐倚東壁。',48,'全唐诗/poet.song.58000.json','["五更不成夢，起坐倚東壁。", "曉月下中天，照我西屋白。", "路行相衝衝，林宿聞啞啞。", "便欲就巾冠，巾冠正狼籍。"]'),
('f41943ec-cfa1-4052-87db-abed346dd12d','自靈泉晚過崇因寺口占','畢仲游','宋','宋诗','song-poetry','','[]','前峰竦而嵬，後峰屹且峨。',48,'全唐诗/poet.song.58000.json','["前峰竦而嵬，後峰屹且峨。", "冷月射溪水，緊風平野火。", "同遊獨無語，此意誰知我。", "虎避無情人，出門不須鎖。"]'),
('39c693e6-dea4-4826-ab85-7d275b639fa8','宿崇因寺十韵','畢仲游','宋','宋诗','song-poetry','','[]','山大石巖巖，平川沙莽莽。',120,'全唐诗/poet.song.58000.json','["山大石巖巖，平川沙莽莽。", "深崖忽有路，一寺何高敞。", "彼僧胡爲知，迎我共攀上。", "夜深眺前峰，百里如指掌。", "詩翁旋沽酒，欲得詠今曩。", "下筆皆珠璣，嗟予豈能仰。", "往來氣益乘，欲敵不敢往。", "回笑塵埃人，何殊在羅網。", "吟哦不自制，逸韵彌清響。", "便可書壁東，留爲異時賞。"]'),
('3a770e73-d008-4983-8972-7b34ac12407c','和子思舅氏晚出崇因之什','畢仲游','宋','宋诗','song-poetry','','[]','烟花寒已凝，風色寒猶惡。',48,'全唐诗/poet.song.58000.json','["烟花寒已凝，風色寒猶惡。", "路雪愛縈綿，簷澌訝垂籜。", "途行想前事，數歲只如昨。", "漸欲過陰崖，愁看冰鑿鑿。"]'),
('6f7eba0d-7fd5-450b-8218-b7cee650dab1','留別陳子思舅','畢仲游','宋','宋诗','song-poetry','','[]','三載豈不長，回念如轉燭。',120,'全唐诗/poet.song.58000.json','["三載豈不長，回念如轉燭。", "南行在今夕，何以圖款曲。", "朱輪走岐路，夫子駕牛犢。", "權門聚冠裳，夫子偃空谷。", "甘貧分始定，樂道心乃足。", "自怪離別間，悽然悲滿目。", "欲爲商聲操，操變不可復。", "欲爲秦聲吟，吟短不可續。", "杯行竟無語，慷慨遶空屋。", "別後兩如何，祇應保饘粥。"]'),
('16154901-ac50-4135-b5c3-a183632cf8ac','佳辰','畢仲游','宋','宋诗','song-poetry','','[]','春風雪中來，吹我堂上茵。',96,'全唐诗/poet.song.58000.json','["春風雪中來，吹我堂上茵。", "斑衣次命服，左右如卿雲。", "芳樽洗復酌，再拜屬吾親。", "親年如大家，四子十二孫。", "子孫亦何事，忠孝而能文。", "請看今世願，不必辭賤貧。", "三牲苦易得，軒冕祇榮身。", "願以五百歲，獻母爲一春。"]'),
('712c3244-adb7-457b-bd68-0b79a26f9de1','再至兖州簡晁十二子履','畢仲游','宋','宋诗','song-poetry','','[]','送客客未至，自作河梁遊。',48,'全唐诗/poet.song.58000.json','["送客客未至，自作河梁遊。", "清瀾浴曉日，爛漫黄金浮。", "蘋藻飄不斷，悵望蓮亭幽。", "憶君古堞詩，八月如轉頭。"]'),
('9facca13-075e-4748-8e91-80d313cd5eb7','靜勝軒','畢仲游','宋','宋诗','song-poetry','','[]','官居背西墉，有居惟蔀室。',168,'全唐诗/poet.song.58000.json','["官居背西墉，有居惟蔀室。", "川原在其外，指掌千里隔。", "李侯富天巧，鑿壁盜山色。", "清風灑面至，竹蔭橫西北。", "坐令方丈地，萬古遺勝蹟。", "管氏南州來，謂侯有靜德。", "朱輪走岐路，夫子駕牛軛。", "權門聚冠蓋，夫子偃空壁。", "甘貧分始定，樂道心乃得。", "自怪塵土人，茲焉憩行役。", "欲爲居士操，聲淡不可識。", "欲學幽人吟，詞野不可易。", "忘懷古今混，問道乾坤窄。", "此意竟如何，青燈夜方寂。"]'),
('c415f8ab-2a89-46c6-8c64-5aa880d1d89e','古寺','畢仲游','宋','宋诗','song-poetry','','[]','崎嶇五六州，夏行今欲雪。',108,'全唐诗/poet.song.58000.json','["崎嶇五六州，夏行今欲雪。", "亂山出已盡，平地心目豁。", "晴日午未溫，霜雲晚如潑。", "蕭疏秦樹遠，曠蕩周原闊。", "徑竹掩招提，門庭苦凄颯。", "廊低不可步，壁朽何堪剳。", "歲月驚轉頭，是非紛若櫛。", "行歸聊可悲，再出尤凜冽。", "用此免饑寒，謀生一何拙。"]'),
('64886bfd-c4a6-4826-9f90-13002a9159a2','城中見山','畢仲游','宋','宋诗','song-poetry','','[]','塵埃埋馬足，人事如鼎沸。',48,'全唐诗/poet.song.58000.json','["塵埃埋馬足，人事如鼎沸。", "朝餔尚不厭，何暇論身計。", "北山十里近，雲色带陰翳。", "日日在目前，無由謝城市。"]'),
('c2274c20-d48b-4b92-a05e-ff15c60ec77f','曹南席上分題警鶴','畢仲游','宋','宋诗','song-poetry','','[]','清風來九皋，月出寒夜永。',48,'全唐诗/poet.song.58000.json','["清風來九皋，月出寒夜永。", "故人聞鶴唳，驚起同引領。", "山遥聲有怨，樹暗飛無影。", "不若君子言，詩書日相警。"]'),
('c8473118-a0cc-4a61-959f-9980521e50e7','熙州蔣穎叔侍郎席上','畢仲游','宋','宋诗','song-poetry','','[]','仗鉞出金門，投壺開玉帳。',48,'全唐诗/poet.song.58000.json','["仗鉞出金門，投壺開玉帳。", "高秋沸簫鼓，萬疊環青嶂。", "白雲襯湖底，舟行若天上。", "絕勝後將軍，峽中惟四望。"]'),
('f9a09655-a6e4-4b0c-bdf0-41e8679e566b','蒙晁美叔秘監召觀書帖繼示長句次韵','畢仲游','宋','宋诗','song-poetry','','[]','作官在閒地，而我不得閒。',204,'全唐诗/poet.song.58000.json','["作官在閒地，而我不得閒。", "有懷南陽書，三載願未還。", "駕言覲中郎，踴躍心桓桓。", "軟言慰孤寂，芳樽潔晨餐。", "詞妙編簡動，理愜心意安。", "期爲高人知，匪效男女歡。", "珍怪漸傾寫，寶墨來三韓。", "內愧無衣裾，靦面依門闌。", "元匪白眉者，謬作青眼看。", "古書羅異代，千百猶未殫。", "如何二王迹，到今紙墨完。", "若獲摩尼珠，寘在承露盤。", "開緘龍蛇踴，偃蹇風濤寬。", "熟視已收卷，愛惜還重觀。", "筆意不可盡，始知學書難。", "永慚出納卑，敢近華省觀。", "珍重難再覿，出門猶據鞍。"]'),
('975f3f6f-7fd4-484c-b08a-3f5007caf30c','感興簡歐陽仲純兄弟','畢仲游','宋','宋诗','song-poetry','','["\u897f\u6e56"]','昔我來潁州，繫馬西湖濱。',288,'全唐诗/poet.song.58000.json','["昔我來潁州，繫馬西湖濱。", "潁州絕褊小，所愛民心淳。", "中間入南國，八載寄壽春。", "去潁無十舍，土風已頑羣。", "從茲重所處，不敢擇要津。", "遷徙雖未固，常願爲潁民。", "今者伯氏來，得官邑相鄰。", "民愚少鬭訟，所訊由饑貧。", "吏戇不識字，况復能舞文。", "惟有租與貸，未免勞躬親。", "而我無官事，獨得頤精神。", "日高偃空房，睡足方欠伸。", "日暮近燈燭，誦書忘冠巾。", "懶來起復坐，自在如閒雲。", "憶昨遊京師，交友千百羣。", "賢否未可辨，正直惟仲純。", "仲純年始壯，氣概雄三軍。", "文章不待學，下筆如千鈞。", "飲酒或一醉，萬物如埃塵。", "近過潁州見，顔色彌清醇。", "兄弟亦相遇，磊落皆奇人。", "邀我上書堂，爲我拂素茵。", "呼奴正大案，食飲羅甘辛。", "論議不惜口，彼此從天真。"]'),
('a3947ebd-52d0-4750-a0f4-da203b66a264','送王君儀北歸','畢仲游','宋','宋诗','song-poetry','','[]','不能送君行，强題送君詩。',180,'全唐诗/poet.song.58000.json','["不能送君行，强題送君詩。", "詩中有鄙語，不是離別辭。", "君長不五尺，氣若千丈蜺。", "談經掩衆口，論道驚羣兒。", "况君擅才華，文若老吏爲。", "剛腸乏軟語，面折不我隨。", "人嘗論君材，照坐珊瑚枝。", "疇能論君心，清靜如摩尼。", "奈何三十六，未免州縣卑。", "君裝赴國門，僕瘦病馬羸。", "太倉幸可糴，窮達慎所之。", "儒冠易感慨，華屋難伸眉。", "紛紛兒女曹，足令壯士悲。", "工部貪採藥，漢老甘茹芝。", "不逢方外人，勿吐胸中奇。"]'),
('244c0ec2-c509-4169-95d8-3fdaec2efd41','贈盧礪','畢仲游','宋','宋诗','song-poetry','','[]','東風吹大河，北客思故鄉。',132,'全唐诗/poet.song.58000.json','["東風吹大河，北客思故鄉。", "門前車且留，念此道路長。", "子服儒衣冠，其家有禁方。", "非徒學之精，而又心術良。", "聞聲辨生死，易臂知陰陽。", "救瘵先閭里，懶上王公堂。", "子來視余疾，反側方在床。", "頭風應手愈，珍重不敢忘。", "遺我刀匕藥，三年用康强。", "我家乏黄金，我才非庾郎。", "贈子不成禮，禿筆題藥囊。"]'),
('4e535ab8-8754-4778-a1b0-e1f8ccbd714f','和孔毅夫學士題小閣','畢仲游','宋','宋诗','song-poetry','','[]','共坐既云隘，出也欲何之。',48,'全唐诗/poet.song.58000.json','["共坐既云隘，出也欲何之。", "晴窗日可負，此地猜瑠璃。", "朝衣雖已穿，襥被亦已遲。", "緬思廬霍勝，入手當何時。"]'),
('8a1ff71a-a8a9-44c9-82dd-2172a719de99','和孔毅夫省宿','畢仲游','宋','宋诗','song-poetry','','[]','拙學如拙商，欲益翻折閱。',48,'全唐诗/poet.song.58000.json','["拙學如拙商，欲益翻折閱。", "壯心消已盡，况復形羸苶。", "君年雖不少，面目猶冰雪。", "漢署夜如何，青燈兼白月。"]'),
('f1137751-a859-4ea9-8edc-aa3e009ca144','再和孔毅夫省宿','畢仲游','宋','宋诗','song-poetry','','[]','吾懶不閱書，知書不我閱。',48,'全唐诗/poet.song.58000.json','["吾懶不閱書，知書不我閱。", "雙瞳瞀仍眵，四體病如苶。", "黑鬚忽已蒼，但未頭如雪。", "空食竟何裨，留連驚歲月。"]'),
('82d0cfa6-f9f7-43c8-b0f7-4f12c617b235','和晁秘校','畢仲游','宋','宋诗','song-poetry','','[]','牆濕生野蒿，簷低脅嘉樹。',48,'全唐诗/poet.song.58000.json','["牆濕生野蒿，簷低脅嘉樹。", "凉飈屋上過，故以逃大暑。", "念彼遠戍人，荷戈事軍旅。", "而我幸安寧，尚愧林泉主。"]'),
('266b2354-4ac9-48cb-8030-17447355f451','和僧圓益題靈泉','畢仲游','宋','宋诗','song-poetry','','[]','我思靈泉遊，不免去閭里。',96,'全唐诗/poet.song.58000.json','["我思靈泉遊，不免去閭里。", "山寒景更清，觸目皆可喜。", "茲泉何潺潺，宛若雲霧起。", "酌之無淺深，那再問泥滓。", "盤盤山爲腹，鑿鑿石爲齒。", "噴薄無四時，其靈止如此。", "斯言聞于人，豈得盡其理。", "更喚山老來，煩師問初始。"]'),
('1c22bbad-e6bd-4cb5-b749-232126cc8fc2','壽李少卿','畢仲游','宋','宋诗','song-poetry','','[]','佳辰遡中元，大第羅燕席。',120,'全唐诗/poet.song.58000.json','["佳辰遡中元，大第羅燕席。", "今歲共茲日，冠蓋合佳客。", "中堂上壽遲，喜氣生四壁。", "男女燕雁行，樽俎皆潤澤。", "惟公臺省舊，况是文章伯。", "明星在中天，五福陰有力。", "惟茲基本厚，未止家萬石。", "共揖廟堂尊，蒼生日安宅。", "南園椿已大，悠久與之敵。", "長看堂上兒，白頭衣五色。"]'),
('676e0bad-3bf9-4867-a4d7-76ac11f30633','希魯奉議四兄生日','畢仲游','宋','宋诗','song-poetry','','[]','畫工畫青松，慘淡千年姿。',168,'全唐诗/poet.song.58000.json','["畫工畫青松，慘淡千年姿。", "遼鶴俛不啄，又有龜如綦。", "丈人坐中間，白髮衣帔𢂹。", "云是東方宿，來爲壽者師。", "再拜致此圖，惟兄能似之。", "骨强老于松，心靜靈于龜。", "形健瘦于鶴，自與長年期。", "從來事丹竈，得道今已遲。", "定應圖上人，適照生之時。", "富貴雖常情，在兄奚足爲。", "王侯金滿堂，不義乃滓泥。", "豈如食舊德，朝冠與朝衣。", "况復源流遠，後昆未可知。", "好看學行者，恐是麒麟兒。"]'),
('d89da12f-dbee-46ae-9c6a-1d950e2e4a82','讀縣父詩榜','畢仲游','宋','宋诗','song-poetry','','[]','縣地苦迫窄，縣亭乃荒凉。',132,'全唐诗/poet.song.58000.json','["縣地苦迫窄，縣亭乃荒凉。", "胡爲君子來，到此成詩章。", "上陳圖史樂，次道爲政方。", "終焉戒易足，俾爾能自强。", "荒亭實何幸，得此人不忘。", "年深粉墨剝，辭意彌激昂。", "誰云官冗小，會有真龍藏。", "其珠在人家，門戶常有光。", "余來誦反覆，感歎鳴中腸。", "臨風亟欲和，把筆猶徬徨。", "安得杜陵翁，爲我題屋梁。"]'),
('e1a26460-06fa-4b9c-b1d2-adf2ea3f6848','讀于濆詩','畢仲游','宋','宋诗','song-poetry','','[]','于濆詩不多，遺藁數千葉。',72,'全唐诗/poet.song.58000.json','["于濆詩不多，遺藁數千葉。", "緬觀作者意，重歎今人拙。", "雅辭清我骨，勁氣噴壁裂。", "感激生亂亡，辛酸更愁絕。", "長城句最苦，三讀淚流血。", "莫學蒙將軍，功高家國滅。"]'),
('7ab84792-6e61-4c7c-a486-b1dbb426ad50','傷春','畢仲游','宋','宋诗','song-poetry','','[]','人傷春色老，我傷春色深。',72,'全唐诗/poet.song.58000.json','["人傷春色老，我傷春色深。", "桃花未肯落，半月羈吾心。", "有酒且斟酒，無酒將奚斟。", "有詩謾吟詩，無詩將奚吟。", "詩酒兩不得，坐媿桃花林。", "咄嗟富家兒，滿堂收黄金。"]'),
('99a55da5-58db-438b-8b2e-4acc8dc820e5','苦雨','畢仲游','宋','宋诗','song-poetry','','[]','陰雲藏雨來，風吼如海潮。',120,'全唐诗/poet.song.58000.json','["陰雲藏雨來，風吼如海潮。", "乖龍喜當路，下雨連三霄。", "平河忽瀰漫，不見城東橋。", "蟄者灌其穴，飛者飄其巢。", "惟有魚與鼈，得勢饒腥臊。", "雖聞雷霆震，若有鬼神號。", "禾豐不得斂，穗濕依生苗。", "農家堵戶歎，始覺虛勤勞。", "乖龍莫之悟，自謂膏澤饒。", "始知旱魃虐，未得如雨妖。"]'),
('2d95d31e-3264-4966-808e-8f9fa7d4150c','自羅山入信陽過金關道中作','畢仲游','宋','宋诗','song-poetry','','[]','村南聞鷄在村北，土垡如堪竹臲卼。',64,'全唐诗/poet.song.58000.json','["村南聞鷄在村北，土垡如堪竹臲卼。", "野蒿誅盡露溪漘，山樹燒殘空石骨。", "疾風吹蓬如卷裘，河水夜凍凌割舟。", "但願黄堂賀新雪，單衣布襪非吾憂。"]'),
('5d2571df-76b7-41aa-8a87-b1753d4d9899','濟陰','畢仲游','宋','宋诗','song-poetry','','[]','東州女兒年十七，身在風塵如在室。',173,'全唐诗/poet.song.58000.json','["東州女兒年十七，身在風塵如在室。", "紅腮綠領巧相宜，露浥海棠嬌滴瀝。", "態濃意遠畫不盡，對客無言却真實。", "濟陰縣令爲留連，樽俎相逢復相失。", "我讀古人書，又愛斯人美。", "既未能忘情，亦未能忘禮。", "以情敗禮禮之賊，以禮約情情有止。", "上不與汝礙崆峒之山，下不與汝隔滄浪之水。", "無山無水有城市，咫尺青樓三萬里。", "東家酒香噴蘭芷，對客醉歌而已矣。", "君不見魯國有男子，拒戶不開寧老死。"]'),
('3c0e08e0-9c03-4c86-bafa-bb43320532f1','送范德孺使遼','畢仲游','宋','宋诗','song-poetry','','[]','都門冠蓋如雲多，馬頭匼匝金盤陀。',384,'全唐诗/poet.song.58000.json','["都門冠蓋如雲多，馬頭匼匝金盤陀。", "平明三節出城去，使華已過桑乾河。", "桑乾地寒氈作屋，冰霜滿野飛鴻鵠。", "道旁簫鼓動地迎，鐵面蕃兒皆拭目。", "金玦裝成寶刀利，銀鞍半露貂裘燠。", "日高賓館駐前旌，饋客往來隨酪粥。", "河間未弛新亭障，山後猶存舊風俗。", "幽燕婦女白如脂，露面來覘漢冠服。", "邊風吹雪罨氈城，氈城在處爲屯營。", "黄沙行盡到靴淀，新年下馬單于庭。", "庭中之人識漢事，而公赫赫傳家聲。", "君臣把酒重相勸，知有從來忠孝名。", "好言天子神聖武，際天接地皆王土。", "桑麻萬里富中原，制作千年還太古。", "白日親觀丹鳳翔，黄河近報神魚舞。", "不須鐵甲屯大荒，坐見長城倚天宇。", "况君總髮懷剛腸，往年司直中書堂。", "單騎走馬絕瀚海，而今復使天一方。", "平時出入雖故事，男兒舉足安可量。", "鄙人再拜贈公語，北邊射獵雲雪岡。", "平安烽火三萬日，羽林超距閒金湯。", "年年蕃馬輸漢地，後車碨礧牽玄黄。", "願持成效獻天子，歸來躍出尚書郎。", "歸來躍出尚書郎，鏘金鳴玉趨明光。"]'),
('6275e983-bbb9-476d-85a0-bf0b231621a0','送朱彥文通直從慶陽辟命','畢仲游','宋','宋诗','song-poetry','','[]','洛陽之人秀眉宇，束髮從軍心自許。',227,'全唐诗/poet.song.58000.json','["洛陽之人秀眉宇，束髮從軍心自許。", "南徹梁江西瀚海，萬里相從舊賓主。", "慶州之險山作城，青岡路狹如鬭鼠。", "我嘗與君馳大漠，夜掘黄沙枕冰土。", "君今重行計安出，羽檄攙槍待君處。", "去年天狗墮地鳴，今年擬破靈鹽城。", "男兒鞍馬是常事，髀肉消盡須重生。", "况君到日春風發，行雲夜閉沙場月。", "戰馬沾泥不用嫌，功成便浴讎人血。", "君不見高平范公慶曆時，往築大順人不知。", "千金散士得死力，橫山可取猶提携。", "至今塞下呼老子，關中使者公之兒。", "當年議奏千萬語，攻守二策真可師。", "勿云近事不足道，狄青之輩爲偏裨。"]'),
('78b14c0f-d8fe-4f12-a154-00898ee001a5','送田百里歸唐','畢仲游','宋','宋诗','song-poetry','','[]','田百里，飄泊如雲心似水，我每思之中夜起。',64,'全唐诗/poet.song.58000.json','["田百里，飄泊如雲心似水，我每思之中夜起。", "忽來訪我黄河涘，抵掌欣欣不能已。", "身形雖么麽，膽大無與比。", "茲行若過汝水濆，爲寄新詩與陳子。"]'),
('9fbb444c-88ef-4c68-b40c-bb9be49f66df','次韵和歐陽季默觀書紀事之作','畢仲游','宋','宋诗','song-poetry','','[]','歐陽季默年三十，處世雖艱心地吉。',199,'全唐诗/poet.song.58000.json','["歐陽季默年三十，處世雖艱心地吉。", "居于頹垣壞屋偪仄之巷，而有倜儻慷慨汪洋之美質。", "高才橫騖若飛走，橫野騰山漫罝畢。", "吾懶居家病益生，絮帽蒙頭造君室。", "兒童驚窺前復後，笑我衰遲見風栗。", "升堂發篋數百紙，爛錦繁華照初日。", "怒生風雲與神會，怪走龍蛇堪股慄。", "奇蹤雖在人已亡，今也源流苦蕭瑟。", "吾家綈囊亦三四，縱有名書未充實。", "妻孥饑餓謂無用，誶語如蛩常唧唧。", "黄籤青縹纔數種，若比君家百無一。", "後會慇懃定若何，人生聚散胡能必。"]'),
('f5472a36-6112-4bdf-9fc4-0f813b018ff2','次韵和晁秘校招飲','畢仲游','宋','宋诗','song-poetry','','[]','侯門公子桃花色，岐路書生情反側。',96,'全唐诗/poet.song.58000.json','["侯門公子桃花色，岐路書生情反側。", "羨君脫灑心坦平，交友如林真少得。", "懷中有疏未肯上，鄉里小兒空太息。", "黄粱甑冷且沽酒，爲客典衣無顧惜。", "淳于道舊釂五斗，倒載不辭門戶隔。", "共約他年江海遊，醉斬鯨魚尋李白。"]'),
('c112f7cf-46db-4393-8605-b6a44ebb1fdd','依韵和祖休承議','畢仲游','宋','宋诗','song-poetry','','[]','吾聞明霞之綺良工造，若比君詩工不到。',67,'全唐诗/poet.song.58000.json','["吾聞明霞之綺良工造，若比君詩工不到。", "擲地方知作者神，補天非是常人巧。", "放懷似覺乾坤小，名節雖高心事少。", "君不見漢陰有丈夫，脚踏空山樹芝草。"]'),
('b7677b21-c0fd-4113-8756-0c246a4cbeb3','蓋公堂歌','畢仲游','宋','宋诗','song-poetry','','[]','膠西丈人頭皓白，避世不作諸侯客。',366,'全唐诗/poet.song.58000.json','["膠西丈人頭皓白，避世不作諸侯客。", "黄帝老子是其師，短褐補肩人不識。", "嗚呼相國起文吏，能解干戈謀社稷。", "諸田喋血腥未已，封裹瘡痍與休息。", "三齊儒生多說士，强讀詩書談治國。", "席間衆口亂如髮，鄉飲明堂盡陳迹。", "丈人西來貌甚野，杖藜柴車面黧黑。", "坐言治道本無事，要爾蒼生自安適。", "爾能高卧知大體，男子耕耘女蠶織。", "用之天下如掌上，况爾區區城七十。", "相君再拜受其教，舍以高堂奉顔色。", "相君已死君不來，千五百年人歎息。", "眈眈新堂作者誰，密州太守文章伯。", "太守高吟醉太白，年穀常豐無盜賊。", "三牛倒曳九仙木，大斤截落瑯琊石。", "脩梁巨柱屹如湧，磊落巍峨稱公德。", "太守思公公不見，闢戶張筵望南北。", "詩成鬼神相對泣，文就龍蛇驚辟易。", "公今存亡詎可問，况今自有神仙骨。", "五嶷山高近城郭，太守有堂奚不宅。", "我欲寫公之意于鳴琴，又欲畫公之容于四壁，太守胡不置我于其側。", "我欲奮飛無羽翼，注目高歌淚沾臆。"]'),
('cbc24491-a6a9-47d2-85f0-c126489a48ef','鴻濛歌','畢仲游','宋','宋诗','song-poetry','','[]','山川鴻濛火未流，祝融羽衛行九州。',128,'全唐诗/poet.song.58000.json','["山川鴻濛火未流，祝融羽衛行九州。", "南方有氣纏斗牛，乃生之人宜公侯。", "諫書十上辭不留，繡衣夜過咸陽樓。", "清談玉帳羌戎羞，羽林超距閒貔貅。", "單車弭節浉岸遊，世間萬事公無求。", "茲辰歌舞良燕休，滿堂賓客來曹劉。", "再拜酌酒交獻酬，文彩照耀珊瑚鈎。", "願公壽考踰山丘，以八千歲爲春秋。"]'),
('15518b18-0006-4cae-8ab6-fefdef7889b9','海內','畢仲游','宋','宋诗','song-poetry','','[]','海內儒生十七萬，日誦詩書頭白半。',56,'全唐诗/poet.song.58000.json','["海內儒生十七萬，日誦詩書頭白半。", "中有成名當路人，却視詩書猶弊券。", "猶弊券，可奈何。", "勸君收淚莫零落，古往今來此輩多。"]'),
('6b255131-a672-4d27-9d84-1ab5ef604c2f','古冢行','畢仲游','宋','宋诗','song-poetry','','[]','朝行古冢東，暮行古冢西。',218,'全唐诗/poet.song.58000.json','["朝行古冢東，暮行古冢西。", "冢中古人骨已朽，冢外遊子今何之。", "朝食古道南，暮食古道北。", "道傍古跡不可見，道上行人常役役。", "古人居今人必愛，今有古人人不識。", "面前和好兒女顔，背後往往張弓射。", "拂衣歸去非不會，無宅無田歸未得。", "長靴短笏隨衆人，斂首低顔爲俗客。", "深居晏坐尚恐喧，平路緩行猶恐蹶。", "口中有聲未嘗吐，嚥入喉嚨化爲血。", "君不見谷口鄭子真，又不見蜀中揚子雲。", "子真老死耕巖石，子雲嗜酒惟醺醺。", "丈夫窮達皆有命，萬事得失非由人。", "街頭沽販味雖薄，猶可賒來傾入唇。"]'),
('76d84cfd-46c0-4ddf-a2f1-b8adb9eeb65f','提葫蘆行','畢仲游','宋','宋诗','song-poetry','','[]','提葫蘆，竹叢裏鳴。',85,'全唐诗/poet.song.58000.json','["提葫蘆，竹叢裏鳴。", "昔嘗見人學，今乃聞爾聲。", "草深山遠徑路狹，春盡日長花竹明。", "往來行人竟何事，足繭縢穿千里行。", "離家去國已牢落，况復饑渴貪前程。", "是時聞爾勸沽酒，下馬解带留長亭。"]'),
('108b54e1-7249-496f-9f37-f01fb6108b26','花溪四松','畢仲游','宋','宋诗','song-poetry','','[]','君不見吾植四松樹，多植六松非溢數。',65,'全唐诗/poet.song.58000.json','["君不見吾植四松樹，多植六松非溢數。", "高織筠籠避猛風，頻挑壤穴防根蠹。", "直幹清音已可憐，短長尺寸詩可傳。", "草堂舊客今安在，錦里花溪四百年。"]'),
('e41baa46-c321-4a24-bf74-e7a2adf76da2','觀文與可學士畫枯木','畢仲游','宋','宋诗','song-poetry','','[]','韋偃樹石名天下，後日良工無及者。',192,'全唐诗/poet.song.58000.json','["韋偃樹石名天下，後日良工無及者。", "任侯借我枯木圖，石氣蒼茫若唐畫。", "畫時只用床頭筆，與可親題是真蹟。", "霜皮合抱隠不彰，老蓋支離存半壁。", "梢摧骨朽心已穿，幹爛龍鱗體猶瘠。", "生意雖休根柢在，崛强杈牙倚天黑。", "膠流斷節文理深，笋枝剝落如針直。", "坐久疑行古塞外，凌空慘淡千年色。", "起身就視覺有神，不見筆痕惟淡墨。", "豈徒揮洒無人似，苦節清風貧到死。", "任侯珍重竟何如，不獨畫好心君子。", "若使與可爲俗流，枯木雖佳侯不收。"]'),
('61bfffca-2088-4eac-a26d-9237afce2e13','楊照承議蘆雁枕屏','畢仲游','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','畫師不肯傳風蝶，故作枯乾逞奇絕。',176,'全唐诗/poet.song.58000.json','["畫師不肯傳風蝶，故作枯乾逞奇絕。", "清秋未合結繁陰，深戶何曾洒飛雪。", "雪裏鴨兒苦耐寒，眠沙枕浦白雲團。", "黄蘆槭槭枝葉乾，江頭鳴鴨恰飛起，恍如身到瀟湘間。", "瀟湘洞庭雲水隔，山路坡阤斷行客。", "從來冬景畫已難，况有翎毛似鶴白。", "已覺冰漫稻粱少，更疑水宿溪垠窄。", "生平有道付滄洲，今日床頭行動色。", "屏風主人家近便，我昔曾過潯陽縣，田蘆野雁嘗親見。", "出門解榻定相逢，借我江鄉今對面。"]'),
('3fc5aa32-09d5-483f-b855-0314930c3793','出郊','畢仲游','宋','宋诗','song-poetry','','[]','出郊雖未遠，已似惡塵埃。',48,'全唐诗/poet.song.58000.json','["出郊雖未遠，已似惡塵埃。", "徑穩車先到，門閒客自開。", "花從今日見，會是隔年來。", "載酒無知數，揮金可快哉。"]'),
('87db44ae-b832-49b8-964e-e17cbf0c9bba','索馬','畢仲游','宋','宋诗','song-poetry','','[]','索馬周岡寺，鳥鳴問去程。',48,'全唐诗/poet.song.58000.json','["索馬周岡寺，鳥鳴問去程。", "頑風入衣冷，寒日带霜清。", "朝市心雖懶，江湖計未成。", "因循已三十，真恐悞生平。"]'),
('7c4055ab-45f8-485f-a167-6a0b970960c8','信陽道中避暑','畢仲游','宋','宋诗','song-poetry','','[]','下馬湯家市，前村數里賒。',48,'全唐诗/poet.song.58000.json','["下馬湯家市，前村數里賒。", "敗籬瓜少蔓，簇舍豆先花。", "放袖從風入，停鞍待日斜。", "欲知爲客恨，更久不成家。"]'),
('8f68d41a-47df-47a7-8bed-337fa947d1b9','郾城道中阻雨','畢仲游','宋','宋诗','song-poetry','','[]','秋雨連三晝，羸驂驅不前。',48,'全唐诗/poet.song.58000.json','["秋雨連三晝，羸驂驅不前。", "氣昏吁可怕，雲斷復相連。", "風急時翻蓋，泥暄懶著鞭。", "窮途不須問，吾道付高天。"]'),
('0188e21b-ade4-4b64-a9f5-7b84991de9b4','許田道中雨止','畢仲游','宋','宋诗','song-poetry','','[]','索索風回陣，暉暉日弄晴。',48,'全唐诗/poet.song.58000.json','["索索風回陣，暉暉日弄晴。", "掃門收石潤，走馬覺身輕。", "路闊車添轍，泥乾僕問程。", "暮川行客遠，雲氣自昏明。"]'),
('3e5d7b7c-3bd9-40d5-b301-05f125fd5739','虞城病中遣懷','畢仲游','宋','宋诗','song-poetry','','[]','本作看書室，翻成搗藥堂。',48,'全唐诗/poet.song.58000.json','["本作看書室，翻成搗藥堂。", "心違經歲月，病久怯風霜。", "未數囊中帙，先論肘後方。", "喜聞臨賀守，鼓枻過湘江。"]'),
('951e2d1e-735a-491d-b5c5-cf09ca0f9700','望王屋','畢仲游','宋','宋诗','song-poetry','','[]','感激愚公事，傳從太古時。',48,'全唐诗/poet.song.58000.json','["感激愚公事，傳從太古時。", "伏中猶積雪，雨上見朝曦。", "氣與扶桑接，心疑峻極卑。", "天壇如可至，吾欲摘參旗。"]'),
('2c72da28-98df-4a73-a782-710cdc2f35d4','過朱僊驛','畢仲游','宋','宋诗','song-poetry','','[]','氣象皇州近，川原暮靄中。',48,'全唐诗/poet.song.58000.json','["氣象皇州近，川原暮靄中。", "沙平千里白，日入半城紅。", "出處形容改，驅馳歲月同。", "身名行可料，天地一衰翁。"]'),
('1ccec5bd-78ba-4a12-9477-a0838eb36bb8','遷居潁谷','畢仲游','宋','宋诗','song-poetry','','[]','漸入深山處，都無客到來。',48,'全唐诗/poet.song.58000.json','["漸入深山處，都無客到來。", "輕裘勝挾纊，渴飲當銜杯。", "得失情何預，閒忙老共催。", "清風一披拂，安坐興悠哉。"]'),
('975f5778-1067-4b55-af74-34be80680b99','定居','畢仲游','宋','宋诗','song-poetry','','[]','臘盡風霜急，東城始定居。',48,'全唐诗/poet.song.58000.json','["臘盡風霜急，東城始定居。", "豫抄新歲酒，却讀少年書。", "好事心渾懶，談空病未除。", "轉頭成四十，吾道竟何如。"]'),
('19936111-6397-4d63-ad2d-28435fcb56a9','贈脩顒上人','畢仲游','宋','宋诗','song-poetry','','[]','巾鉢來何所，茅齋近竹林。',48,'全唐诗/poet.song.58000.json','["巾鉢來何所，茅齋近竹林。", "能談高士傳，會得祖師心。", "我識詩情苦，公求理性深。", "三年居潁水，誰復是知音。"]'),
('a63fd2a9-f3a9-45a2-a678-89c70855e91c','留別損之大士','畢仲游','宋','宋诗','song-poetry','','[]','去去南州遠，無人可問禪。',48,'全唐诗/poet.song.58000.json','["去去南州遠，無人可問禪。", "牽懷從此日，聚首在何年。", "水落城東路，風清淮上船。", "我心須自寫，彈斷古琴弦。"]'),
('98332f64-844c-4e5a-a339-ca8e4f827b9a','河陽閒居','畢仲游','宋','宋诗','song-poetry','','[]','飄泊成留滯，河陽見五春。',48,'全唐诗/poet.song.58000.json','["飄泊成留滯，河陽見五春。", "壞池無過路，委巷作比鄰。", "糲食稀留客，肩輿懶倩人。", "臨流休照面，自合鬢如銀。"]'),
('e0ea7f61-3790-4799-8fee-5efbaa40d222','河陽重九','畢仲游','宋','宋诗','song-poetry','','[]','佳辰雖可重，無客共登高。',48,'全唐诗/poet.song.58000.json','["佳辰雖可重，無客共登高。", "蒸粉隨粗飯，挼花對濁醪。", "放歌元不解，擬賦亦徒勞。", "坐聽兒童語，悠悠愧爾曹。"]'),
('a42584d2-52f0-4bbe-b4f2-69c44cbe837f','獻壽二首  其一','畢仲游','宋','宋诗','song-poetry','','[]','慶日三陽近，高門附帝居。',48,'全唐诗/poet.song.58000.json','["慶日三陽近，高門附帝居。", "迎祥春入暮，獻壽晚連裾。", "中子今持節，諸孫日誦書。", "始知題萬石，未足大吾閭。"]'),
('8fdf4f68-4697-48b7-83b8-de60f47a1f9c','獻壽二首  其二','畢仲游','宋','宋诗','song-poetry','','[]','家近黄金闕，筵供白玉船。',48,'全唐诗/poet.song.58000.json','["家近黄金闕，筵供白玉船。", "兩孫今應詔，一子日朝天。", "壽酒如鱗次，斑衣作陣圓。", "夢齡人試數，從此更千年。"]'),
('702f3c3f-a8f0-4989-b435-f98c02b9dde9','佳辰二首  其一','畢仲游','宋','宋诗','song-poetry','','[]','傍臘春猶遠，佳辰氣自和。',48,'全唐诗/poet.song.58000.json','["傍臘春猶遠，佳辰氣自和。", "慈顔親事少，壽相比人多。", "姊妹新爲會，兒童預作歌。", "萊衣容醉倒，始奈錦茵何。"]'),
('89f7f7b5-d536-447f-855e-a5d6e717fe39','佳辰二首  其二','畢仲游','宋','宋诗','song-poetry','','[]','戶內三千口，誰爲第一樽。',48,'全唐诗/poet.song.58000.json','["戶內三千口，誰爲第一樽。", "清風傳舊族，陰德助吾門。", "阿母神仙降，班姑法度存。", "他年堂上燕，侍立見玄孫。"]'),
('dbeed6d5-13e2-458e-bd9a-007341933290','姪馬子試晬','畢仲游','宋','宋诗','song-poetry','','[]','去歲當今日，兒生在北堂。',48,'全唐诗/poet.song.58000.json','["去歲當今日，兒生在北堂。", "眉疏才必秀，耳大壽應長。", "乳驥蹄猶小，冥鴻翼未張。", "吾門如可大，藉汝志强梁。"]'),
('a4dfb096-c515-4926-a5ab-4cf797675bfb','早赴城西倉即事呈諸同志','畢仲游','宋','宋诗','song-poetry','','[]','上馬雞鳴後，都門四望中。',48,'全唐诗/poet.song.58000.json','["上馬雞鳴後，都門四望中。", "曉光欺月色，和氣挾春風。", "計拙功名遠，官閒况味同。", "醉鄉如可入，相率慰飄蓬。"]'),
('dd2effbf-e8f3-4006-a2d3-5a4020391f36','就南排岸謁宋成伯不值而還蒙詩見贈次韵','畢仲游','宋','宋诗','song-poetry','','[]','懶作青門客，來尋隠吏居。',48,'全唐诗/poet.song.58000.json','["懶作青門客，來尋隠吏居。", "上堂誰解榻，窺戶却還車。", "似怕臨池驛，空翻插架書。", "生涯知有地，共學灌園蔬。"]'),
('5964c202-8fa4-4f97-aa19-3e1b5b5d9371','乙亥歲八月十五日夜同景叔知府少卿翼道提舉大夫望月于河中之名閫堂兼簡襄守歐三叔弼虢守孫八元忠二首  其一','畢仲游','宋','宋诗','song-poetry','','[]','上樓初照席，條華漸分明。',48,'全唐诗/poet.song.58000.json','["上樓初照席，條華漸分明。", "佳節三秋半，前期一雨晴。", "冷光天外散，高會世間清。", "坐久疑輕舉，微風習習生。"]'),
('882a128f-74a4-44a1-9498-dc4c3c544404','乙亥歲八月十五日夜同景叔知府少卿翼道提舉大夫望月于河中之名閫堂兼簡襄守歐三叔弼虢守孫八元忠二首  其二','畢仲游','宋','宋诗','song-poetry','','[]','秋深仍雨過，望月宴高城。',48,'全唐诗/poet.song.58000.json','["秋深仍雨過，望月宴高城。", "列岫呈中夜，微雲避太清。", "星沉天若掃，林迥野無聲。", "故友知强健，應同醉五更。"]'),
('c4519226-bf5a-4551-ae0f-de8a5ad954e7','陪蒲守景叔學士會暢家園','畢仲游','宋','宋诗','song-poetry','','[]','亭幽宜更酌，樹近合頻行。',48,'全唐诗/poet.song.58000.json','["亭幽宜更酌，樹近合頻行。", "蒲劍槮槮長，荷錢疊疊生。", "隔林千岫踴，带郭一川橫。", "共選尋山屐，無心更濯纓。"]'),
('43413f76-27c6-43cb-b7fd-bb5b0828fc03','沈丘縣遇冬至夜會夷仲明叔','畢仲游','宋','宋诗','song-poetry','','[]','佳節無佳句，留連小縣城。',48,'全唐诗/poet.song.58000.json','["佳節無佳句，留連小縣城。", "客來爐火著，人靜佛燈明。", "把酒隨時俗，高吟屬弟兄。", "令人驚歲月，屈指是新正。"]'),
('50fce02e-9e23-4bf9-8d6c-7e99177469f2','次韵和宋寧道太祝許氏園席上','畢仲游','宋','宋诗','song-poetry','','[]','雅宴屬才華，清詩自一家。',48,'全唐诗/poet.song.58000.json','["雅宴屬才華，清詩自一家。", "高談落風雨，醉目傲烟霞。", "席地疏林隔，傳杯小徑斜。", "再來春已老，猶得醉殘花。"]'),
('d79791f4-eb6b-4fe1-b556-cc8d830ff3ae','次韵席上','畢仲游','宋','宋诗','song-poetry','','[]','無寥情易感，多病酒先除。',48,'全唐诗/poet.song.58000.json','["無寥情易感，多病酒先除。", "城影落平地，月光飛太虛。", "高吟空有調，倦思本無餘。", "讀罷傳三鼓，披衣歸我廬。"]'),
('f4bd78a8-345e-4f8a-b250-74108f384905','夜宿崇因寺述懷奉呈諸公','畢仲游','宋','宋诗','song-poetry','','[]','月老庭除白，火明山頂高。',48,'全唐诗/poet.song.58000.json','["月老庭除白，火明山頂高。", "酒容無俗客，詩興任吾曹。", "促席暫讙謔，思家還鬰陶。", "坐聞鐘磬響，那免話離騷。"]'),
('5de6bed4-990a-4b38-94cf-485f2dee4ff5','寓宿樂明之殿直家戲作','畢仲游','宋','宋诗','song-poetry','','[]','地狹開爐小，門深掩徑斜。',48,'全唐诗/poet.song.58000.json','["地狹開爐小，門深掩徑斜。", "雨寒冰裹木，風怒雪翻車。", "北第頻留客，南園欲探花。", "我身無定所，酒到是吾家。"]'),
('d951cb96-b967-4c1b-a2e0-7a4e1c541d83','會草堂嘗酒戲成四十字呈子思舅','畢仲游','宋','宋诗','song-poetry','','[]','白酒旋開封，身如鳥出籠。',48,'全唐诗/poet.song.58000.json','["白酒旋開封，身如鳥出籠。", "愁腸先抹倒，醉眼任矇鬆。", "甕近那妨就，杯寒且更烘。", "翁居鎮如此，我馬又西東。"]'),
('fdf86718-af6d-4f01-a9e2-3bc98b6f2380','酒後','畢仲游','宋','宋诗','song-poetry','','[]','爲爾題詩句，詩成莫浪傳。',48,'全唐诗/poet.song.58000.json','["爲爾題詩句，詩成莫浪傳。", "避人那是怯，勸酒自知妍。", "翠袖身如削，清歌喉未圓。", "良宵誰與並，明月共嬋娟。"]'),
('c9ca5766-9d83-44fd-9bb4-799f74c3283a','次韵子思舅','畢仲游','宋','宋诗','song-poetry','','[]','幽居山霧合，日色曉相交。',48,'全唐诗/poet.song.58000.json','["幽居山霧合，日色曉相交。", "凍馬空嘶櫪，癡鴉不離巢。", "舊醅澄綠沫，新橘破朱苞。", "我豈揚雄比，無須苦客嘲。"]'),
('adf3c63a-8b8d-494a-9402-73ce0474b20f','讀子思詩二首  其一','畢仲游','宋','宋诗','song-poetry','','[]','子思詩二百，開卷淚沾衣。',48,'全唐诗/poet.song.58000.json','["子思詩二百，開卷淚沾衣。", "今世識者少，古人能亦稀。", "當年出咳唾，此日成珠璣。", "誰憐盛名後，妻子貧無衣。"]'),
('cb3ece5e-4baf-4f2f-ab89-09208e5f48a3','讀子思詩二首  其二','畢仲游','宋','宋诗','song-poetry','','[]','子思詩句好，當日少知音。',48,'全唐诗/poet.song.58000.json','["子思詩句好，當日少知音。", "不作蘇梅體，猶勝庾鮑吟。", "郟城山不改，清潁水猶深。", "試問安良事，流傳直至今。"]'),
('4b8ac67a-a2b8-4a6d-a129-f3f50c5c7e1c','次韵李成之待制見寄','畢仲游','宋','宋诗','song-poetry','','[]','有客昔遭遇，郎官帥秦川。',48,'全唐诗/poet.song.58000.json','["有客昔遭遇，郎官帥秦川。", "得閒欣燕處，佳句出天然。", "羽翼九萬里，功名三十年。", "詩成傳萬口，世俗累都捐。"]'),
('18fe0d68-91d8-45b6-9dcb-44f59786bf64','次韵和子夷秘校見惠之作','畢仲游','宋','宋诗','song-poetry','','[]','啟函如會面，懷抱爲君開。',48,'全唐诗/poet.song.58000.json','["啟函如會面，懷抱爲君開。", "昔有風騷主，今爲伯仲才。", "士風門外轍，生計掌中杯。", "早晚依閭巷，烏巾恣往來。"]'),
('d0ca079b-3a63-4a21-bc3e-d573cb5a9e55','次韵楊久中阻雨','畢仲游','宋','宋诗','song-poetry','','[]','雞鳴雖不改，人病自添慵。',48,'全唐诗/poet.song.58000.json','["雞鳴雖不改，人病自添慵。", "地滑泥無跡，簷疏瓦有松。", "天低渾似幕，雲怒不成峰。", "欲决繁陰破，慚無利劍鋒。"]'),
('7697553c-44f4-4050-a15e-6d595bc329fb','次韵和越州監酒酇令七兄見寄','畢仲游','宋','宋诗','song-poetry','','[]','去國悲新壟，還鄉曳故裾。',48,'全唐诗/poet.song.58000.json','["去國悲新壟，還鄉曳故裾。", "澗寒迷路晚，花落度關初。", "計拙家無補，官閒睡有餘。", "生兒如可教，早晚大吾閭。"]'),
('f39f5d74-f477-40e4-b036-e61319146cd9','讀將叔弟送路帥詩','畢仲游','宋','宋诗','song-poetry','','[]','定州詩刻好，模寄比南金。',48,'全唐诗/poet.song.58000.json','["定州詩刻好，模寄比南金。", "道盡行人意，堪論作者心。", "邊城歸盛事，雅道付知音。", "珍重吾將叔，當時亦苦吟。"]'),
('261f0f8c-2dd3-43b7-946f-5172ed288250','和宋成伯','畢仲游','宋','宋诗','song-poetry','','[]','度日門長掩，尋春事已非。',48,'全唐诗/poet.song.58000.json','["度日門長掩，尋春事已非。", "鵲驚隨吏散，燕熟傍人飛。", "手拙裁書懶，頭昏漉酒稀。", "坐來空咄咄，不是悟禪機。"]'),
('b5ea8d62-7648-40a4-af0e-855e38c7bc93','蕨澗曹正叔有詩見寄因以答謝','畢仲游','宋','宋诗','song-poetry','','[]','子學有餘力，我生無定居。',48,'全唐诗/poet.song.58000.json','["子學有餘力，我生無定居。", "與人常不合，謀己一何疏。", "酒熟同誰酌，詩成懶自書。", "會須還潁水，高枕閉吾廬。"]'),
('16426ea8-09c1-4acf-8fbe-b2d914f2fd2f','得來書有感因成四十字呈夷仲宣仲','畢仲游','宋','宋诗','song-poetry','','[]','獨坐長如醉，書來意暫醒。',48,'全唐诗/poet.song.58000.json','["獨坐長如醉，書來意暫醒。", "未能論會合，猶且慰零丁。", "客少庭稀掃，人回戶又扃。", "歸期試閒卜，見說紫姑靈。"]'),
('683ed7d6-d96f-410b-b304-b7b67f61557b','寄南齋諸君兼簡牧之公遠','畢仲游','宋','宋诗','song-poetry','','[]','寄語生平友，暌違情若何。',48,'全唐诗/poet.song.58000.json','["寄語生平友，暌違情若何。", "每斟樽內酒，常憶醉時歌。", "大賦相如巧，新詩子建多。", "幸煩傳數紙，且欲恣吟哦。"]'),
('a5e2874b-21aa-4e46-a626-f755d659f1fa','寄鄭介夫','畢仲游','宋','宋诗','song-poetry','','[]','鄭子安强否，梅花萬里春。',48,'全唐诗/poet.song.58000.json','["鄭子安强否，梅花萬里春。", "如何投虎穴，直欲犯龍鱗。", "北闕今無數，南方信有人。", "可憐妻子在，年少不謀身。"]'),
('7009fc0f-96c5-4c6b-ad13-ee8d5d2b6ef4','次十五里店寄交代楊十七判官','畢仲游','宋','宋诗','song-poetry','','[]','世事元無定，吾今得已多。',48,'全唐诗/poet.song.58000.json','["世事元無定，吾今得已多。", "轉頭新歲月，開眼舊山河。", "蹭蹬如君少，因循奈我何。", "此生深會得，不用接輿歌。"]'),
('7cd4f63e-4d68-4fb0-b5af-355538bc37ea','和李善初會張范二公','畢仲游','宋','宋诗','song-poetry','','[]','會面雖難得，親情豈易忘。',48,'全唐诗/poet.song.58000.json','["會面雖難得，親情豈易忘。", "定須留客醉，應話老夫忙。", "地去朝門遠，身依古寺凉。", "相逢拚一醉，千日未爲長。"]'),
('adc56e42-ffa0-4724-85bd-2e2801629ac8','從軍還京贈羅適正之奉議','畢仲游','宋','宋诗','song-poetry','','[]','一別書渾廢，相逢老可嗟。',48,'全唐诗/poet.song.58000.json','["一別書渾廢，相逢老可嗟。", "免爲邊地鬼，還宿故人家。", "塞路風霜惡，京塵歲月賒。", "衰顔不重少，兒戲煉丹砂。"]'),
('fc591c75-f809-46e3-9c9c-ea40008806f6','出巡河東與徐勳宣德','畢仲游','宋','宋诗','song-poetry','','[]','防敵無時節，論兵有是非。',48,'全唐诗/poet.song.58000.json','["防敵無時節，論兵有是非。", "屯營蕃馬健，部落漢人稀。", "土屋穿寒月，氈裘護鐵衣。", "相逢一樽酒，分首雪中歸。"]'),
('34b38cf6-f5ea-4d8f-ab94-2cbd636a9d3e','送寅亮宣義赴明州','畢仲游','宋','宋诗','song-poetry','','[]','隨分之官好，舟行不計程。',48,'全唐诗/poet.song.58000.json','["隨分之官好，舟行不計程。", "江山新入夢，風物舊知名。", "客館離人醉，賓筵楚士清。", "須知今夜月，近海更分明。"]'),
('90ee9354-df7b-48c3-a566-181d461ae1b7','罷淮漕歸汝','畢仲游','宋','宋诗','song-poetry','','[]','任拙因成懶，求閒偶得歸。',48,'全唐诗/poet.song.58000.json','["任拙因成懶，求閒偶得歸。", "前途純可料，往事盡成非。", "汝岸瓜田薄，風川藋逕微。", "終須一遷徙，知有濼魚肥。"]'),
('732750eb-e93a-4055-9c9b-2ac9011bb53e','至鄭州望故陳子思靈泉舊居愴然有感詩以述懷','畢仲游','宋','宋诗','song-poetry','','[]','夫子嘗招隠，雞鳴汝上川。',48,'全唐诗/poet.song.58000.json','["夫子嘗招隠，雞鳴汝上川。", "飲徒隨手散，詩草任人傳。", "甥舅元相好，妻兒也可憐。", "有魂招不得，嗚咽問靈泉。"]'),
('590c0b39-367c-48a5-9ba7-938e9d61e60b','忤俗','畢仲游','宋','宋诗','song-poetry','','[]','忤俗真堪笑，謀生又不能。',48,'全唐诗/poet.song.58000.json','["忤俗真堪笑，謀生又不能。", "放懷衣落拓，高卧髮鬅鬙。", "面垢常揮汗，牙衰怕嚼冰。", "床頭鬃拂弊，不會逐青蠅。"]'),
('bf6ec700-25b1-45c3-a634-67256e503e23','書懷','畢仲游','宋','宋诗','song-poetry','','[]','高城壘脩竹，小舍似山居。',48,'全唐诗/poet.song.58000.json','["高城壘脩竹，小舍似山居。", "痛飲謀身懶，高歌與世疏。", "拂衣慚國士，買釣夢江魚。", "可笑虞卿老，窮愁强著書。"]'),
('85482c49-29a2-4d3d-a1b6-1449f8a3cdc1','永日','畢仲游','宋','宋诗','song-poetry','','[]','永日梅空發，夜眠分作題。',48,'全唐诗/poet.song.58000.json','["永日梅空發，夜眠分作題。", "不因懷北客，未折向南枝。", "渡嶺朝雲斷，緣江春路遲。", "如何夢中作，常勝覺來詩。"]'),
('e6ecc98c-9fa3-4646-934b-5de3c8f68888','秋風','畢仲游','宋','宋诗','song-poetry','','[]','天地東南遠，秋風萬里來。',48,'全唐诗/poet.song.58000.json','["天地東南遠，秋風萬里來。", "青雲如漫語，白日會相催。", "頭带千莖雪，心闌一寸灰。", "說歸歸未得，江海路悠哉。"]'),
('b92719d2-c047-4f7f-9d40-8699a30979b2','夜雨','畢仲游','宋','宋诗','song-poetry','','[]','夜雨洗殘暑，秋風應候來。',48,'全唐诗/poet.song.58000.json','["夜雨洗殘暑，秋風應候來。", "庭柯色未減，黄菊意將開。", "布被已思夾，霜鐘漸欲催。", "歲華空向晚，心事日成灰。"]'),
('a7892074-0847-4aab-83c1-a43051c9eff0','破屋','畢仲游','宋','宋诗','song-poetry','','[]','破屋風千穴，櫺疏日一竿。',48,'全唐诗/poet.song.58000.json','["破屋風千穴，櫺疏日一竿。", "長巾籠短髮，舊褐怯新寒。", "道路形容改，悲啼骨髓乾。", "乾坤非不大，無地得閒官。"]'),
('bae059a0-57c6-49ad-9820-c214ffc36941','疏簷','畢仲游','宋','宋诗','song-poetry','','[]','疏簷團鳥雀，畫壁飽風霜。',48,'全唐诗/poet.song.58000.json','["疏簷團鳥雀，畫壁飽風霜。", "汲水三村遠，誅茅半畝强。", "齋錢隨客意，佛事寄僧堂。", "月落人相對，陰陰塔影長。"]'),
('16880c99-afcc-4ec6-b645-105640e4230f','早起','畢仲游','宋','宋诗','song-poetry','','[]','起作南樓望，山河在我傍。',48,'全唐诗/poet.song.58000.json','["起作南樓望，山河在我傍。", "春風入河濟，曉霧合嵩行。", "带郭名園少，穿雲古岸長。", "留連成皓首，何處是吾鄉。"]'),
('363cb6c9-6cde-4c03-a55a-c23401988273','策杖','畢仲游','宋','宋诗','song-poetry','','[]','策杖西原上，東風意浩然。',48,'全唐诗/poet.song.58000.json','["策杖西原上，東風意浩然。", "山河思舊隠，日月換新年。", "徑曲穿林巧，樽移席地偏。", "野花誰飣餖，故故簇平川。"]'),
('c734b26a-8045-48a7-806a-10a5c52bbb98','亂水二首  其一','畢仲游','宋','宋诗','song-poetry','','[]','亂水號新港，頹雲蘸古城。',48,'全唐诗/poet.song.58000.json','["亂水號新港，頹雲蘸古城。", "山樓遥出沒，野日自昏明。", "樹冷禽聲滅，霜高鶻翅輕。", "夢歸今未得，寂寞寸心驚。"]'),
('fd07c3d0-0d2a-464c-bc00-f11cb01fd216','亂水二首  其二','畢仲游','宋','宋诗','song-poetry','','[]','水落芙蕖老，山高薜荔長。',48,'全唐诗/poet.song.58000.json','["水落芙蕖老，山高薜荔長。", "野雲吹不斷，晚雨氣先凉。", "信筆題詩逸，停杯漉酒忙。", "酣歌露雙足，有意濯滄浪。"]'),
('51bae41b-c146-4447-9643-b8ac19d41892','恭輓神宗皇帝二首  其一','畢仲游','宋','宋诗','song-poetry','','[]','御極三宸正，調元一氣淳。',48,'全唐诗/poet.song.58000.json','["御極三宸正，調元一氣淳。", "銅臺漳水夜，玉匣漢陵春。", "地拓山河舊，天升日月新。", "自今遺老內，有是四朝人。"]'),
('65f7360f-d493-48e3-8511-b15ecc69645c','恭輓神宗皇帝二首  其二','畢仲游','宋','宋诗','song-poetry','','[]','北極迴天象，西陵法帝居。',48,'全唐诗/poet.song.58000.json','["北極迴天象，西陵法帝居。", "松門黄道直，帳殿紫宸虛。", "宴罷千秋節，哀纏六尺輿。", "御詩兼手詔，新見睿思書。"]'),
('14f936e7-b811-419f-917f-df0dc2e91f43','恭輓哲宗皇帝二首  其一','畢仲游','宋','宋诗','song-poetry','','[]','徧覆仁無外，尊居道可名。',48,'全唐诗/poet.song.58000.json','["徧覆仁無外，尊居道可名。", "就堯方日出，過杞忽天傾。", "海闊金鳬下，宮開玉鏁鳴。", "早知龍竟去，鑄鼎不須成。"]'),
('7e3e6da1-d917-41a6-8739-4fc2863438ff','恭輓哲宗皇帝二首  其二','畢仲游','宋','宋诗','song-poetry','','[]','容衛千官出，攀號萬國同。',48,'全唐诗/poet.song.58000.json','["容衛千官出，攀號萬國同。", "新名西下壘，空定北郊宮。", "天泣時零雨，神遊恐御風。", "孤臣如在列，應許抱遺弓。"]'),
('06e9ec42-5bcb-4da3-99ac-7fdd2ea861b5','恭輓宣仁聖烈太皇太后四首  其一','畢仲游','宋','宋诗','song-poetry','','[]','受遺開嗣聖，約禮避前人。',48,'全唐诗/poet.song.58000.json','["受遺開嗣聖，約禮避前人。", "聽覽從公議，艱難付老臣。", "宮車閭闔晚，帳殿鞏原春。", "似待吾君長，雲軒即上賓。"]'),
('e2827bd9-8517-46df-902d-c5333f575237','恭輓宣仁聖烈太皇太后四首  其二','畢仲游','宋','宋诗','song-poetry','','[]','聽朝驚屢輟，端拱異平居。',48,'全唐诗/poet.song.58000.json','["聽朝驚屢輟，端拱異平居。", "垂殿簾初徹，因山道已除。", "書遺長樂記，音斷濯龍車。", "誥下猶加惠，華夷定宴如。"]'),
('016257e3-54e1-488f-8b6f-6aa6fd7359ff','恭輓宣仁聖烈太皇太后四首  其三','畢仲游','宋','宋诗','song-poetry','','[]','因革功兼至，權宜道可稱。',48,'全唐诗/poet.song.58000.json','["因革功兼至，權宜道可稱。", "力扶天步穩，端拱太陽升。", "椒寢移彤管，泉關付漆燈。", "須知天子孝，不獨改園陵。"]'),
('ac402bd4-dc2f-4b13-b9d4-e037adaacf38','恭輓宣仁聖烈太皇太后四首  其四','畢仲游','宋','宋诗','song-poetry','','[]','勳業三朝盛，哀榮萬國同。',48,'全唐诗/poet.song.58000.json','["勳業三朝盛，哀榮萬國同。", "人疑無外戚，家不選中宮。", "天泣時零雨，神遊恐御風。", "憂勞如治水，九載亦成功。"]'),
('845bdf5f-b2d7-481e-8292-e9854480a61c','恭輓欽聖憲肅皇太后二首  其一','畢仲游','宋','宋诗','song-poetry','','[]','維昔艱難際，安危屬母慈。',48,'全唐诗/poet.song.58000.json','["維昔艱難際，安危屬母慈。", "元龜猶不豫，大策更誰咨。", "搴霧雲方合，當空月遽迷。", "聖君常泣慕，常以舜爲師。"]'),
('92f11b7d-965c-4cf0-b53f-c7a77f9d3037','恭輓欽聖憲肅皇太后二首  其二','畢仲游','宋','宋诗','song-poetry','','[]','嗣聖當天日，權宜道不居。',48,'全唐诗/poet.song.58000.json','["嗣聖當天日，權宜道不居。", "力明當辟事，豫下撤簾書。", "備物端門遠，神遊武帳虛。", "不知任與姒，較德定何如。"]'),
('76a040ee-45ea-4d36-bdab-0dd37d6f1733','恭輓欽慈皇后二首  其一','畢仲游','宋','宋诗','song-poetry','','[]','神考當天日，宮闈祝燕禖。',48,'全唐诗/poet.song.58000.json','["神考當天日，宮闈祝燕禖。", "日符元有感，坤軸欻先摧。", "追冊音容閟，攀號吉葬哀。", "行知九虞祭，欽聖仗同迴。"]'),
('398e73ad-f28b-47d0-9698-9236e0830efa','恭輓欽慈皇后二首  其二','畢仲游','宋','宋诗','song-poetry','','[]','緬懷章懿事，聖孝代相傳。',48,'全唐诗/poet.song.58000.json','["緬懷章懿事，聖孝代相傳。", "比上欽慈冊，還同明道年。", "玉衣晨不整，帳殿日相連。", "聞說詞多感，哀容可動天。"]'),
('6d581ea6-408f-46e4-a7f2-98f9b85c197f','輓司馬溫國公丞相二首  其一','畢仲游','宋','宋诗','song-poetry','','[]','黄髮來雖暮，丹心病未休。',48,'全唐诗/poet.song.58000.json','["黄髮來雖暮，丹心病未休。", "艱難天下事，際會老臣謀。", "似覺浮風返，空嗟白日留。", "定知名洶洶，萬歲與千秋。"]'),
('873cfc69-39e0-48e6-9418-06b6b416ca7f','輓司馬溫國公丞相二首  其二','畢仲游','宋','宋诗','song-poetry','','[]','禮絕非因貴，哀深却有榮。',48,'全唐诗/poet.song.58000.json','["禮絕非因貴，哀深却有榮。", "世間都畫像，海外亦聞聲。", "後事雖從老，前賢是友生。", "故應房魏輩，泉下定交情。"]'),
('20742015-2052-494f-985f-3df7b92bb395','輓范丞相忠宣公六首  其一','畢仲游','宋','宋诗','song-poetry','','[]','曳杖三朝老，持衡一品尊。',48,'全唐诗/poet.song.58000.json','["曳杖三朝老，持衡一品尊。", "忽同秦逐客，幾見楚冤魂。", "公衮方還第，輀車已及門。", "遺言不須記，一一表中存。"]'),
('5627d220-1006-4252-b1d3-73f2007a1e6c','輓范丞相忠宣公六首  其二','畢仲游','宋','宋诗','song-poetry','','[]','出處從來定，榮華取次休。',48,'全唐诗/poet.song.58000.json','["出處從來定，榮華取次休。", "嘗看居相府，只似在安州。", "不事千金産，能捐萬戶侯。", "哀哉天報施，僅免葬江流。"]'),
('5a21ac45-01e3-4b9c-b48f-c9719a5b2107','輓范丞相忠宣公六首  其三','畢仲游','宋','宋诗','song-poetry','','[]','伏枕言雖少，遺書志可哀。',48,'全唐诗/poet.song.58000.json','["伏枕言雖少，遺書志可哀。", "尚謀裨國事，猶欲盡人材。", "白日空垂照，悲風亦自來。", "更驚諸老盡，吾道信悠哉。"]'),
('48283370-6260-404d-8c8e-908e7964abea','輓范丞相忠宣公六首  其四','畢仲游','宋','宋诗','song-poetry','','[]','大節誰堪擬，危言每可驚。',48,'全唐诗/poet.song.58000.json','["大節誰堪擬，危言每可驚。", "不牽身外物，寧向澤邊行。", "近闕官皆復，還家沒亦榮。", "升堂誰慟哭，知是老門生。"]'),
('7da47212-88cd-4218-bd34-37accc7148ae','輓范丞相忠宣公六首  其五','畢仲游','宋','宋诗','song-poetry','','[]','忠義傳三世，衣冠盛百年。',48,'全唐诗/poet.song.58000.json','["忠義傳三世，衣冠盛百年。", "功名富貴地，父子弟兄賢。", "被放長如往，生歸豈偶然。", "至家還不起，無處問蒼天。"]'),
('d7379919-98dd-4edf-81a7-e94bd52a6039','輓范丞相忠宣公六首  其六','畢仲游','宋','宋诗','song-poetry','','[]','揮淚西原上，晴雲爲我陰。',48,'全唐诗/poet.song.58000.json','["揮淚西原上，晴雲爲我陰。", "誰知如望歲，竟不復爲霖。", "主聖空撝己，民思未絕吟。", "已休還一慟，非但哭知音。"]'),
('d93feedb-6055-4c96-8922-1921fd73fd8d','輓司空申國呂公六首  其一','畢仲游','宋','宋诗','song-poetry','','[]','浩蕩風雲地，哀榮屬老臣。',48,'全唐诗/poet.song.58000.json','["浩蕩風雲地，哀榮屬老臣。", "兩朝尊柱石，三世擅經綸。", "際會看前輩，安寧付後人。", "不須論制作，風俗近還淳。"]'),
('aa5102b2-28d3-45e0-afb1-1f25d32b0a55','輓司空申國呂公六首  其二','畢仲游','宋','宋诗','song-poetry','','[]','騎吹西城曉，衣冠一望中。',48,'全唐诗/poet.song.58000.json','["騎吹西城曉，衣冠一望中。", "尚疑歸鄭國，還似葬溫公。", "道在民先定，兵銷歲自豐。", "故知伊呂事，千載有遺風。"]'),
('f4aa9fa8-bcfb-4302-9c2e-c4b1d28da8da','輓司空申國呂公六首  其三','畢仲游','宋','宋诗','song-poetry','','[]','試論司空事，還如慶曆年。',48,'全唐诗/poet.song.58000.json','["試論司空事，還如慶曆年。", "鹽梅雖國論，衣繡是家傅。", "二聖知人望，三公託世賢。", "奚須論燕處，無事不超然。"]'),
('4c540ba5-4a8d-4e2c-bc60-8f61a356e578','輓司空申國呂公六首  其四','畢仲游','宋','宋诗','song-poetry','','[]','歲月還箕尾，風雲暗上臺。',48,'全唐诗/poet.song.58000.json','["歲月還箕尾，風雲暗上臺。", "定超三界外，元自九天來。", "冰木逡巡合，泉門颯沓開。", "太平雖已見，吾道亦悠哉。"]'),
('480300bf-f1d8-4659-89c9-f2e561e96fb1','輓司空申國呂公六首  其五','畢仲游','宋','宋诗','song-poetry','','[]','位與諸公絕，恩逾上相尊。',48,'全唐诗/poet.song.58000.json','["位與諸公絕，恩逾上相尊。", "朝廷惟再拜，論道掩諸昆。", "體貌傳三世，光華聚一門。", "蒼天苦難料，端坐讀招魂。"]'),
('b81c0eeb-990c-4e8e-9e7c-3c2f81ec4f86','輓司空申國呂公六首  其六','畢仲游','宋','宋诗','song-poetry','','[]','道繼三賢後，名成六相齊。',48,'全唐诗/poet.song.58000.json','["道繼三賢後，名成六相齊。", "氣摩南斗直，功蓋北山低。", "背日衣冠祖，穿雲鹵簿迷。", "道旁誰白首，堅卧作兒啼。"]'),
('017e6966-8836-4b91-bb56-9d0ff110d3b8','輓王元之相公二首  其一','畢仲游','宋','宋诗','song-poetry','','[]','門風清可尚，有道付陶甄。',48,'全唐诗/poet.song.58000.json','["門風清可尚，有道付陶甄。", "舊載傳家榜，新承顧命篇。", "遺文星轉斗，定策日升天。", "東府功名地，安居十五年。"]'),
('cb437661-382c-404f-bd86-453dfab8a32c','輓王元之相公二首  其二','畢仲游','宋','宋诗','song-poetry','','[]','道與風雲會，思留雨露滋。',48,'全唐诗/poet.song.58000.json','["道與風雲會，思留雨露滋。", "小心黄閣老，大手白麻詞。", "家有衣冠盛，朝無故舊私。", "不須三寸舌，終號帝王師。"]'),
('4a5df252-0484-4f7a-9263-09a67973d961','輓歐陽伯和三首  其一','畢仲游','宋','宋诗','song-poetry','','[]','不起斯人疾，哀歌未是哀。',48,'全唐诗/poet.song.58000.json','["不起斯人疾，哀歌未是哀。", "淚流千點血，心死一團灰。", "白日空垂照，悲風亦自來。", "半塗成永訣，天道信悠哉。"]'),
('ea8d9789-da9c-4349-8023-86dbdba5f9d6','輓歐陽伯和三首  其二','畢仲游','宋','宋诗','song-poetry','','[]','慟哭西原迥，晴雲爲我陰。',48,'全唐诗/poet.song.58000.json','["慟哭西原迥，晴雲爲我陰。", "山河一長劍，生死兩知心。", "世譜傳來久，天文驗自今。", "此名埋不得，未信九原深。"]'),
('1609044f-d88b-4659-91d8-47bed8f3ed66','輓歐陽伯和三首  其三','畢仲游','宋','宋诗','song-poetry','','[]','純孝慈顔感，悲啼令季傷。',48,'全唐诗/poet.song.58000.json','["純孝慈顔感，悲啼令季傷。", "鳬飛元傍母，雁少不成雙。", "壽夭從開闢，賢愚竟渺茫。", "不須論甲子，未省鬢毛蒼。"]'),
('7e3dcac7-2041-4667-a4d9-5832b6360507','輓履中學士二首  其一','畢仲游','宋','宋诗','song-poetry','','[]','孝悌由家法，詞章亦世傳。',48,'全唐诗/poet.song.58000.json','["孝悌由家法，詞章亦世傳。", "婚姻甥舅好，門戶弟兄賢。", "問疾猶樽俎，遺文謾簡篇。", "平生惟一轍，何事不長年。"]'),
('b4563315-e42e-4813-ac79-58703a3e0832','輓履中學士二首  其二','畢仲游','宋','宋诗','song-poetry','','[]','漫向蓬丘老，都無一遣車。',48,'全唐诗/poet.song.58000.json','["漫向蓬丘老，都無一遣車。", "家人新買道，弔客舊通書。", "樂事生來少，兼官病後除。", "蒼蒼吾欲問，生理竟何如。"]'),
('491a7dc6-0d5b-4551-853c-56e2668963f7','輓晁端友著作二首  其一','畢仲游','宋','宋诗','song-poetry','','[]','好學五車富，輕財四壁貧。',48,'全唐诗/poet.song.58000.json','["好學五車富，輕財四壁貧。", "風流漢家令，文物晉詩人。", "門戶青氈舊，窮途白髮新。", "招魂誰解意，慚愧屈靈均。"]'),
('12361b8a-c6a5-41d8-948f-a72782152ed6','輓晁端友著作二首  其二','畢仲游','宋','宋诗','song-poetry','','[]','試問生何事，清詩七百餘。',48,'全唐诗/poet.song.58000.json','["試問生何事，清詩七百餘。", "父兄無舊産，妻子有遺書。", "散誕謀生懶，高情與世疏。", "蒼天高莫問，長短竟何如。"]'),
('fe55b11b-aa15-4334-96ba-c3e6b2029028','輓李成之待制六丈三首  其一','畢仲游','宋','宋诗','song-poetry','','[]','高論嵇中散，行吟楚大夫。',48,'全唐诗/poet.song.58000.json','["高論嵇中散，行吟楚大夫。", "笑談雖自若，放逐竟何辜。", "浮世終難料，蒼天不可呼。", "莫論身後事，忠義付諸孤。"]'),
('fa4cd17a-5fcc-4ff1-83f7-2079217603e4','輓李成之待制六丈三首  其二','畢仲游','宋','宋诗','song-poetry','','[]','西帥旌幢舊，東州几杖新。',48,'全唐诗/poet.song.58000.json','["西帥旌幢舊，東州几杖新。", "偏裨嘗破膽，徒弟盍書紳。", "雄略渾無敵，沈機妙若神。", "不須鋤盜賊，公在本良民。"]'),
('69a12952-dde4-477a-9925-98de80d204c8','輓李成之待制六丈三首  其三','畢仲游','宋','宋诗','song-poetry','','[]','道孤存白眼，骨朽任黄泉。',48,'全唐诗/poet.song.58000.json','["道孤存白眼，骨朽任黄泉。", "不與今人合，空爲後世憐。", "文章還誤己，窮達竟歸天。", "遺藁知猶在，應容手自傳。"]'),
('a7740535-0bb2-4e94-9327-913c300c5ac5','輓盧革通議三首  其一','畢仲游','宋','宋诗','song-poetry','','[]','耆宿今多少，惟公景德人。',48,'全唐诗/poet.song.58000.json','["耆宿今多少，惟公景德人。", "家鄰吳市卒，名重漢庭臣。", "路在猶耕月，門閒似送春。", "纔知圖畫好，時見舊精神。"]'),
('21cc446e-da7b-4224-9000-7a1e997c43cc','輓盧革通議三首  其二','畢仲游','宋','宋诗','song-poetry','','[]','教子生前貴，休官物外榮。',48,'全唐诗/poet.song.58000.json','["教子生前貴，休官物外榮。", "居家金節重，開戶玉棺輕。", "江水元如舊，松林長未成。", "祗應山鳥憾，長向壠頭鳴。"]'),
('c095d6c7-5928-4a16-a527-b51d2d76117d','輓盧革通議三首  其三','畢仲游','宋','宋诗','song-poetry','','[]','誰記先生事，聲名五十年。',48,'全唐诗/poet.song.58000.json','["誰記先生事，聲名五十年。", "素風人不及，陰德世相傳。", "氣與名流合，官隨子舍遷。", "闔門賓客散，悵望白雲天。"]'),
('8647ad07-c3be-4237-b042-d47a5b60b239','代范忠宣輓中散某公三首  其一','畢仲游','宋','宋诗','song-poetry','','[]','平日書生貴，中年使者尊。',48,'全唐诗/poet.song.58000.json','["平日書生貴，中年使者尊。", "繡衣雖去國，珠履會填門。", "奏疏皆民事，遺言爲國恩。", "哭君無好句，端坐獨招魂。"]'),
('052d28cb-20c4-4fe1-8e14-46ddae2eef2d','代范忠宣輓中散某公三首  其二','畢仲游','宋','宋诗','song-poetry','','[]','宿昔函關路，遊人作上官。',48,'全唐诗/poet.song.58000.json','["宿昔函關路，遊人作上官。", "鷄鳴軒蓋入，馬到吏民安。", "苦節摧頭白，清名過齒寒。", "生平彈與挂，只是一朝冠。"]'),
('f58bff2f-96fd-4ba6-ab85-3923213d1e07','代范忠宣輓中散某公三首  其三','畢仲游','宋','宋诗','song-poetry','','[]','解組將安適，無何乃故鄉。',48,'全唐诗/poet.song.58000.json','["解組將安適，無何乃故鄉。", "門庭雖取次，詩酒是尋常。", "車過音猶在，琴閒調已亡。", "因居悟生理，天地只茫茫。"]'),
('615d1283-9d8c-48b7-94b9-35a2dc4227b6','代范德孺輓李稷運使四首  其一','畢仲游','宋','宋诗','song-poetry','','[]','倥傯軍中事，飛騰使者尊。',48,'全唐诗/poet.song.58000.json','["倥傯軍中事，飛騰使者尊。", "龍岡雖有地，馬革返無門。", "未見朝廷誄，空遺子弟恩。", "不如行楚澤，先自作招魂。"]'),
('d30d3485-8d84-4194-8469-c07157104d11','代范德孺輓李稷運使四首  其二','畢仲游','宋','宋诗','song-poetry','','[]','萬里魂應返，沙場血未乾。',48,'全唐诗/poet.song.58000.json','["萬里魂應返，沙場血未乾。", "幽明新雨露，恩怨舊衣冠。", "聲作虞歌易，詞賡楚些難。", "莫憐歸骨晚，弔奠只空棺。"]'),
('0b9e464a-4e52-4b1d-abfa-9630759ab90c','代范德孺輓李稷運使四首  其三','畢仲游','宋','宋诗','song-poetry','','[]','吾道何伸屈，斯人忽已亡。',48,'全唐诗/poet.song.58000.json','["吾道何伸屈，斯人忽已亡。", "夢妖非二豎，風變哭三良。", "室有千言記，塵無一窖藏。", "舉頭天色在，今古自蒼蒼。"]'),
('1a9a7c76-5fc7-4dc8-b7f5-4645268d8579','代范德孺輓李稷運使四首  其四','畢仲游','宋','宋诗','song-poetry','','[]','遺札何堪問，知無封禪書。',48,'全唐诗/poet.song.58000.json','["遺札何堪問，知無封禪書。", "殺身今已矣，報國事何如。", "人去衣冠在，魂來戶牖虛。", "應同廣川記，惟見玉蟾蜍。"]'),
('de925885-0c4b-49d2-95bd-6f85c78003ad','送太師潞國文公致仕赴闕朝覲歸洛','畢仲游','宋','宋诗','song-poetry','','[]','事業觀前輩，河汾出異人。',288,'全唐诗/poet.song.58000.json','["事業觀前輩，河汾出異人。", "擎天爲柱石，蓋代服經綸。", "早歲登黄閣，羣公會紫宸。", "指揮平大盜，咳唾福生民。", "契合由天意，威行靜塞塵。", "飽聞鳴鸑鷟，久已畫麒麟。", "陰德歸宗社，昌言啟聖神。", "功成絕能口，道在不謀身。", "自昔規模定，于今風俗淳。", "立廷山不動，容物海無津。", "文力揮南斗，台光拱北宸。", "英姿元岌嶪，雄略只逡巡。", "慷慨遺軒冕，光華被縉紳。", "十年三冊命，四海一師臣。", "貴極多齊物，名高却任真。", "氣完神洒落，骨老石嶙峋。", "正殿需雲合，初筵醴酒淳。", "異恩非故事，全美勸朝倫。", "高卧鵷鴻集，忘懷鳥雀馴。", "鬻熊心益壯，尚父德逾新。", "行色嚴舟御，榮光照席珍。", "二疏翻小節，九老盡佳賓。", "坐上文章士，田間道義鄰。", "曹劉不難致，園綺會相親。"]'),
('01b01d32-c1f2-45b7-94c3-dfcd4a91bbd7','送交代楊應之判官歸洛','畢仲游','宋','宋诗','song-poetry','','[]','借問楊夫子，還家洛浦春。',288,'全唐诗/poet.song.58000.json','["借問楊夫子，還家洛浦春。", "兩爲黄綬吏，雙健白頭親。", "烏帽斜欹面，斑衣穩稱身。", "鵲靈方報喜，龜夢久方神。", "高卧今賢相，居閒舊老臣。", "上堂從隠几，侍坐好書紳。", "存沒空懷感，交遊素耐貧。", "先生墳上淚，御史甑中塵。", "嵩頂饒穿屐，伊流慣幅巾。", "直弦歌太尉，曲學笑平津。", "自滯心元懶，偷閒味却真。", "折腰陶靖節，散髮屈靈均。", "王屋風鳴籟，龍門月漾銀。", "白芽烹澗水，綠笋當江蓴。", "折鹿諸儒喜，騎馿大尹嗔。", "贈人袍已弊，賒酒券常新。", "小子元疏放，忘歸任屈伸。", "馬肝嗟屢食，犬吠脫無因。", "文史慚方朔，形骸謝伯倫。", "恥同珠履客，寧作醉鄉人。", "瓜熟叨爲代，情親願卜鄰。", "乞牋金躑躅，試研玉麒麟。", "祖道無供帳，停車有吐茵。", "心胸兩傾倒，轇轕動星辰。"]'),
('7bfc8199-2185-41c0-8d41-791f45e87296','送鄆州楊子安教授由京歸洛','畢仲游','宋','宋诗','song-poetry','','[]','好去嵩陽客，清河穩放船。',216,'全唐诗/poet.song.58000.json','["好去嵩陽客，清河穩放船。", "東州新學校，南郭富林泉。", "悟道先生敏，爲文子弟傳。", "烏皮常隠几，黄絹動成篇。", "太尉風流在，裴休理性玄。", "老松生幹直，大海得珠圓。", "肆筆君房好，論才賈傅傳。", "尚書行給札，博士久虛員。", "獻策諸公喜，談經衆手編。", "長鯨鱗鬣就，儀鳳羽毛鮮。", "小子甘環堵，窮途懶著鞭。", "家貧門外轍，酒價杖頭錢。", "官冷雖知命，身閒學問禪。", "功名看異日，交契懶同年。", "明月行梁苑，凉風度潁川。", "叫閽宜上疏，負郭莫歸田。", "散飲盃投地，更闌斗挂天。", "離懷吟不足，彈斷古琴弦。"]'),
('0696f923-5aa6-477e-8341-b5e871c6aa97','早寒','畢仲游','宋','宋诗','song-poetry','','[]','十月清宵永，空齋已怯寒。',120,'全唐诗/poet.song.58000.json','["十月清宵永，空齋已怯寒。", "霜籬飛葉密，風案拂沙乾。", "晏叔狐裘穩，公孫布被完。", "簷澌方綴瓦，井凍漸封幹。", "飽食留鷹距，虛驚落雁翰。", "誰來沽酒飲，自笑典衣難。", "想望存心曲，嘻吟恣筆端。", "河冰思澤國，路雪寄長安。", "邑邑爐灰冷，熒熒燭燼闌。", "門前生計在，葦蓆稱車單。"]'),
('88f32e81-6744-4f94-8fa6-4df89887fead','興龍節','畢仲游','宋','宋诗','song-poetry','','[]','簪笏千官拱帝宸，四方同日燕君恩。',64,'全唐诗/poet.song.58000.json','["簪笏千官拱帝宸，四方同日燕君恩。", "五弦度曲南風應，萬壽稱觴北極尊。", "金奏無譁覃雨露，瑶圖有算比乾坤。", "願爲善頌賡天保，如日如山萬子孫。"]'),
('7a90ab86-9efc-4636-ba6b-e34caaef3e86','羅山即事','畢仲游','宋','宋诗','song-poetry','','[]','吏情臨老盍偷閒，異縣人風倦往還。',64,'全唐诗/poet.song.58000.json','["吏情臨老盍偷閒，異縣人風倦往還。", "古屋半摧元是塚，重岡相带不成山。", "昇平是處容餬口，應接非心祗强顔。", "早晚騎鯨跨滄海，欲拋簪笏寄人間。"]'),
('5d9ba5e1-398a-466a-9e23-0c6354e11bd8','信陽軍筵設樂口號二首  其一','畢仲游','宋','宋诗','song-poetry','','[]','談笑西州塞上春，歸來不薄兩朱輪。',64,'全唐诗/poet.song.58000.json','["談笑西州塞上春，歸來不薄兩朱輪。", "功名致主期三代，忠孝傳家第一人。", "御史平生能許國，將軍未老肯謀身。", "義陽今與淮陽比，汲孺當年亦諫臣。"]'),
('f10c7061-e2cd-4185-b8e1-af6cc2d0810e','信陽軍筵設樂口號二首  其二','畢仲游','宋','宋诗','song-poetry','','[]','曾將行事著成書，前世嘗聞近世無。',64,'全唐诗/poet.song.58000.json','["曾將行事著成書，前世嘗聞近世無。", "帝闕天門辭禁近，蜀山秦塞任崎嶇。", "殿帷昔用書囊染，皮几今隨道帽烏。", "忠孝成名生計懶，義田十頃近蘇湖。"]'),
('7074cbd4-7963-40aa-a8f7-a75763b46b3f','至曹州值羅正之著作部夫河上有阻會合以詩見意','畢仲游','宋','宋诗','song-poetry','','[]','百里傳書浪有期，到頭樽俎恰相違。',64,'全唐诗/poet.song.58000.json','["百里傳書浪有期，到頭樽俎恰相違。", "春回通沇花爭發，冰泮明河客未歸。", "年老無成今世有，身閒不飲古人稀。", "諸公憐我如相問，爲道因循未拂衣。"]'),
('a55d2fb5-ed58-4871-9eed-6e8001c80891','內中考進士','畢仲游','宋','宋诗','song-poetry','','[]','北風吹雪舞長廊，束带三千筆陣忙。',64,'全唐诗/poet.song.58000.json','["北風吹雪舞長廊，束带三千筆陣忙。", "地色不通金瑣澀，天香未散玉爐光。", "龍墀暴漲詞源湧，鶴駕迷空羽衛翔。", "三月漢庭重射策，幾人彈幘待王陽。"]'),
('93ee43af-1820-42ee-b833-980898aaf1cb','入內考進士同考官唱和三首  其一','畢仲游','宋','宋诗','song-poetry','','[]','早歲成名地已尊，徘徊五十始乘軒。',64,'全唐诗/poet.song.58000.json','["早歲成名地已尊，徘徊五十始乘軒。", "官同長孺寧居後，疏似王陽獨上言。", "道氣鬰紆灊嶺秀，詞源浩瀚峽江渾。", "研朱共較公孫策，坐覺文風似建元。"]'),
('68a465b5-a1b8-4c40-afbe-609824814d4a','入內考進士同考官唱和三首  其二','畢仲游','宋','宋诗','song-poetry','','[]','未得還家意不忙，日斜人散傍修廊。',64,'全唐诗/poet.song.58000.json','["未得還家意不忙，日斜人散傍修廊。", "白頭已向新吟懶，青眼相逢舊話長。", "高閣無聲沉晝漏，側門有路想天章。", "聞公自謂忘懷者，今日情懷豈易忘。"]'),
('9356d929-3876-4729-9f9a-fd1f1f1a1668','入內考進士同考官唱和三首  其三','畢仲游','宋','宋诗','song-poetry','','[]','明光寓直偶然同，八百儒衣度漢宮。',64,'全唐诗/poet.song.58000.json','["明光寓直偶然同，八百儒衣度漢宮。", "下筆春雷從地起，舉頭帝座在天中。", "條陳不啻三千牘，品藻今惟六七公。", "況是篇章容易得，好令編集附唐風。"]'),
('3c490086-519f-4f4c-b362-4d5caaaac251','登瀛閣','畢仲游','宋','宋诗','song-poetry','','[]','穿池引水事清幽，水有寒魚釣艇浮。',64,'全唐诗/poet.song.58000.json','["穿池引水事清幽，水有寒魚釣艇浮。", "慣識蓬萊好風月，裝成滄海舊汀洲。", "波涵弱柳雙行影，露裛衰荷半頃秋。", "從此東州富賓客，非才先得從公遊。"]'),
('6a074c87-08a9-44fa-9f44-7e8a0ec433f5','余除鑄錢使者居厚除尚書郎俄皆銷印即事二首呈居厚  其一','畢仲游','宋','宋诗','song-poetry','','[]','出處平生大致同，中間得失等雞蟲。',64,'全唐诗/poet.song.58000.json','["出處平生大致同，中間得失等雞蟲。", "髠髦昔似晉羣謝，華髮今成楚兩龍。", "握有蘭香爲子祟，御無銅臭坐余窮。", "善和舊宅殘書卷，只合連床聽曉鐘。"]'),
('ebf67c5b-96fe-447f-8ab9-44277f9614c9','余除鑄錢使者居厚除尚書郎俄皆銷印即事二首呈居厚  其二','畢仲游','宋','宋诗','song-poetry','','[]','病鴻垂翅噤無聲，慣見虛弦莫浪驚。',64,'全唐诗/poet.song.58000.json','["病鴻垂翅噤無聲，慣見虛弦莫浪驚。", "二仲卜鄰元不惡，兩生堅壁未嘗行。", "出關誰識爲周史，入社猶堪伴洛英。", "都把首陽山占斷，採薇到老沒人爭。"]'),
('ac3734b4-8e42-44f6-9d01-f63876045f83','秦州道中','畢仲游','宋','宋诗','song-poetry','','[]','單車五月使西州，行入秦關鳥鼠秋。',64,'全唐诗/poet.song.58000.json','["單車五月使西州，行入秦關鳥鼠秋。", "蘇季金多纔過洛，子房功大願封留。", "新詩欲報難開口，舊物閒思若轉頭。", "邊戍移書謝妻子，搗衣相寄不須愁。"]'),
('e1d64a1d-18fe-4b69-ae39-bfaf184f9cfc','別從事','畢仲游','宋','宋诗','song-poetry','','[]','從事歸來半白頭，吾今便欲別南州。',64,'全唐诗/poet.song.58000.json','["從事歸來半白頭，吾今便欲別南州。", "穿花載酒知難得，散髮行歌且自由。", "官小恰爲黄綬吏，興濃思共赤松遊。", "莫嫌潁上生涯少，會向焦陂買釣舟。"]'),
('6567a5a5-d419-4024-92fe-e7b465ea63b5','潁州道中有感','畢仲游','宋','宋诗','song-poetry','','[]','異鄉聞說潁人賢，我到常疑地使然。',64,'全唐诗/poet.song.58000.json','["異鄉聞說潁人賢，我到常疑地使然。", "江泛五程無險岸，馬行千里盡平川。", "新禾狼籍團團穟，遠樹婆娑簇簇烟。", "寄語汝陰官長道，會須日上泛湖船。"]'),
('62a08788-bde7-4538-85cc-16a1f43bb944','臨潁道中值雨','畢仲游','宋','宋诗','song-poetry','','[]','野氣寒雲漫不收，飄風送雨冷颼颼。',64,'全唐诗/poet.song.58000.json','["野氣寒雲漫不收，飄風送雨冷颼颼。", "路長馬怯驚蹄滑，巢濕鴉飛打樹稠。", "計拙甘爲黄綬吏，途窮空敝黑貂裘。", "閉門坐卧真安穩，吾道東西不自由。"]'),
('f0d986ff-f453-4024-8a89-2568dce4bb45','暫居河上獲從致政丈朝請之遊仰慕高風因成拙句','畢仲游','宋','宋诗','song-poetry','','[]','葛巾欹側鬢毛疏，安穩揚雄宅一區。',64,'全唐诗/poet.song.58000.json','["葛巾欹側鬢毛疏，安穩揚雄宅一區。", "縱酒偶然因客至，行歌渾不用人扶。", "穠花嫩蕊何曾歇，小榭幽亭亦勝無。", "春日出郊惟跨馬，牡丹纔發到西都。"]'),
('30133f6e-9d12-41cd-a470-3b03fd930b77','清河閒居','畢仲游','宋','宋诗','song-poetry','','[]','書囊藥笈付妻孥，解語嬌兒戲坐隅。',64,'全唐诗/poet.song.58000.json','["書囊藥笈付妻孥，解語嬌兒戲坐隅。", "几浄飽看新印史，壁高親挂舊山圖。", "待憑風月招佳客，豈有功名屬腐儒。", "小睡接䍦巾自落，未甘散髮號狂夫。"]'),
('c04e10d3-a02e-4989-ba39-74f937aaefe6','望春宋公第','畢仲游','宋','宋诗','song-poetry','','[]','宋公池館舊相招，人比青松更後凋。',64,'全唐诗/poet.song.58000.json','["宋公池館舊相招，人比青松更後凋。", "但怪麒麟猶素壁，不知祥鳳已丹霄。", "賓筵揖讓雖分散，儒館風流未寂寥。", "不比填門並擁篲，百年纔過即聲銷。"]'),
('cbfaf541-7e4d-4479-99a8-fb338f7d0102','題崇因寺','畢仲游','宋','宋诗','song-poetry','','[]','閒遊偶此共攀緣，勝事誰能爲我傳。',64,'全唐诗/poet.song.58000.json','["閒遊偶此共攀緣，勝事誰能爲我傳。", "山鳥無巢任來往，溪流有石更潺湲。", "路迷空谷寒生霧，目極平林遠自烟。", "便是瀛洲與方丈，不知何處有飛仙。"]'),
('4a06de23-310d-4164-ba86-5f6b57ae4bc0','過天清寺','畢仲游','宋','宋诗','song-poetry','','[]','收拾閒官作伴來，百年懷抱爲君開。',64,'全唐诗/poet.song.58000.json','["收拾閒官作伴來，百年懷抱爲君開。", "高標不數慈恩塔，迥眺如登單父臺。", "料有神明扶岌嶪，恍疑星斗接崔嵬。", "不妨痛飲相牽率，待把生涯付酒杯。"]'),
('fdf5cc73-d792-4f1f-a3de-2fee07fb397c','曹南貢父學士席上','畢仲游','宋','宋诗','song-poetry','','[]','真珠花小帖腮垂，不分蘇州說杜韋。',64,'全唐诗/poet.song.58000.json','["真珠花小帖腮垂，不分蘇州說杜韋。", "漢殿香新初著體，楚宮腰怯未勝衣。", "風林巢穩鶑雛嫩，水閣梁高燕子飛。", "欲作清詩答清唱，恨無清思敵玄暉。"]'),
('b058bb84-7074-48cf-bf54-5e7d575d7771','賀呂子進舍人告謝','畢仲游','宋','宋诗','song-poetry','','[]','金殿移班再拜歸，門庭未冷又光輝。',64,'全唐诗/poet.song.58000.json','["金殿移班再拜歸，門庭未冷又光輝。", "百年相府風流在，三世詞臣際會稀。", "應復異時當化筆，莫留同甲弊朝衣。", "似觀天上三階正，又有文星入紫微。"]'),
('764f41d7-8d18-42be-8b4c-64ecf4ec1a23','次韵和子思舅','畢仲游','宋','宋诗','song-poetry','','[]','聞說幽居傍北溪，莫將歸思作新詩。',64,'全唐诗/poet.song.58000.json','["聞說幽居傍北溪，莫將歸思作新詩。", "未爲野客隨翁去，應被山僧笑我癡。", "近日病中爲酒敵，他年物外得禪師。", "林泉漫有花開約，借馬相從能幾時。"]'),
('21152abc-9ee0-443c-b9ef-b88d6bfc91e3','和陳子思舅探梅','畢仲游','宋','宋诗','song-poetry','','[]','曉過東堂探早梅，山翁指處一枝開。',64,'全唐诗/poet.song.58000.json','["曉過東堂探早梅，山翁指處一枝開。", "只憐舊路無人到，誰爲新詩有意裁。", "晚雪欺凌空自怨，春風吹拂似相猜。", "更須催問今朝客，有酒有花宜早來。"]'),
('a86e3909-4c7b-4e19-a21b-aefda55b39ba','次韵蘇子瞻內翰入直鎖院賜官燭法酒','畢仲游','宋','宋诗','song-poetry','','[]','兼金作带玉爲郎，夜步花磚拜賜忙。',64,'全唐诗/poet.song.58000.json','["兼金作带玉爲郎，夜步花磚拜賜忙。", "絳蠟持來元未點，黄封纔破已聞香。", "星隨燼落花猶在，霜送杯深味更長。", "乞曉却穿丹鳳入，白麻宣對殿中央。"]'),
('2ec754fb-16c9-45e3-aa2d-a098d0204d1f','和趙達夫入試院','畢仲游','宋','宋诗','song-poetry','','[]','不带書來倦日長，詩傳新語似襄陽。',64,'全唐诗/poet.song.58000.json','["不带書來倦日長，詩傳新語似襄陽。", "工夫不比唐風集，氣味如聞漢著香。", "醉酒典衣吾已老，賜袍奪錦子行將。", "憑詩更作騷人體，爲說幽蘭靜處芳。"]'),
('2f0efc7c-64a9-41db-ac77-a5d3438df68c','和趙堯夫晨起','畢仲游','宋','宋诗','song-poetry','','[]','留連夜色城中月，造作秋聲雨後桐。',64,'全唐诗/poet.song.58000.json','["留連夜色城中月，造作秋聲雨後桐。", "殘燭有花非目眩，宿酲無病似頭風。", "未從丹竈遊方外，且對黄粱說夢中。", "三十萬家天欲曉，非烟非霧氣葱葱。"]'),
('e018ebf4-3a04-49dc-b347-67b5dc737bd3','次韵和應之判官寵示之作','畢仲游','宋','宋诗','song-poetry','','[]','青衫補綻髮鬅鬆，未信無文可送窮。',64,'全唐诗/poet.song.58000.json','["青衫補綻髮鬅鬆，未信無文可送窮。", "醉入南山題石虎，夢回西洛賦驚鴻。", "君才特起如秋鶚，我病微吟若夏蟲。", "場屋舊遊都老大，可憐樂事轉頭空。"]'),
('b736afc3-3b84-41d3-aab5-4d9d578d394b','和呂紀常奉使契丹','畢仲游','宋','宋诗','song-poetry','','[]','雪壓胡沙老上庭，春華雖減使華增。',64,'全唐诗/poet.song.58000.json','["雪壓胡沙老上庭，春華雖減使華增。", "且看意氣並人物，未說文章與吏能。", "靴澱早行圍曉月，滹沱還渡坼春冰。", "紅牙新下都司誥，異日應須五色綾。"]'),
('88c321cd-46fd-4e1f-97d4-959c8974adda','次韵和錢穆父提刑九日登鄆州樂郊','畢仲游','宋','宋诗','song-poetry','','[]','酒面吹花點客衣，茱萸採盡葉離離。',64,'全唐诗/poet.song.58000.json','["酒面吹花點客衣，茱萸採盡葉離離。", "蒼苔不掃迷三徑，綠竹長生任四時。", "文會難逢嗟已散，清歡易失却成悲。", "北垣龕石皆陳迹，頼有曹南慰我思。"]'),
('95c0f650-ab09-4584-89de-d18dcead3d5a','和錢穆父舍人','畢仲游','宋','宋诗','song-poetry','','[]','簪笏三人共一班，仙凡回首不相關。',64,'全唐诗/poet.song.58000.json','["簪笏三人共一班，仙凡回首不相關。", "連名花判圍宮硯，隔坐香焚暗博山。", "紅藥對開階兩畔，紫宸入侍殿中間。", "更知外省文書少，草罷詞頭閣老閒。"]'),
('82ca2547-b147-4e6f-843c-3296f8d876ce','寄鄆州李常武兼簡王希才先生須城王敦夫','畢仲游','宋','宋诗','song-poetry','','[]','胡髯洛面少知音，會愛清閒忙至今。',64,'全唐诗/poet.song.58000.json','["胡髯洛面少知音，會愛清閒忙至今。", "負郭買田元有意，上書論事已無心。", "參軍近日詩情老，居士從來理性深。", "若見須城王令尹，爲言憔悴白頭吟。"]'),
('c32308f8-efe6-4266-b8b5-b7342ab38cc1','寄歐蔡二家兄弟','畢仲游','宋','宋诗','song-poetry','','[]','人靜身閒日月遲，酒來誰共倒玻璃。',64,'全唐诗/poet.song.58000.json','["人靜身閒日月遲，酒來誰共倒玻璃。", "吟如峴首山前過，醉似武陵溪畔迷。", "新夢未曾離潁上，舊交長是憶淮西。", "郡城到處頻行樂，駟馬馿車理却齊。"]'),
('ccdc9c6d-b4c9-4a02-b262-c106cae2cc21','和夷仲寄仲純叔弼','畢仲游','宋','宋诗','song-poetry','','[]','流水無聲凍未銷，故人何日許相招。',64,'全唐诗/poet.song.58000.json','["流水無聲凍未銷，故人何日許相招。", "霜花開徧城頭樹，月色應添淮上橋。", "十載塵埃身碌碌，百年杯酒意飄飄。", "弟兄已有東歸意，早晚同來採藥苗。"]'),
('82c5fac9-f896-4c18-9036-d7ade1ac74e2','和河南尹上清宮祈雪','畢仲游','宋','宋诗','song-poetry','','[]','旌旄十里駐邙山，夜醮琳宮太古壇。',64,'全唐诗/poet.song.58000.json','["旌旄十里駐邙山，夜醮琳宮太古壇。", "寶殿降真方隠隠，大田彌望已漫漫。", "撫封和氣通爲潤，載路歡謠不避寒。", "瓊苑玉樓扃大內，惟瞻銀闕在雲端。"]'),
('b2630b05-4488-4bfd-936d-f14f50d96a59','和董十二司戶見寄','畢仲游','宋','宋诗','song-poetry','','[]','官居破屋兩三間，佳客留連我厚顔。',64,'全唐诗/poet.song.58000.json','["官居破屋兩三間，佳客留連我厚顔。", "一月俸餘纔有酒，十分地僻却無山。", "折腰州縣慵來久，散髮江湖願未還。", "不是清朝甘吏隠，偶因多病伏安閑。"]'),
('0e807c03-d54e-4af7-a7c0-cbd03beb50f2','次韵魏承議','畢仲游','宋','宋诗','song-poetry','','[]','翠柏相交夾路深，閉門憔悴白頭吟。',64,'全唐诗/poet.song.58000.json','["翠柏相交夾路深，閉門憔悴白頭吟。", "曉風駕月粘天去，宿雨堆雲接地陰。", "酒伴留連非北道，交情珍重比南金。", "近來髮落牙仍缺，惟有如丹一寸心。"]'),
('80b75cba-5f34-4d4f-b98d-2dd886c2e727','次韵和貢父學士遊左山歸泛北湖','畢仲游','宋','宋诗','song-poetry','','[]','带郭湖山歸故丘，使君把作醉鄉遊。',64,'全唐诗/poet.song.58000.json','["带郭湖山歸故丘，使君把作醉鄉遊。", "僧軒愛客長開戶，沙鳥迎人不避舟。", "一塔清風來處遠，三樓寒月影相留。", "酣歌想見江南路，野客溪禽好在不。"]'),
('73871b5b-5cbf-41c7-b42a-cb9c6b685890','次韵和裴士傑庫部對棋上貢父學士','畢仲游','宋','宋诗','song-poetry','','[]','吏散公堂訟已平，東軒一局晚窗明。',64,'全唐诗/poet.song.58000.json','["吏散公堂訟已平，東軒一局晚窗明。", "風雲不動星辰燦，樽俎無聲玉石爭。", "意外死生由巧拙，手中舒卷乍陰晴。", "自憐小數非秋格，坐久惟聞鴻鵠聲。"]'),
('6ab07620-aca3-4de3-aa15-937044f3286d','次韵和褚恕通察推淮上有感','畢仲游','宋','宋诗','song-poetry','','[]','小床高枕卧書空，節物凄凉歲歲同。',64,'全唐诗/poet.song.58000.json','["小床高枕卧書空，節物凄凉歲歲同。", "錢在杖頭嘗自醉，花開門外爲誰紅。", "君閒好事棋成癖，我病裁詩句不工。", "故國欲歸歸未得，東風隨夢去匆匆。"]'),
('2eee4af6-e00c-4422-8cc9-d12f7ae32c7a','和梅德充見寄','畢仲游','宋','宋诗','song-poetry','','[]','前年離陝宴溪傍，白髮蒼顔各老郎。',64,'全唐诗/poet.song.58000.json','["前年離陝宴溪傍，白髮蒼顔各老郎。", "親意百年楊仲武，友情千里晉真長。", "論詩手出都官藁，好事家傳侍讀香。", "書到并州何處覓，柳溪高會正傳觴。"]'),
('1391612a-b73e-4fca-ab86-f71a7d39afbb','和歐陽伯和見寄','畢仲游','宋','宋诗','song-poetry','','[]','自笑無能與世疏，此身疑作野人居。',64,'全唐诗/poet.song.58000.json','["自笑無能與世疏，此身疑作野人居。", "穿花載酒雖難得，散髮行歌許自如。", "頼有兒童守門戶，不妨賓客到階除。", "會須拂拭烏皮几，準擬虞卿共著書。"]'),
('5d6b368f-9c39-4398-995a-51c98346800d','和李文叔寄虢州孫元忠學士','畢仲游','宋','宋诗','song-poetry','','[]','病懶逢春不似春，已衰心力未閒身。',64,'全唐诗/poet.song.58000.json','["病懶逢春不似春，已衰心力未閒身。", "入關勝跡都題漢，度隴方言漫計秦。", "人會一時親賈馬，交情千里屬雷陳。", "漸知歸計無多事，只待男婚女嫁人。"]'),
('ab90b0f8-5cf5-4928-b6f3-e09452180af6','次韵和穀熟徐仲元著作監倉之什','畢仲游','宋','宋诗','song-poetry','','[]','行見東州山外山，却回河上醉春寒。',64,'全唐诗/poet.song.58000.json','["行見東州山外山，却回河上醉春寒。", "新詩點檢留心苦，舊事尋思覺鼻酸。", "上疏未能同主父，带經猶得學倪寬。", "只今欲作歸休計，淮上田園累歲乾。"]'),
('3113a68d-6d50-4494-995e-7f4982704d0e','奉呈中叔仙翁覬永光和','畢仲游','宋','宋诗','song-poetry','','[]','兩君相得富家聲，書字題詩別有名。',64,'全唐诗/poet.song.58000.json','["兩君相得富家聲，書字題詩別有名。", "健筆九分張長史，苦吟再産謝宣城。", "門閒掩月居人少，木老凌風直舍清。", "顧我菲才空有願，願同吏隠過昇平。"]'),
('3dc62032-84a1-4f5e-bedb-c5201a1f5605','和希魯四兄奉議陪蒲守景叔學士宴名閫堂書事','畢仲游','宋','宋诗','song-poetry','','[]','大棟修梁城北樓，使君冠蓋簇樓頭。',64,'全唐诗/poet.song.58000.json','["大棟修梁城北樓，使君冠蓋簇樓頭。", "左山右水足清會，弔古懷賢非俗流。", "月出長天猶未夕，風來大暑頓成秋。", "登高能賦真吾事，未及相如死不休。"]'),
('eb8f03b3-5a00-467b-98fd-76b475c11814','和宋開叔韵遊風穴山白雲寺','畢仲游','宋','宋诗','song-poetry','','[]','人去人來半日間，徘徊絕頂覺身閒。',64,'全唐诗/poet.song.58000.json','["人去人來半日間，徘徊絕頂覺身閒。", "風雲不動心猶恐，星斗相輝手可攀。", "皂蓋遠如天上至，籃輿曾記月中還。", "防身一劍今誰倚，何必崆峒始是山。"]'),
('edb7177d-80a5-4eb0-a4af-fe90de22ba6b','和僧圓益晚歸三峰','畢仲游','宋','宋诗','song-poetry','','[]','昨朝分路指溪泉，今日憐師寄一篇。',64,'全唐诗/poet.song.58000.json','["昨朝分路指溪泉，今日憐師寄一篇。", "歸去且看松徑綠，重來應見杏花妍。", "風吹林杪聲初鬧，日曬牆陰影漸延。", "待得青春夜如晝，却煩相喚詠嬋娟。"]'),
('f5d3db72-f67a-42ef-a563-263ca8a134c2','和夷仲兄嵩山嶽寺會宿','畢仲游','宋','宋诗','song-poetry','','[]','相迎終日踏泥沙，行過山南路更賒。',64,'全唐诗/poet.song.58000.json','["相迎終日踏泥沙，行過山南路更賒。", "雖有風光堪共賞，自憐詩酒屬吾家。", "野僧好事招題壁，稚子無端愛折花。", "官冷囊空不須問，此身强健自生涯。"]'),
('92117fc8-2f41-4b1b-91ee-148f16104448','悲陳子思','畢仲游','宋','宋诗','song-poetry','','[]','別後悲傷今已休，相逢淚散不能收。',64,'全唐诗/poet.song.58000.json','["別後悲傷今已休，相逢淚散不能收。", "遺書欲問難開口，往事尋思若轉頭。", "李白才華都是夢，淵明牢落幾經秋。", "草堂故地今存否，留作生祠記舊遊。"]'),
('223b730d-da58-4036-a76b-8cc3affb51a8','輓歐陽文忠公三首  其一','畢仲游','宋','宋诗','song-poetry','','[]','夜夢鈞天去不還，送車千乘出長安。',64,'全唐诗/poet.song.58000.json','["夜夢鈞天去不還，送車千乘出長安。", "醉翁亭遠名空在，會老堂深壁未乾。", "墓草荒凉秋日暗，松林蕭索晚風寒。", "北山有石誰能取，四十年名不易刊。"]'),
('d67dc1e1-0d10-41bc-b45b-341413ca7a00','輓歐陽文忠公三首  其二','畢仲游','宋','宋诗','song-poetry','','[]','少師盛德書生服，居士高名數歲餘。',64,'全唐诗/poet.song.58000.json','["少師盛德書生服，居士高名數歲餘。", "清潁歸來人事近，白雲乘去夜堂虛。", "累朝舊籍刊成史，集古新編滿載車。", "聞說使星來已晚，茂陵應復進遺書。"]'),
('4971330a-d142-4779-a780-85959bc5c3ed','輓歐陽文忠公三首  其三','畢仲游','宋','宋诗','song-poetry','','[]','冠冕魁梧二府尊，義緣宗社不謀身。',64,'全唐诗/poet.song.58000.json','["冠冕魁梧二府尊，義緣宗社不謀身。", "生前事業成三主，天下文章無兩人。", "志與經綸埋厚地，道懷正直作明神。", "未年七十身先退，再使人間風俗淳。"]'),
('a384aa71-27e0-4573-810a-0891d4ec38c8','和陳子思遊靈泉山','畢仲游','宋','宋诗','song-poetry','','[]','婆娑盤石大，狼籍野雲多。',24,'全唐诗/poet.song.58000.json','["婆娑盤石大，狼籍野雲多。", "借問山中客，桃源路幾何。"]'),
('3dad075c-88ce-45b3-bf65-347c7bbfa483','和十一舅題金蝦蟆','畢仲游','宋','宋诗','song-poetry','','[]','石窟昔藏金，蟾光射百尋。',24,'全唐诗/poet.song.58000.json','["石窟昔藏金，蟾光射百尋。", "今朝在何處，山景正陰陰。"]'),
('00d7303d-08ae-4735-a5a0-f85176eeca76','和希之','畢仲游','宋','宋诗','song-poetry','','[]','幽禪吾不學，靜處豈無心。',24,'全唐诗/poet.song.58000.json','["幽禪吾不學，靜處豈無心。", "日轉眠雙樹，風和散兩襟。"]'),
('587214c0-ff79-4261-98af-671a518dd361','月沒','畢仲游','宋','宋诗','song-poetry','','[]','月沒雲生障，風和雪壓沙。',24,'全唐诗/poet.song.58000.json','["月沒雲生障，風和雪壓沙。", "居家嘗似客，行路却如家。"]'),
