('14f286e5-a05e-4a4e-99b9-2dd21ae97154','答童師敏','蔡京','宋','宋诗','song-poetry','','[]','聞說羣花爛漫開，知君醉賞不能來。',32,'全唐诗/poet.song.58000.json','["聞說羣花爛漫開，知君醉賞不能來。", "臨風對酒空惆悵，不得相從把一杯。"]'),
('fc831c20-94a4-4391-9cad-220a02e5d24c','與范謙叔飲西園','蔡京','宋','宋诗','song-poetry','','[]','一日趨朝四日閒，荒園薄酒願交驩。',64,'全唐诗/poet.song.58000.json','["一日趨朝四日閒，荒園薄酒願交驩。", "三峰崛起無平地，二派爭流有激湍。", "極目榛蕪惟野蔓，忘憂魚鳥自波瀾。", "滿船載得圭璋重，更掬珠璣洗眼看。"]'),
('c54f5e40-8601-4601-a70e-9655cd19d3af','送蔡攸征燕','蔡京','宋','宋诗','song-poetry','','[]','老懶身心不自由，封書寄與淚橫流。',64,'全唐诗/poet.song.58000.json','["老懶身心不自由，封書寄與淚橫流。", "百年信誓當深念，三伏征塗盍少休。", "目送旌旗如昨夢，心存關塞起新愁。", "緇衣堂下清風滿，早早歸來醉一甌。"]'),
('586b4ee4-a0b4-432c-84f7-7238f08dcacb','別寵姬','蔡京','宋','宋诗','song-poetry','','[]','爲愛桃花三樹紅，年年歲歲惹東風。',32,'全唐诗/poet.song.58000.json','["爲愛桃花三樹紅，年年歲歲惹東風。", "如今去逐它人手，誰復尊前念老翁。"]'),
('012ab4f7-2f14-4fea-befb-7465cc9e6e02','恭和御制己亥十一月十三日南郊祭天齋宮即事賜詩  其一','蔡京','宋','宋诗','song-poetry','','[]','雪晴至日日初南，帝舉明禋祀事嚴。',64,'全唐诗/poet.song.58000.json','["雪晴至日日初南，帝舉明禋祀事嚴。", "萬瓦溝中寒色在，一輪空外曉光暹。", "雲和龍軫開冰轍，風暖鸞旗拂凍簷。", "共喜天心扶聖德，珠璣更誤寵恩霑。"]'),
('7513e646-1ad5-4aba-9b84-8e73bc889231','恭和御制己亥十一月十三日南郊祭天齋宮即事賜詩  其二','蔡京','宋','宋诗','song-poetry','','[]','展采齊明拱面南，濃雲深入夜更嚴。',64,'全唐诗/poet.song.58000.json','["展采齊明拱面南，濃雲深入夜更嚴。", "風和不放瓊英落，日暖高隨玉漏暹。", "照地神光臨午陛，鳴皋仙羽下重簷。", "五門回仗如天上，看舉雞竿雨露霑。"]'),
('0a971071-0ab6-4b4d-877f-3805893ca74f','恭和御制己亥十一月十三日南郊祭天齋宮即事賜詩  其三','蔡京','宋','宋诗','song-poetry','','[]','衮龍朱履午階南，大輦鸞鳴羽衛嚴。',64,'全唐诗/poet.song.58000.json','["衮龍朱履午階南，大輦鸞鳴羽衛嚴。", "玉軫乍回黄道穩，金烏初上白雲暹。", "五門曉吹開旗尾，萬騎花光入帽簷。", "已見神光昭感格，鶴書恩下萬邦霑。"]'),
('ac44b993-e3d2-49d9-be55-474378c91ba1','恭和御制己亥十一月十三日南郊祭天齋宮即事賜詩  其四','蔡京','宋','宋诗','song-poetry','','[]','飲福初回八陛南，凝旒裒對百神嚴。',64,'全唐诗/poet.song.58000.json','["飲福初回八陛南，凝旒裒對百神嚴。", "睍消塵入康衢潤，神應光隨北陸暹。", "丹檻雉開中扇影，朱繩鶴下五門簷。", "羣生鼓舞明禋畢，却憶花飛舞袖霑。"]'),
('c3e577d4-5815-47c7-8c99-8fb97b6cbcbb','題神霄宮  其一','蔡京','宋','宋诗','song-poetry','','[]','下馬神霄第一回，晴空宮殿九秋開。',32,'全唐诗/poet.song.58000.json','["下馬神霄第一回，晴空宮殿九秋開。", "月中桂子看時落，雲外仙軿特地來。"]'),
('9011c4c3-e2d9-40b5-9507-d1b1fb340033','題神霄宮  其二','蔡京','宋','宋诗','song-poetry','','[]','參差碧瓦切昭回，繡戶雲輀次第開。',32,'全唐诗/poet.song.58000.json','["參差碧瓦切昭回，繡戶雲輀次第開。", "仙伯九霄曾付託，得隨真主下天來。"]'),
('f40971d6-36f3-46d6-bcd7-0cb451b626f4','留題保和殿壁','蔡京','宋','宋诗','song-poetry','','[]','瓊瑶錯落密成林，檜竹交加午有陰。',32,'全唐诗/poet.song.58000.json','["瓊瑶錯落密成林，檜竹交加午有陰。", "恩許塵凡時縱步，不知身在五雲深。"]'),
('e906a41e-4726-4c53-a20e-b9b53bcb081a','至玉真軒奉詔賡補','蔡京','宋','宋诗','song-poetry','','[]','保和新殿麗秋暉，詔許塵凡到綺闈。',32,'全唐诗/poet.song.58000.json','["保和新殿麗秋暉，詔許塵凡到綺闈。", "雅燕酒酣添逸興，玉真軒內看安妃。"]'),
('23ec9d60-b87d-4318-8dae-144662fab399','見安妃像','蔡京','宋','宋诗','song-poetry','','[]','玉真軒檻暖如春，只見丹青未有人。',32,'全唐诗/poet.song.58000.json','["玉真軒檻暖如春，只見丹青未有人。", "月裏常娥終有恨，鑑中姑射未應真。"]'),
('815a8325-ec5f-4a4d-8296-f3ac4ab82fef','紹聖春宴口號  其一','蔡京','宋','宋诗','song-poetry','','[]','牙牌曉奏集英班，日照雲龍下九關。',32,'全唐诗/poet.song.58000.json','["牙牌曉奏集英班，日照雲龍下九關。", "紅蠟青烟寒食後，翠華黄屋太微間。"]'),
('44a38171-6bf5-492f-9aa8-3c68a44ae286','紹聖春宴口號  其二','蔡京','宋','宋诗','song-poetry','','[]','三春樂奏三春曲，萬歲聲連萬歲山。',32,'全唐诗/poet.song.58000.json','["三春樂奏三春曲，萬歲聲連萬歲山。", "欲識君臣同樂意，天威咫尺不違顔。"]'),
