('a02ab21f-e8b7-4a5a-a14a-571eee1175c7','句  其七','蔡京','宋','宋诗','song-poetry','','[]','姑射神仙猶飲露，龜臺王母未忘桃。',16,'全唐诗/poet.song.58000.json','["姑射神仙猶飲露，龜臺王母未忘桃。"]'),
('54b44aed-854c-481b-9c16-21ffb42969b8','潭嵐院','李孝博','宋','宋诗','song-poetry','','[]','堆積嵐光照碧潭，山前一寺號潭嵐。',32,'全唐诗/poet.song.58000.json','["堆積嵐光照碧潭，山前一寺號潭嵐。", "四時想見無窮景，借問老僧能盡談。"]'),
('c2bfd48c-e3e7-486e-bfdb-44fdfb674b61','次蔣穎叔韵','李孝博','宋','宋诗','song-poetry','','[]','維舟亭下號三灣，萬疊青山一水間。',32,'全唐诗/poet.song.58000.json','["維舟亭下號三灣，萬疊青山一水間。", "偏愛澄江照天碧，飛來幾片白雲閑。"]'),
('f3682be4-d767-400e-9a0c-f9c4c5aec998','別惠山贈璋山主','蕭淵','宋','宋诗','song-poetry','','[]','三年愛山來幾回，携筇躡履真悠哉。',129,'全唐诗/poet.song.58000.json','["三年愛山來幾回，携筇躡履真悠哉。", "片石可枕雲可偎，愆期不到縈吾懷。", "中藉高僧還有才，能與佳勝爲良媒。", "汲泉煮茗何歡咍，松邊竹下容琴杯。", "我嗟官滿今還臺，欲去不忍須重來。", "慇懃慇懃孰與偕，寒猿老鶴聲相哀。", "山有情兮韞瓊瑰，願泉無窮兮滋九垓。", "它時再賞登崔嵬，約師把手忘形骸。"]'),
('820f22ed-63f4-4313-afeb-f601bec7549d','題共樂堂','柳安道','宋','宋诗','song-poetry','','[]','平波數頃萬峰前，一片丹青畫不全。',64,'全唐诗/poet.song.58000.json','["平波數頃萬峰前，一片丹青畫不全。", "幽榭小橋橫翠水，茂林修竹鎖輕烟。", "綺羅弦管追歡地，雪月風花爛醉天。", "爭奈及瓜歸覲去，湖山無復苦留連。"]'),
('b9f42f6c-a808-4154-890a-17a52ce9e7b6','送程給事知越州','謝慥','宋','宋诗','song-poetry','','[]','越山岝㟯凌蒼穹，北山獨秀誇卧龍。',190,'全唐诗/poet.song.58000.json','["越山岝㟯凌蒼穹，北山獨秀誇卧龍。", "集賢學士辭青瑣，高牙新擁千騎雄。", "晝看卧龍峰，夕隠蓬萊宮。", "雙旌倒影射日紅，心閑不厭來山中。", "排虛屏障環四封，翠積琉璃千萬重。", "乍見烟霞西復東，倏聽海鼓鳴鼕鼕。", "照湖一望光悠溶，寒波百里秋瞳矓。", "茂林修竹交青葱，崢嶸樓閣疑天通。", "使君况復氣摩空，高吟萬字才不窮。", "醉倒猶索黄金鍾，下筆凜凜生清風。", "幸當聖世民俗豐，莫惜樽俎頻雍容。", "但憂政成被追鋒，白雲幽鳥不得長相從。"]'),
('5cfe2c35-ecb0-45ea-b363-6ff7d439114e','句  其一','畢仲愈','宋','宋诗','song-poetry','','[]','徘徊幽興盡。',6,'全唐诗/poet.song.58000.json','["徘徊幽興盡。"]'),
('9d02c7e5-d43b-4783-9857-4fae79c0e8c8','句  其二','畢仲愈','宋','宋诗','song-poetry','','[]','已招明月移歌扇，更倩春風試舞腰。',16,'全唐诗/poet.song.58000.json','["已招明月移歌扇，更倩春風試舞腰。"]'),
('9ec14904-18a2-4652-90c0-455cd16bb5cf','句  其三','畢仲愈','宋','宋诗','song-poetry','','[]','明燈數點林中見，橫笛一聲烟外聞。',16,'全唐诗/poet.song.58000.json','["明燈數點林中見，橫笛一聲烟外聞。"]'),
('6e304ef1-f88b-417a-88cb-8aaaa838d499','句','李籍','宋','宋诗','song-poetry','','[]','三公歷拜皆無敵，二府更居貴莫倫。',16,'全唐诗/poet.song.58000.json','["三公歷拜皆無敵，二府更居貴莫倫。"]'),
('572217b9-fc4c-45d9-ac06-af1d75867c3d','句','王鯨','宋','宋诗','song-poetry','','["\u897f\u6e56"]','時闢西湖作勝遊，使君元是濟川舟。',16,'全唐诗/poet.song.59000.json','["時闢西湖作勝遊，使君元是濟川舟。"]'),
('cd9b14f9-8b83-48d7-a69f-a68777e1019e','題忠烈侯廟','萬規','宋','宋诗','song-poetry','','[]','王事多艱險不移，委身先敵大江湄。',64,'全唐诗/poet.song.59000.json','["王事多艱險不移，委身先敵大江湄。", "臨危授命生前勇，列爵封侯死後祠。", "龔寇已隨湍下沒，子規無復夜深悲。", "欲知幽顯存忠義，勳業重光兩石碑。"]'),
('6b0f7c3f-7a8b-4d8e-a537-887967764317','題雙瀑亭','萬規','宋','宋诗','song-poetry','','[]','萬斛珠璣瀉碧空，幾年含蓄在龍宮。',64,'全唐诗/poet.song.59000.json','["萬斛珠璣瀉碧空，幾年含蓄在龍宮。", "春秋未斷縱橫勢，南北曾奔次第雄。", "莫向寒岩長漱石，好歸滄海共成功。", "曾看清夜陪明月，影破朝陽鳳入桐。"]'),
('eb3dd3ad-17e2-440d-bdd0-c3fa1c35db0a','訪曹副宮不遇留題','李陶真','宋','宋诗','song-poetry','','[]','一別仙標歷四春，神霄今復又相親。',64,'全唐诗/poet.song.59000.json','["一別仙標歷四春，神霄今復又相親。", "爐中氣候丹初熟，匣裏光芒劍有神。", "未駕鸞輿朝碧落，且將蹤跡傲紅塵。", "乘風暫過羌廬去，異日相期拜紫宸。"]'),
('3efe3524-ba59-4dea-b6b8-f7f958c5ce7d','留詩別衆','李陶真','宋','宋诗','song-poetry','','[]','毛竹森森自翦裁，試吹一曲下瑶臺。',32,'全唐诗/poet.song.59000.json','["毛竹森森自翦裁，試吹一曲下瑶臺。", "當途不遇知音者，拂袖白雲歸去來。"]'),
('795fb6d2-f220-43f5-9ac6-df86363fc22a','孔林','范正民','宋','宋诗','song-poetry','','[]','漢陵玉匣盡，秦山銀海空。',72,'全唐诗/poet.song.59000.json','["漢陵玉匣盡，秦山銀海空。", "干戈百世後，獨完先聖宮。", "樹有千年色，門無數仞崇。", "盛德包覆載，遂順因所宗。", "坐若顔閔後，頗聞鄒魯風。", "撫膺感遺言，零落涕沾胸。"]'),
('4c7ce7c4-c229-4758-8e7d-bcc850d26f58','季顔師顔謫齊州以詩寄之','范正民','宋','宋诗','song-poetry','','[]','歷下故人今何在，音書久已隔寒暄。',64,'全唐诗/poet.song.59000.json','["歷下故人今何在，音書久已隔寒暄。", "多年別後紛紛事，何日罇前細細論。", "忍見風霜摧羽翮，空教江漢瀉詞源。", "聖朝寬大超前古，即有恩光照覆盆。"]'),
('8bef24cd-a048-41c3-9b6d-0e9e7e294745','吳江太湖笠澤虹橋','江汝明','宋','宋诗','song-poetry','','["\u592a\u6e56"]','地據東吳勝，江從震澤連。',24,'全唐诗/poet.song.59000.json','["地據東吳勝，江從震澤連。", "萬家臨一水，千古得三賢。"]'),
('07a6828e-47b0-4a6d-8f97-63d078b917fe','送張邦基母  其一','陳氏','宋','宋诗','song-poetry','','[]','念別每驚魂，流年多病身。',48,'全唐诗/poet.song.59000.json','["念別每驚魂，流年多病身。", "惟我延陵子，情真意更親。", "分携無淚盡，望遠更愁新。", "老眼將何暖，音書不厭頻。"]'),
('eaaee990-b429-473d-b3fd-7aaa13115c57','送張邦基母  其二','陳氏','宋','宋诗','song-poetry','','[]','雪意亂江雲，江梅漸放春。',48,'全唐诗/poet.song.59000.json','["雪意亂江雲，江梅漸放春。", "雁歸人去後，愁與歲華新。", "榮路君方振，園居我豈貧。", "惟餘憂我念，相憶莫沾巾。"]'),
('f4ff21f8-9afe-4147-b551-85c966ca2ad5','合肥書懷','朱服','宋','宋诗','song-poetry','','[]','歷盡風波老境侵，一麾重寄蜀山陰。',32,'全唐诗/poet.song.59000.json','["歷盡風波老境侵，一麾重寄蜀山陰。", "時清不復崇詩禁，更向淮西續舊吟。"]'),
('e4b7558f-f25f-466b-a7de-3a70425adbe5','廬州三首  其一','朱服','宋','宋诗','song-poetry','','[]','晴湖列遠岫，萬疊來駿奔。',24,'全唐诗/poet.song.59000.json','["晴湖列遠岫，萬疊來駿奔。", "橫入小蜀岡，金友依玉昆。"]'),
('21d51285-9a70-48be-9a22-7688313d6299','廬州三首  其二','朱服','宋','宋诗','song-poetry','','[]','將軍蕩寇力能任，陳迹依然得重尋。',32,'全唐诗/poet.song.59000.json','["將軍蕩寇力能任，陳迹依然得重尋。", "血繞樓船龍戰息，水搖城堞雉飛深。"]'),
('f761272c-88da-4f55-ac47-f5eded6be544','廬州三首  其三','朱服','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','肥川勝賞冠他州，浦口揚舲得俊遊。',32,'全唐诗/poet.song.59000.json','["肥川勝賞冠他州，浦口揚舲得俊遊。", "梅雨正迷江國路，萍風未破洞庭秋。"]'),
('f47d1f98-8363-4fa8-a369-773e3ce1570e','巢湖','朱服','宋','宋诗','song-poetry','','[]','平湖壓郡境，血食等靈媼。',24,'全唐诗/poet.song.59000.json','["平湖壓郡境，血食等靈媼。", "豈無升斗水，活此車中薧。"]'),
('1b1a5cbc-f756-4bca-9a4d-a910cc31bb65','過廬州','朱服','宋','宋诗','song-poetry','','[]','昔年吳魏交兵地，今日承平會府開。',64,'全唐诗/poet.song.59000.json','["昔年吳魏交兵地，今日承平會府開。", "沃壤欲包淮甸盡，堅城猶抱蜀山迴。", "柳塘春水藏舟浦，蘭若秋風教弩臺。", "獨有無情原上草，青青還入燒痕來。"]'),
('081e9341-09df-48a8-a904-056bb6ad850e','九日','朱服','宋','宋诗','song-poetry','','[]','一見黄花只自羞，蕭然短髮不禁秋。',32,'全唐诗/poet.song.59000.json','["一見黄花只自羞，蕭然短髮不禁秋。", "誰人爲整烏紗帽，獨倚西風滿眼愁。"]'),
('6aa5b41b-3043-40d0-b1f0-57c162055a91','柳絮','朱服','宋','宋诗','song-poetry','','[]','隨風逐浪事輕狷，巧占人間欲夏天。',32,'全唐诗/poet.song.59000.json','["隨風逐浪事輕狷，巧占人間欲夏天。", "只恐障空飛似雪，從教糝徑白於綿。"]'),
('0773089d-45a4-4e45-b81b-7d77f435ecae','次韵桃花菊','朱服','宋','宋诗','song-poetry','','[]','籬邊不語自成蹊，紅入秋叢見亦稀。',64,'全唐诗/poet.song.59000.json','["籬邊不語自成蹊，紅入秋叢見亦稀。", "亂插烏巾酬老健，輕浮白酒惜春歸。", "劉郎一去花何晚，陶令重來色已非。", "蝶散蜂藏無足怪，冷香寒艷不堪依。"]'),
('9f9829c5-1b76-48be-b268-5eae7bfa4eda','梅花','朱服','宋','宋诗','song-poetry','','[]','幽香淡淡影疏疏，雪虐風飛亦自如。',32,'全唐诗/poet.song.59000.json','["幽香淡淡影疏疏，雪虐風飛亦自如。", "正是花中巢許輩，人間富貴不關渠。"]'),
('1e2fee8f-5fe7-4070-94bc-dac4a0f910d8','元豐盛事','朱服','宋','宋诗','song-poetry','','[]','冠带橋門路，雍容俊士關。',48,'全唐诗/poet.song.59000.json','["冠带橋門路，雍容俊士關。", "微言尊噩噩，小道屏閒閒。", "禮樂高千古，詩書到百蠻。", "斯文知未泯，璧水尚如環。"]'),
('672ad527-4843-4d6a-b6a1-4f425b1a52fa','汨羅弔屈原','朱服','宋','宋诗','song-poetry','','[]','委命仇讎事可知，章華荆棘國人悲。',32,'全唐诗/poet.song.59000.json','["委命仇讎事可知，章華荆棘國人悲。", "恨公無壽如金石，不見秦嬰繫頸時。"]'),
('154d1cff-64ca-4f84-9a4b-25586c8514cb','題東老庵','朱服','宋','宋诗','song-poetry','','[]','收拾精神歸卷內，了無非譽入懷中。',64,'全唐诗/poet.song.59000.json','["收拾精神歸卷內，了無非譽入懷中。", "祇因庭樹藏春色，更有琴書繼古風。", "學道固非原憲病，好賢誰信孟嘗窮。", "清尊猶剩回仙酒，萬家悠然一醉空。"]'),
('77d2b9ab-431c-458e-95e9-161f7e1067c1','句  其一','朱服','宋','宋诗','song-poetry','','[]','孤臣正泣龍髯草，遊子空簪鳳尾花。',16,'全唐诗/poet.song.59000.json','["孤臣正泣龍髯草，遊子空簪鳳尾花。"]'),
('f62cb80a-2164-4f38-bc95-d6f008457599','句  其二','朱服','宋','宋诗','song-poetry','','[]','相逢盡欲傾家釀，久客誰能散橐金。',16,'全唐诗/poet.song.59000.json','["相逢盡欲傾家釀，久客誰能散橐金。"]'),
('5c6ccb39-5561-485b-ac5c-87767844c82c','句  其三','朱服','宋','宋诗','song-poetry','','[]','水無涓滴不爲用，山到崔嵬猶力耕。',16,'全唐诗/poet.song.59000.json','["水無涓滴不爲用，山到崔嵬猶力耕。"]'),
('08c74d9f-511b-4531-9122-322b1ba3ef1a','句  其四','朱服','宋','宋诗','song-poetry','','[]','鷄鳴分水繞肥城。',8,'全唐诗/poet.song.59000.json','["鷄鳴分水繞肥城。"]'),
('ce1c8746-0331-4462-872d-d5aff17132aa','句  其五','朱服','宋','宋诗','song-poetry','','[]','琉璃十頃浸旻蒼，此境淮南自少雙。',16,'全唐诗/poet.song.59000.json','["琉璃十頃浸旻蒼，此境淮南自少雙。"]'),
('b0ef1786-e07e-4325-8656-a175ed34d780','句  其六','朱服','宋','宋诗','song-poetry','','[]','睠戀肥城詎忍還，每貪公退枕書眠。',16,'全唐诗/poet.song.59000.json','["睠戀肥城詎忍還，每貪公退枕書眠。"]'),
('0eaab82a-24f9-42b2-8caa-fcc4f9a67fbd','句  其七','朱服','宋','宋诗','song-poetry','','[]','九韶先幸舜，五嶺後通秦。',12,'全唐诗/poet.song.59000.json','["九韶先幸舜，五嶺後通秦。"]'),
('4a6dc0ef-ba32-4510-b2e9-0b28443193c7','句  其八','朱服','宋','宋诗','song-poetry','','[]','遥看一樹凌霜葉，好似衰顔醉裏紅。',16,'全唐诗/poet.song.59000.json','["遥看一樹凌霜葉，好似衰顔醉裏紅。"]'),
('f48aa222-08a6-424c-8072-60818f76a810','句  其九','朱服','宋','宋诗','song-poetry','','[]','西清邇英閣，密勿侍經筵。',36,'全唐诗/poet.song.59000.json','["西清邇英閣，密勿侍經筵。", "晝漏逾三鼓，宸居近玉磚。", "多聞資學殖，清問發真筌。"]'),
('bba9b103-5d31-465b-ac66-0ddfee08ec93','子瞻和予致齋詩有端向甕間尋吏部老來惟欲醉爲鄉之句因送薄酒兼成斐章冀發笑也','趙令鑠','宋','宋诗','song-poetry','','[]','古人醉以酒，蓋亦有所寓。',72,'全唐诗/poet.song.59000.json','["古人醉以酒，蓋亦有所寓。", "一飲百憂忘，陶陶朝復暮。", "公欲醉爲鄉，甕間尋吏部。", "惜取青銅錢，濁醪安足酤。", "敢竊好事名，聊資子雲具。", "巧手斧鼻端，此情知有素。"]'),
('ca7648e8-3fdf-4ba3-a346-4fa506cd88c5','子瞻辭免起居之命令鑠復用前韵一首以勉之','趙令鑠','宋','宋诗','song-poetry','','[]','登州與儀曹，到官如旅寓。',72,'全唐诗/poet.song.59000.json','["登州與儀曹，到官如旅寓。", "螭陛鳳凰池，翱翱未云暮。", "冰雪照人清，黄色盈中部。", "譬如千日釀，一宿陋清酤。", "載筆無多時，公真濟時具。", "歎息賀德基，猶知我尸素。"]'),
('392988d8-129c-4279-9371-cb2965296f7d','遊紫麟峰','趙令松','宋','宋诗','song-poetry','','[]','千仞奇峰薄上清，葛洪於此尚留名。',64,'全唐诗/poet.song.59000.json','["千仞奇峰薄上清，葛洪於此尚留名。", "紫麟瑞靄春風暖，白虎丹成夜月明。", "點點蒼苔空有跡，菲菲芳草不聞聲。", "高蹤回首今何在，山水猶含萬古情。"]'),
('1b7b189c-c023-4fcb-a787-1585f8b720d7','賜秦國大長公主挽詞三首  其一','宋神宗','宋','宋诗','song-poetry','','[]','海闊三山路，香輪定不歸。',48,'全唐诗/poet.song.59000.json','["海闊三山路，香輪定不歸。", "帳深空翡翠，珮冷失珠璣。", "明月留歌扇，殘霞散舞衣。", "都門送車返，宿草自春菲。"]'),
('18977a0e-d70d-4419-84c0-8fa94f039ef4','賜秦國大長公主挽詞三首  其二','宋神宗','宋','宋诗','song-poetry','','[]','曉發城西道，靈車望更遥。',48,'全唐诗/poet.song.59000.json','["曉發城西道，靈車望更遥。", "春風空魯館，明月斷秦簫。", "塵入羅衣暗，香隨玉篆銷。", "芳魂飛北渚，那復可爲招。"]'),
('f7fc65c4-2c08-49c9-b53c-7cc12b1eb5b3','賜秦國大長公主挽詞三首  其三','宋神宗','宋','宋诗','song-poetry','','[]','慶自天源發，恩從國愛申。',48,'全唐诗/poet.song.59000.json','["慶自天源發，恩從國愛申。", "歌鐘雖在館，桃李不成春。", "水折空還沁，樓高已隔秦。", "區區會稽市，無復獻珠人。"]'),
('2aa35608-a263-45b6-b482-29a5b93890dc','四言詩一章','宋神宗','宋','宋诗','song-poetry','','[]','五季失圖，獫狁孔熾。',40,'全唐诗/poet.song.59000.json','["五季失圖，獫狁孔熾。", "藝祖造邦，意有懲艾。", "爰設內府，基以募士。", "曾孫保之，敢忘厥志。"]'),
('286dde90-a50c-4fe3-b6a5-df8581081a2f','題封樁庫','宋神宗','宋','宋诗','song-poetry','','[]','每虔夕惕心，妄意遵遺業。',24,'全唐诗/poet.song.59000.json','["每虔夕惕心，妄意遵遺業。", "顧予不武資，何以成戎捷。"]'),
('5419c666-7bf8-4e22-adec-1b74c0d22cc8','賜大理丞梁士基橫州宅生連理荔枝','宋神宗','宋','宋诗','song-poetry','','[]','橫浦江南岸，梁家聞世賢。',24,'全唐诗/poet.song.59000.json','["橫浦江南岸，梁家聞世賢。", "一株連理木，五月荔枝天。"]'),
('ac596518-3204-4f54-8206-2d93af1dafc4','賜太師文彥博','宋神宗','宋','宋诗','song-poetry','','[]','四紀忠勞著，三朝聞望隆。',48,'全唐诗/poet.song.59000.json','["四紀忠勞著，三朝聞望隆。", "享茲難老祉，報在不言功。", "富矣勳彌大，居焉貌甚沖。", "西都舊士女，白首竚瞻公。"]'),
('a924f7a8-9a81-4ef1-8568-ae4a1e425d9f','句  其一','宋神宗','宋','宋诗','song-poetry','','[]','一方文武魁天下，萬里英雄入彀中。',16,'全唐诗/poet.song.59000.json','["一方文武魁天下，萬里英雄入彀中。"]'),
('828addba-7405-4676-ac9e-4b478c2a09a7','句  其二','宋神宗','宋','宋诗','song-poetry','','[]','燕翼功參九，安榮世歷三。',24,'全唐诗/poet.song.59000.json','["燕翼功參九，安榮世歷三。", "軒輝雖揜北，風教自存南。"]'),
('e878a4e4-02d0-405a-8408-8cf31fab1439','句','袁百之','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長江雪浪過樊口，西山翠插天崔嵬。',16,'全唐诗/poet.song.59000.json','["長江雪浪過樊口，西山翠插天崔嵬。"]'),
('a48dcb6d-2d14-49ed-8bc3-73bd37ad823a','句','陸惟忠','宋','宋诗','song-poetry','','[]','投醪谷董羹鍋內，掘窖盤遊飯碗中。',16,'全唐诗/poet.song.59000.json','["投醪谷董羹鍋內，掘窖盤遊飯碗中。"]'),
('c54375e4-e9fd-426a-89e4-15f8db1944d5','贈賈仲武','劉弇','宋','宋诗','song-poetry','','[]','賈侯器宇何軒昂，下視齪齪真秕糠。',384,'全唐诗/poet.song.59000.json','["賈侯器宇何軒昂，下視齪齪真秕糠。", "眉分八字髭根黄，自許忠膽鐵石剛。", "彫弓一挽一石强，錦臂錯出虬青蒼。", "匣劍排射星斗光，壯心飛過祁連傍。", "架鷹朝按血染裳，鐵驄騎出轡鬧裝。", "健兒前呵檛列行，捷矢齊指雲中鶬。", "豈惟武力稱擅場，亦有文價騰焜煌。", "新詩字字古錦囊，清論灑落飛天潢。", "險韵千百敢獨當，管鋒落紙鏗琳琅。", "古文探討屋壁藏，史傳山岳遺毫芒。", "酒酣往往歌慨慷，連卷大白鯨吞航。", "自云疇昔富文章，家在冀北邊一方。", "天書屢膺貢州鄉，雲衢卜日橫騫翔。", "中間落泊志不償，武科拉取如截肪。", "况有豪氣十丈長，蟠蟄僅類絆驌驦。", "苦恨天驕久頡頏，撫臂便覺大袂攘。", "坐縻歲月耗囷倉，口厭醇釀飽肉粱。", "吾非斯人可相望，要且報國真不忘。", "我來自東甫春陽，邂逅紺宇同一觴。", "幅巾輕蓰追徜徉，促膝調笑初無妨。", "自知投分出泛常，豁如餒腹得糗粻。", "短長不復置形相，落去䁹睨决壅防。", "嵇生轉覺嗜鍛忙，高陽還因酒發狂。", "漫叟戲規祇攪腸，㗦嘈不減笛弄羌。"]'),
('c560e4a2-df5c-47bb-8ce0-0142aa64d808','元豐辛酉七月九夜大風四十韵','劉弇','宋','宋诗','song-poetry','','[]','海傍七月無好天，頑雲夜半爭糾纏。',384,'全唐诗/poet.song.59000.json','["海傍七月無好天，頑雲夜半爭糾纏。", "雷公轟車電操幟，如以墨汁當空湔。", "門闌刺眼不見地，逼塞四野可築拳。", "須臾霾風贔屭起，便覺怒竅呺喧闐。", "茫茫平地駕轣轆，礧石雜下麗譙顛。", "訓狐投隅狗走竇，拔木僵仆踵不旋。", "鏗轟時聞擲飄瓦，洶沸錯以池羹煎。", "藩垣卷去甚撤幙，屋壁如受衆挻挻。", "戞空飛礫正激射，况復急雨篩涌泉。", "初疑昆陽遁猛獸，又訝伏弩攢龐涓。", "黔頭豹褌健肘髀，剖拆囊袋椎鈐鍵。", "天吳助强馬啣舞，鼯鼬嘷嘯尸陰權。", "呼聲過於赴趙日，烈勢更甚焚崑前。", "酣奔劇驟砉未已，陣馬沓奏摩雙鞬。", "蚩尤殲師灑腥血，驅駕山岳揮秦鞭。", "海濤撞舂萬鼙震，岌嶪直恐三山騫。", "林椒宿鳥亂投墜，脅息豈間烏與鳶。", "蝦蟆何知妄嘈囋，似爲得意驚翩翾。", "流螢迸草戢光耀，啾蚓縮穴愁踆跧。", "泓窊往往走湍瀨，卧內直可浮長鱣。", "伊余竟夕不成寐，縱有短炬誰復然。", "屋如漏釜直下注，坐取滲漉攢兩肩。", "羸童叩鼻卧東壁，噤不譁駭如束氈。", "黎明下堂踏新淖，祗覺撫髀成憮然。"]'),
('bc8894b0-c579-4e4f-a9d6-930a96139194','同朱彥周遊元陽洞兼示文吳二羽人','劉弇','宋','宋诗','song-poetry','','[]','窮西三湘鄰，奔迫萬岑會。',288,'全唐诗/poet.song.59000.json','["窮西三湘鄰，奔迫萬岑會。", "盤拏崩騰根，疑此先草昧。", "不周遷大荒，勢落燭龍外。", "遠徵混沌鑿，晚怵大塊噫。", "平疏一注玉，寬削四隅黛。", "前崖岌初豪，傍竇戢如塊。", "暗蹊青鮎卧，側足得無殆。", "霜蕤擁凝液，衣綴倚空蓋。", "危呀傲天頑，九地一瘍潰。", "鬰然崷崒姿，似與石廊配。", "間聞赫幽光，吹作雷雨解。", "石鼓形似餘，擊考亦砰磕。", "陰陰隆冬戶，塞向真瑣碎。", "鴻濛挹氣母，茫昧超物怪。", "不應私開闢，曾是閱成壞。", "黄熊非鯀化，九肋蕃碩大。", "蹣跚舞陰機，無乃羞主宰。", "肉芝桂純白，仙物今故在。", "雲烟更斐亹，巧弄非一態。", "篔簹下蕭摵，往往到竽籟。", "片桃仙凡隔，愁絕止飛瀨。", "誰爲篝火遊，邈叩無底界。", "世傳元崇隠，茲事或虛採。", "驕陽五月竟，客子短轅邁。"]'),
('e3dab0c3-5c16-4df7-973a-4312125df75b','儀真呂明父席中觀新曲','劉弇','宋','宋诗','song-poetry','','[]','有客揚楚舲，歸歟汩吾事。',288,'全唐诗/poet.song.59000.json','["有客揚楚舲，歸歟汩吾事。", "波神慳東漲，吞遏限脩螮。", "轉頭彫歲陰，蓬行變匏繫。", "一逢金鑾人，穆我若清吹。", "挽置十尺床，淵襟掃苛細。", "壺封拆初黄，露液攢沸蟻。", "老實侑脧紫，枯螯嚼霜漬。", "坐有豪爽賓，譁譁睨雲驥。", "屯雲刮癡白，有如擁天篲。", "疏櫺炯蕭森，北固决遥眥。", "半酣大軸出，鯨窟咀甘飴。", "當中傾玄圃，琚瑀紛百綴。", "物愁殫眇情，神妬奪孤閟。", "快魂疏泠泠，大叱回熟寐。", "况復儀真曲，不減銅堤思。", "淒清激吳音，皓齒曾未愧。", "辛鹹皆可口，卷舌得真意。", "初如嚴冬逼，肅物有餘惴。", "末似陽春回，怳入衆骨醉。", "將壇凜先登，樂府仍一洗。", "呂侯斯人望，胸中弔古氣。", "二十佩青綸，三十清間侍。", "高纏見騰踏，茂渥擅褒賁。", "頃來笑畫脂，無補當身寄。"]'),
('972ff02f-2098-4f60-b7ed-49818eee8323','送方絢解元赴試南宮用桂林一枝荆山片玉爲韵八首  其一','劉弇','宋','宋诗','song-poetry','','[]','紛紛束書兒，穿穴蠹栖桂。',60,'全唐诗/poet.song.59000.json','["紛紛束書兒，穿穴蠹栖桂。", "及當千人軍，往往出下計。", "誰如冠軍豪，飄揚選鋒銳。", "刺手拔鯨牙，灑落見孤詣。", "更看抉重關，喜色動春袂。"]'),
('d575f48f-9207-48e6-8c5a-bb3dd5b0bbb1','送方絢解元赴試南宮用桂林一枝荆山片玉爲韵八首  其二','劉弇','宋','宋诗','song-poetry','','[]','人言蜀道難，歷井如捫參。',60,'全唐诗/poet.song.59000.json','["人言蜀道難，歷井如捫參。", "何如棘圍裏，對面橫霜鐔。", "聲價一日中，不數雙南金。", "秋風大情生，半入瀟灑襟。", "袖有百鍊骨，躍馬辭家林。"]'),
('b44f97a9-3ca4-4ce7-8db1-db53a1bcebe4','送方絢解元赴試南宮用桂林一枝荆山片玉爲韵八首  其三','劉弇','宋','宋诗','song-poetry','','[]','馬家白眉良，由來罕儔匹。',60,'全唐诗/poet.song.59000.json','["馬家白眉良，由來罕儔匹。", "誰諧虞帝音，貴在得夔一。", "顢頇康樂後，况有阿連出。", "春留棣萼好，影厠鴒原密。", "定是金華遊，羊邊起高叱。"]'),
('dacf914d-42c0-4b8b-b32a-e125a537f1fc','送方絢解元赴試南宮用桂林一枝荆山片玉爲韵八首  其四','劉弇','宋','宋诗','song-poetry','','[]','君王十二閑，一一登權奇。',60,'全唐诗/poet.song.59000.json','["君王十二閑，一一登權奇。", "飽之青玉芻，絡以黄金羈。", "南宮舊冀北，雜遝追風姿。", "驌驦固神物，豈病孫陽嗤。", "如聞有桂約，暗滿秋風枝。"]'),
('64930b3e-f624-43e7-9298-6ae1058f3d83','送方絢解元赴試南宮用桂林一枝荆山片玉爲韵八首  其五','劉弇','宋','宋诗','song-poetry','','[]','我來莆之陽，與子初班荆。',72,'全唐诗/poet.song.59000.json','["我來莆之陽，與子初班荆。", "巖巖太古鏡，中有不蝕明。", "青緗無留賞，理到刃必迎。", "雎盱腐儒後，數見胸膽橫。", "詩哦逼振綺，酒吸摧奔鯨。", "君看老雄變，冠距將而鳴。"]'),
('ee1e6542-87c4-4ee7-8b3b-c759a184b598','送方絢解元赴試南宮用桂林一枝荆山片玉爲韵八首  其六','劉弇','宋','宋诗','song-poetry','','[]','病夫亦何有，愧彼小酉山。',60,'全唐诗/poet.song.59000.json','["病夫亦何有，愧彼小酉山。", "頼君不佁儗，拔揵捫吾關。", "意豐報逾儉，叩迫出益慳。", "經郛榛萊翦，聖海波瀾閑。", "茲人不易得，坐使幽懷刪。"]'),
('ddbae7ef-9fd3-4adb-b324-33aad75a1d50','送方絢解元赴試南宮用桂林一枝荆山片玉爲韵八首  其七','劉弇','宋','宋诗','song-poetry','','[]','天王坐明堂，溫詔飛赤縣。',60,'全唐诗/poet.song.59000.json','["天王坐明堂，溫詔飛赤縣。", "家家魯儒生，羣星會頭弁。", "坐愁谷駒空，豈直罩魚擅。", "子行殊未央，去逐淮雲片。", "神鋒正吹毛，願看長鯨剸。"]'),
('77544029-1af4-4948-8416-26836caef999','送方絢解元赴試南宮用桂林一枝荆山片玉爲韵八首  其八','劉弇','宋','宋诗','song-poetry','','[]','女床固饒鳳，方流亦生玉。',60,'全唐诗/poet.song.59000.json','["女床固饒鳳，方流亦生玉。", "百年海邦莆，文雅殆成俗。", "之人卷鯨波，浩汗寄高躅。", "飜笑洴澼子，長年事皸瘃。", "唾手拾壯圖，未負春顛綠。"]'),
('be05a889-eee9-4109-967a-ec862d5ba64d','古風謝汪都講示惜惜吟','劉弇','宋','宋诗','song-poetry','','[]','番陽先生萬人敵，少來繙書始成癖。',320,'全唐诗/poet.song.59000.json','["番陽先生萬人敵，少來繙書始成癖。", "風前白眼望青天，笑捉短鬚吟惜惜。", "地祇關鐵掣臨賀，天家寶場正中劃。", "萬空扶坎覓坤苗，鑿盡頑陰冶清液。", "鍥磨鑱鑢歸高手，養水工夫價連璧。", "別斲圓虛費鈷鉧，粉白黛綠低真色。", "傳看代北青氍毹，一泓幾動春消息。", "無論丞相戒撲滿，先許司空熾然石。", "楚萍赫赤浪傳甘，秦缶模糊徒薦客。", "由來此秘似未睹，瑣瑣搔爬嗤美炙。", "先生早茂椿松姿，道韵仙風方日逼。", "胡麻青䭀飯調饑，夜榻抱弓跧七尺。", "粉闈聊當襥被遊，齎携不靳胡奴力。", "大鼾酣酣動蟄雷，霜飈澀盡銅壺滴。", "青螺仙女暮成炊，綠竹夫人寒卧壁。", "興來活筆卷天潢，南國小巫陰褫魄。", "悠悠萬物何親疏，新故終緣世情隔。", "夏裘秋箑竟誰負，寢廟偃溲轉身易。", "昨布東皇九十春，融冶一番浮綺席。", "莫學長檠換短檠，惜惜鴟夷兩拋擲。"]'),
('cf739034-2b1c-4470-a3ea-b1cb9567f2ca','癸酉歲暮壽春道中五首  其一','劉弇','宋','宋诗','song-poetry','','[]','有城有城半蕪沒，倔强當年開狡窟。',64,'全唐诗/poet.song.59000.json','["有城有城半蕪沒，倔强當年開狡窟。", "青韁白馬成底事，魏得其狗空凌突。", "清淮不洗饕利魄，石馬崔嵬化英物。", "據鞍浩歎爲踟躕，但有悲風起蓬勃。"]'),
('81a15d5a-4333-42b1-a353-386b60facc66','癸酉歲暮壽春道中五首  其二','劉弇','宋','宋诗','song-poetry','','[]','有鳥有鳥高飛鴻，哀鳴嗷嗷隻影東。',64,'全唐诗/poet.song.59000.json','["有鳥有鳥高飛鴻，哀鳴嗷嗷隻影東。", "枯聲策策霜後葉，狂態騷騷空際蓬。", "秋毫不礙掛天斗，一氣正在胚腪中。", "客邪中饑亂心曲，短裘垢襪催衰癃。"]'),
('7393b003-9d85-41ee-9f55-dc9c50561862','癸酉歲暮壽春道中五首  其三','劉弇','宋','宋诗','song-poetry','','[]','有渡有渡背北城，淩排駕淮吹暮聲。',64,'全唐诗/poet.song.59000.json','["有渡有渡背北城，淩排駕淮吹暮聲。", "郵程未央豈病涉，寄汝一檝推生平。", "古來豪士重感概，車下未乏宵衣征。", "出處任天幸無苦，有如此水吾其行。"]'),
('5bc0652c-2a14-4eef-8eef-c2e3ef292730','癸酉歲暮壽春道中五首  其四','劉弇','宋','宋诗','song-poetry','','[]','有叟有叟皤兩顛，杖藜道周傲天年。',64,'全唐诗/poet.song.59000.json','["有叟有叟皤兩顛，杖藜道周傲天年。", "懷顔發笑挽行子，胡乃憊爲忘舍旃。", "吾儕小人敢不勉，孔孟卷轍如趨然。", "男兒禿脛乃始已，非爾所知徒憮然。"]'),
('754be285-dacd-4ef3-b563-70789a435941','癸酉歲暮壽春道中五首  其五','劉弇','宋','宋诗','song-poetry','','[]','有客有客垢髮鬚，羹魁掛鞍無宿儲。',64,'全唐诗/poet.song.59000.json','["有客有客垢髮鬚，羹魁掛鞍無宿儲。", "翹心北闕比寒藿，它日南山拋舊廬。", "逆旅丈人真脆意，揖我下床邀踞罏。", "悠悠高門擊鮮子，萍匏殊根勿誚渠。"]'),
('4492b9c0-1841-481d-9d33-2768276e111d','建陽縣二首  其一','劉弇','宋','宋诗','song-poetry','','[]','東甌消沉故王日，俗號剽輕如故實。',64,'全唐诗/poet.song.59000.json','["東甌消沉故王日，俗號剽輕如故實。", "挾策不數應門兒，雅尚儒人鄒魯匹。", "頃來官長稍自安，市里頗聞浮訴窒。", "陳侯健者吾故人，坐致豈康得無術。"]'),
('b747027a-23b3-4021-adaf-080fb06b0787','建陽縣二首  其二','劉弇','宋','宋诗','song-poetry','','[]','紗民趁商市日高，紅女機杼仍分曹。',64,'全唐诗/poet.song.59000.json','["紗民趁商市日高，紅女機杼仍分曹。", "雙橋卧虹上下水，石脊瘦龍狂鬭牢。", "穡登爾場俗豐樂，匹馬北客方滔滔。", "轉將身掛利名網，擲此故歲如騰猱。"]'),
('094a0416-e16b-4155-af8b-546d7dca180e','贈相掌文廖生一首','劉弇','宋','宋诗','song-poetry','','[]','廖生術天與，如鑑掛高墀。',204,'全唐诗/poet.song.59000.json','["廖生術天與，如鑑掛高墀。", "能以禍福語，感動諸奔馳。", "至有不旋踵，坐獲百萬貲。", "推排鬼氣奪，擯斥海岳移。", "自云前十年，負術驤螺湄。", "鬧中出雙掌，得子如沙披。", "乃今十年後，所契了不疑。", "况有遠大語，未易論銖錙。", "曾聞物外償，不若君家詩。", "吾謂廖生曰，一詩何補爲。", "生云等詩爾，我則如渴饑。", "一詩固不惜，爲生試言之。", "天地有文理，俯仰自可推。", "有文在其掌，乃晉魯嬰兒。", "方其表異態，覽者初亦癡。", "生當千年後，把握論蓍龜。", "顧生勿輕許，角立非生誰。"]'),
('5607b290-9bd8-4904-8c2a-42784bcd962f','贈廖相手一首','劉弇','宋','宋诗','song-poetry','','[]','廖生得掌訣，初自龐眉緇。',288,'全唐诗/poet.song.59000.json','["廖生得掌訣，初自龐眉緇。", "束身事覘矕，羞爲不情兒。", "力持禍福語，傾動諸奔馳。", "所至餉自倍，如賈操贏奇。", "衡從辨侵射，側正分隆庳。", "天緘砉初閟，鬼覷慳幽披。", "環環太史氏，抱珥司渾儀。", "臺輿與侯王，初不論何誰。", "寫照阿堵中，唯生鼓頷頤。", "自云前十年，挾術驤螺湄。", "伸縮殆萬肘，較量但肥羸。", "最晚得子掌，决眥逾灼龜。", "九方揖孤駿，神睹歸心師。", "子姑詰奇中，曩言甯肆欺。", "今者非他須，子盍償吾詩。", "冀因拂衣還，松丸染高楣。", "我聞囿形質，至文從可推。", "懸象麗霄極，川岳羅坤維。", "逸獸別彪炳，激水生漣漪。", "上飾右繒綺，高甍紛楶栭。", "石鼓貴刻畫，汾鼎珍陸離。", "鑑靈不漫理，節煥饒豐蕤。", "器敝緣有舋，玉捐因見疵。", "况當筋骸束，前構了不疑。"]'),
('59c96a4d-247f-4198-a8c7-43068a7bb537','走筆答郭子隆勾稽','劉弇','宋','宋诗','song-poetry','','[]','春歸幾何時，綠樹陰已滿。',288,'全唐诗/poet.song.59000.json','["春歸幾何時，綠樹陰已滿。", "蕭條子雲巷，誰借吹噓暖。", "常日雙柴扉，深扃類休澣。", "稚燕掠翩翾，疏蟬弄淒斷。", "擷芳聊自娛，併食習成懶。", "嶷嶷棲鸞郎，蝸居間三款。", "兒童憚逢迎，應客事謾誕。", "謝絕高軒榮，祗增鼯鼠短。", "頼君不吾靳，尚復斗筲算。", "南薰破笑語，慇懃接誾侃。", "酸然梅雨天，煩襟斗湔浣。", "波瀾信苦孔，風力到微管。", "加有建安作，大軸舒憤懣。", "力關神臂弓，傳以青玉笴。", "自宜造英莖，豈直駢組纂。", "居然膚寸毫，搜刔入稀罕。", "諷疾頰渦飛，把持手爭盥。", "索然貧窶家，連挹茂陵碗。", "久矣吾衰頹，占數還鄙酇。", "長年苦中乾，更事筋駑緩。", "比雁自不材，方木宜登散。", "赫如千尺光，旁爍幽隘窾。", "處此得無猜，神觀迷町疃。", "誰如富青箱，利器未施䂎。"]'),
('92762c75-546f-4a40-a8bb-8335a195e6a3','送李侯朝散還任一首','劉弇','宋','宋诗','song-poetry','','["\u5e90\u5c71", "\u6d1e\u5ead\u6e56"]','西山閱今昔，章水弄清泚。',288,'全唐诗/poet.song.59000.json','["西山閱今昔，章水弄清泚。", "雲陴插天半，滕閣中隠起。", "青鴛千萬家，湖光豁如洗。", "鍾陵一都會，信亦非偶爾。", "君來無幾何，所得已倍蓰。", "笑談送白日，慷慨拾遐軌。", "成詩殆百篇，天籟落凡耳。", "秋摽拔孤峰，陰膽掉百鬼。", "顧我佁儗人，晚乃識君子。", "未漫禰生刺，先倒蔡公屣。", "清揚舞眉間，秀語屑瓊蘂。", "囊間錐立見，公今無乃是。", "柰何迫歸歟，笑把吳雲指。", "六月江南天，煩抱劇含滓。", "輕篙下鯢浪，畫槊搖翬尾。", "高懷傲匡廬，醉眼寬彭蠡。", "山長楚甸轉，駃席抉空紫。", "珠璣紛滿篋，銀鈎赫蹏紙。", "野蔌饒掇英，水豢足緍鯉。", "人生不知他，安與樂而已。", "行行勿滯淫，吳中古來美。", "一官雖翕翼，焉往不爲仕。", "洞庭五湖間，明月清可跐。", "鹽豉誇未下，蓴羹貴千里。"]'),
('68f93c03-75c9-4e87-8e43-0070504cdf1e','寄李彥弼端臣','劉弇','宋','宋诗','song-poetry','','[]','吾生本何爲，筆墨代耨耒。',288,'全唐诗/poet.song.59000.json','["吾生本何爲，筆墨代耨耒。", "拂衣辭雲林，偶與寸祿會。", "隨翔俗子後，如垢不時靧。", "幾欲臨紫虛，摽身飛鳥外。", "時哉不吾與，歲晚怵顛沛。", "炯炯平生心，誰與論梗槩。", "李侯西南秀，胸腹無留礙。", "表表起孤韵，迴飆寫蒼檜。", "筆挫三千英，壯甚敵王愾。", "高搴若木枝，直撫靈鰲戴。", "前年帝王州，晤語早傾蓋。", "欣逢妙年客，良愧晼晚態。", "謂我文字工，超起到前輩。", "去年清漳滸，經從不辭再。", "高談破三鼓，陰膽掉百怪。", "是時方窮冬，瑟縮寂萬籟。", "滕閣掛星斗，嵌根眇江带。", "慚非徐孺榻，僅飽吳兒鱠。", "忍爲鴟夷笑，恃有太白在。", "四騶馳頹年，遺跡掃茫昧。", "君今規壯圖，吾轅方未改。", "青原心欲折，合散幾烟靄。", "空懷簡書畏，未卜簪裾對。", "翻思謝客吟，拾月弄雲海。"]'),
('fbb39eb1-dea0-409d-8d34-c02144bd284d','石廊洞','劉弇','宋','宋诗','song-poetry','','[]','君不見仙家三十六洞天，西南大半盤蒼巔。',227,'全唐诗/poet.song.59000.json','["君不見仙家三十六洞天，西南大半盤蒼巔。", "此外元陽擅嶄絕，况有石廊人喜傳。", "碧蓮參差隅地湧，徙倚危梯飛螮蝀。", "陰陰洞戶半空開，一縷聯凹愁寄種。", "萬鈞崔嵬挂礧石，吁可怪兮若飛動。", "天然湫面尋丈間，寒掬初慳媼神捧。", "紫崖蒙茸瑶草秀，懸泉涓涓挹天酒。", "淑靈豈即乾坤私，窟宅宛是神仙舊。", "飛鳥點影陽光回，遊子履深驚殷雷。", "九夏三冬自回斡，雨暘寒燠爭喧豗。", "神物奄有似無謂，突兀古廟當巖隈。", "鼪鼯笑舞助怪變，落日愁絕松風哀。", "瞰臨一方殆天意，累露之疑此其是。", "仙乎仙乎胡不歸，忍使秋燐泣陰鬼。"]'),
('37ac25a0-b191-4b42-993b-9db5883c9226','同楊方士弭楫圓潭漩因賦詩即事','劉弇','宋','宋诗','song-poetry','','[]','媼神臂陰關，一水下辰卯。',240,'全唐诗/poet.song.59000.json','["媼神臂陰關，一水下辰卯。", "青玉走萬岑，收來不容稍。", "盪爲無涯津，谽谺究深窅。", "誰乎張嚵咽，吞嚼爭一飽。", "復疑刺秦魄，環柱怒方拗。", "直前孰長驅，橫騖孰侵鈔。", "或來浩無旁，或去削如剽。", "長年雷車轟，盡心轉蓬掃。", "舂容送日月，汩𣹜亂昏曉。", "老蛟非無須，一掬擅囷窌。", "鯿魴雜鰍鰕，嬉沫佐陰傲。", "翩彼晉高真，羽駕殄遺狡。", "直下錮三泉，所補决非小。", "今無垂涎憂，過者色猶愀。", "蒼波耆舊空，斷石風烟老。", "琳宮跨崚嶒，像設儼緗縹。", "爾來南北帆，坐閱幾飛鳥。", "我作六月游，未覺煩暑到。", "撫舊感徂遷，商功愧論報。", "方寸洗濯心，得君此同調。"]'),
('20cc622e-5bfd-43e6-9ee6-119316e4fc63','次韵和毛正仲胡潜畫鶴歌','劉弇','宋','宋诗','song-poetry','','[]','青田有仙物，脫略衆凡外。',200,'全唐诗/poet.song.59000.json','["青田有仙物，脫略衆凡外。", "駕彼輕舉人，邈與五雲會。", "一朝羽羣空，誰識真意態。", "有客筆氣捎雲莊，寫以全體翩低昂。", "月棲宛是隻清影，露警似許聲圓吭。", "舊傳蟬雀傅輕箑，末技枉奏真孱凉。", "非如楚綃削秋水，迹未拔陸心先翔。", "叔寶踞瘦骨，巢父洗塵戀。", "屋壁擅新誇，巾縢揜餘玩。", "展疑洞天逼，緘恐神物怨。", "因舞成賦良未真，緣相作經那足神。", "萬黄金輕寸毫重，劍術豈啻移裴旻。", "薛公鶴手高唐世，其人已逐東波逝。", "儻得胡生肖似歸，古人未必今人非。"]'),
('ea6a284e-42de-4dda-b97e-cf6b2219e00d','李宰新成假山','劉弇','宋','宋诗','song-poetry','','[]','夫子絕俗姿，趣尚豁雲海。',216,'全唐诗/poet.song.59000.json','["夫子絕俗姿，趣尚豁雲海。", "花移洛下品，池割天潢派。", "中間疊嵯峨，石手紛磊磊。", "功侔一簣始，正爾臨爽塏。", "羅浮窮南勢，迎目出巧怪。", "洗昏新罅發，秘匿若有待。", "騫騰天吳揖，聳削虬尾擺。", "當頭七八峰，縹緲散青靄。", "直下三四溪，何年取東匯。", "洞指白鹿迷，路認桃源改。", "時時攻冥煩，瀟灑遞天籟。", "得非緣夜半，提挈有真宰。", "俗物卑培塿，高標想衡岱。", "我家香罏傍，登躡素心在。", "一從羈官綴，未省識𡾋嵬。", "俯窺攙雲骨，逸興幾十倍。", "無爲議真假，自可蠲塵浼。", "何日升君堂，把酒取一快。"]'),
('877071f8-1c63-4601-bf9f-95406bf4c54a','遊浮洲寺寒林亭','劉弇','宋','宋诗','song-poetry','','[]','吳牛喘月齒髮頹，晚陰閣雨雜殷雷。',194,'全唐诗/poet.song.59000.json','["吳牛喘月齒髮頹，晚陰閣雨雜殷雷。", "一番重釀熨人暑，徑欲濯澗捫崔嵬。", "潭潭招提此亭在，鷗鷺慣客無驚猜。", "番君故國號瀟灑，巨浸沃日西南來。", "別爲瀰茫浩汗之沼沚，中有晶熒照耀金碧之樓臺。", "錢塘未應邈，北顧真悠哉。", "飲牛之津斡星渚，一色藍英玉奩貯。", "連岡十里卧晴虹，近竹遠松如抹堵。", "就追神觀所得多，清風爲我生曾波。", "有生弔暑乃天性，獨快疏櫺亦吾病。", "無論承露盤，未議清凉境。", "安得大地變廣寒，相與一世振絺屏箑纓頭冠。"]'),
('714d46cb-7277-4d26-9970-7cbadcef6c86','黄魚鮓寄狄復之因佐以詩','劉弇','宋','宋诗','song-poetry','','[]','魚有健且脩，供庖厥名鱣。',240,'全唐诗/poet.song.59000.json','["魚有健且脩，供庖厥名鱣。", "紛紛水豢中，嗜者貪肥鮮。", "頷根束短喙，鮎皮突鱏肩。", "十月天風高，三櫺潦聲乾。", "修蛇列長罛，獵獵排曉湍。", "魚師頓艤䑰，柔鬐掛鈎竿。", "小固不足數，大或斤盈千。", "丹膚染霜鍔，疏鱗脫連錢。", "吳儂喜健噉，日取充羞盤。", "我食幸有餘，鮓法得新傳。", "薑芹間紅糝，漬以春醅瀾。", "置暖恐後熟，羃塵防弗蠲。", "興來發新坩，正喜供饞咽。", "瓊蕤附骨脆，黄臘豐脂團。", "麋臡信非工，豈復數蚳蝝。", "醢馬試何事，屠虹祇誇謾。", "福州甖如斗，密覆恨不寬。", "勤勤寄我友，持以敵琅玕。", "君識茂先比，舉臠知所然。", "此味勝他味，勿作等閒看。"]'),
('0408ddb9-9f21-4558-8859-3192d796286a','石港高侯見遺雛鶴輒成十五韵','劉弇','宋','宋诗','song-poetry','','[]','我生好鶴乃天性，得自高侯非所祈。',240,'全唐诗/poet.song.59000.json','["我生好鶴乃天性，得自高侯非所祈。", "啄插錐芒初穎脫，頂埋丹顆未依稀。", "親携竊笑髠籠返，細看恐先喬舄飛。", "三島夢魂迷曉色，九秋舞影怯霜威。", "長哦自異晨烏啅，瘦骨全勝野雀肥。", "無跡可尋華表舊，有程應想洞天歸。", "精神瀟灑元非俗，飲喙安閒似見幾。", "載以畫船休觖望，浴之野水好生輝。", "漢宮舊拂仙入掌，遼海今看羽客衣。", "勿爲稻粱生健羨，第令鷄鶩許投依。", "鳴皋不隔高騫志，截脛初忘過分譏。", "夜砌行聞清露警，午窗終伴醉棋圍。", "右軍鵝謾誇真賞，海客鷗空駭暗機。", "烟月此生真不負，蓬茅他日肯相違。", "片心便擬成高謝，騎去揚州弄晚暉。"]'),
('3f4502a2-5bbb-4d8b-8dbb-ee38c3cb877f','送李令如堤上部夫','劉弇','宋','宋诗','song-poetry','','[]','東風日作催花計，減去年來大半春。',248,'全唐诗/poet.song.59000.json','["東風日作催花計，減去年來大半春。", "未省春歸向何許，真成等閒愁殺人。", "我欲揖君空酒樽，君刺野航朝涉津。", "翩然揮手謝春去，我欲留之良苦辛。", "沙堤漫漫失故處，下有清海濤頭奔。", "濤頭奔，可奈何，江淮由來水事多。", "田家遣丁纔取具，吳歈行勸不煩訶。", "蝸牛小廬亂雲鍤，梓土把草夷陂阤。", "我聞神禹乂九土，息壤能蟄千丈波。", "獨坐敗堤去民吏，翻笑王尊禦濁河。", "李侯方精强，程督宜有科。", "民事不可緩，田疇久滂沱。", "嗷嗷老將稚，意在却蛟鼉。", "無爲坐歎息，勞事非蹉跎。", "山膚雜水豢，强飯時吟哦。", "暮歸泊煩促，不厭玉顔酡。", "他時解看官門北，千里長虹卧軟莎。"]'),
('ea062be1-042f-48fe-9782-97174fc19f5b','憶昨','劉弇','宋','宋诗','song-poetry','','[]','憶昨年甫壯，弄翰白玉京。',252,'全唐诗/poet.song.59000.json','["憶昨年甫壯，弄翰白玉京。", "自許稍不凡，笑談揖公卿。", "蟾蠩貯書滴，彩筆當桉橫。", "束琴推隻彈，後出笑商聲。", "搴芝得孤秀，濯繭抽繁縈。", "時時騎箕尾，儓儗諸儒生。", "斷經謹誰何，森羅護千兵。", "白袷照青春，綠鬢彯華纓。", "步兵卒獨駕，禰衡有虛名。", "寫懷紫菌閣，指日邁西清。", "短翮無逸飛，顧與俚俗并。", "七年甫一第，脫籍纔白丁。", "簿書聊牽强，短褐戒徂征。", "十月揚瀾浦，千里海陵城。", "風濤寸心逼，節物兩毛驚。", "茂陵饒渴肺，臨淄少宦情。", "掣肘亦奚補，隨翔終少成。", "有如蛄䗐蟲，蠹米取腹盈。", "丹經徒虛語，欲仙骨不輕。", "頹年負壯圖，白日阻丹誠。", "鄧禹解笑人，斯言良未平。"]'),
('d65d1818-c097-418d-8646-1c7e687cabb1','人日','劉弇','宋','宋诗','song-poetry','','[]','去年人日螺江邊，今年人日在通川。',192,'全唐诗/poet.song.59000.json','["去年人日螺江邊，今年人日在通川。", "故家浩蕩五千里，客子騷屑心茫然。", "霜蘆盡解故時葉，生意斗爾歸蘭荃。", "海風如刀冰塞渡，欲航野水雪暗天。", "它鄉信美非吾土，香草悅魂真浪傳。", "南冠故聲祇操楚，劉章雅志惟歌田。", "五秉如單費廩粟，一囊就盡持餐錢。", "顛毛冉冉不吾與，齒根浮動輕於翾。", "小雀誰言畏死鷂，未肯屈折同桮棬。", "章貢直西三徑在，爾來望眼欲成穿。", "科桑洗竹真吾事，孰使齪齪纔充員。", "何時解得無拘束，歸釣潭頭楓葉鯿。"]'),
('943f5215-854f-4aa3-bd0d-b971ebb8af18','同李端臣遊薦福寺禪院','劉弇','宋','宋诗','song-poetry','','[]','相期采真游，驟得青蓮界。',144,'全唐诗/poet.song.59000.json','["相期采真游，驟得青蓮界。", "戴公舊棲隠，締構化祇裓。", "古老張祖乘，參兒走巾瓶。", "百年沸魚鼓，牡□聯青冥。", "白門三面水，天末蘋風起。", "衣重褰濕雲，苔幽凉屐齒。", "南來雙舂鋤，乾雪點晴湖。", "憐渠足閑淡，怳欲與之俱。", "蟹眼課谷汲，分餉雲腴泣。", "落日轉金繩，林暝歸鳥急。", "束身事幽討，稅駕苦不早。", "及茲一囅然，微君孰顛倒。"]'),
('512b87ca-ca5f-46f3-a154-e868996f3d39','敘舊贈董承君','劉弇','宋','宋诗','song-poetry','','[]','搖搖不根舟，瀰漫隨所適。',291,'全唐诗/poet.song.59000.json','["搖搖不根舟，瀰漫隨所適。", "朝辭呂梁險，暮駭瞿塘迫。", "長波送日月，漭與雲海隔。", "晚從天末歸，良愧故人識。", "夫子吾土傑，久任詞翰責。", "刺手翻天漿，灑作弔古墨。", "班班出素藴，想見豹姿澤。", "憶昨長淮壖，半面欣相得。", "君時天涯官，我亦西風客。", "薰弦破愁顔，爽抱洗連璧。", "吳岑刻玉瘦，吟對挹佳色。", "頹年瞥眼過，十見溪草碧。", "鍾陵旅學子，官况秋蟬翼。", "彯撇愧西崦，弔影心惻惻。", "{鬼夔}魖競揶揄，甚者得鴟嚇。", "由來次公狂，僅免陳遵謫。", "敢意今者見，依然得江國。", "鄉情比重裘，暖氣回肘腋。", "南閭與東阡，間躡車馬迹。", "古人重交契，遠有千里憶。", "連牆彼何人，老死不相覿。", "張陳汩勢利，光初竟何益。", "青原秀撞天，螺水藍膏擘。", "襟期方未央，更約浮我白。"]'),
('ecbecc55-9a23-4b66-a7f0-4dea11cb29e6','送邢清臣赴左選','劉弇','宋','宋诗','song-poetry','','[]','泊舟梅林浦，解纜墨潭灣。',96,'全唐诗/poet.song.59000.json','["泊舟梅林浦，解纜墨潭灣。", "層波日日生，雙槳那得閒。", "龐眉青翰客，相與春風還。", "江梅吹欲盡，江柳未勝攀。", "無以持贈君，對君成强顔。", "官况斬新好，晚步非間關。", "直北清夢多，半落夷門山。", "慇懃尺素語，毋爲魚鴻慳。"]'),
('ca6729a9-51b1-4e4f-8756-0a44328da0eb','送真藏主赴泐潭乾老會中','劉弇','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','昔別大仰巔，今逢章江濱。',216,'全唐诗/poet.song.59000.json','["昔別大仰巔，今逢章江濱。", "浮雲限南北，歲月一欠伸。", "上人邦閭秀，落髮早辭親。", "滄浪浴日月，初不點垢氛。", "問師頃何事，學佛苦賓賓。", "納踵不輟屨，無乃大勞神。", "自云吾西兒，腹寶殊不貧。", "是身難再得，所惜劇飈輪。", "十年躋楚嶠，六見匡山春。", "總祐遷秀晉，誰疏復誰親。", "束身從之遊，驪頷一一捫。", "如疲得熟歇，似笑回孤嗔。", "近聞邑別境，寶峰插高旻。", "中有拔俗老，疑馬駒後身。", "餐風了不制，癢興如爬皴。", "鬧綠稍暗地，梅雨吹南雲。", "輕於凉風翮，笠首携筇孫。", "男兒貴决裂，勉哉行問津。"]'),
('f12a58e5-7dcb-4656-aab9-b9b560cf88cb','贈前住瑞竹寔禪師','劉弇','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','清矑上人四十餘，二十爰祝髮與鬚。',304,'全唐诗/poet.song.59000.json','["清矑上人四十餘，二十爰祝髮與鬚。", "惟桑與梓舊螺水，四維陁典卧起俱。", "陽岐有嫡嗣曰勇，得法殆亦西佛如。", "昂昂出世建業寺，譬土囊口納衆噓。", "金耏子有吼物志，卷鉢攝筇重趼趨。", "玄契妙悟似不偶，得未曾有才斯須。", "生平學解一朝盡，貳負臣忽脫帝拘。", "無端梅柳漏春信，成蹊桃李言略無。", "頃拋瑞竹依章滸，埋照接衽最下徒。", "楮衾菅蓆聊卒歲，末俗未覺誰龍豬。", "蒼岑白澗謝人境，南若楚岳旁匡廬。", "斜幅繞脛湊初學，蟬聯大剎知幾區。", "又其甚者控闤闠，金碧爛日傾國都。", "如師不使正法席，笑衆釋子何朱愚。", "玉虎蟄音久不吐，是使一世狻猊虛。", "陋禪趁塊揜孤唱，何啻雞蹠隄江湖。", "瀘川南子素狂直，爲不平者有矣夫。", "雖師理自無固必，欲得垂手可後乎。", "由來世事多反覆，使我北望長嗟吁。"]'),
('cb9678c8-6865-4d31-b9a0-ab6e34cd157b','丫頭巖','劉弇','宋','宋诗','song-poetry','','[]','弋陽之東當古道，有石突兀號丫頭。',179,'全唐诗/poet.song.59000.json','["弋陽之東當古道，有石突兀號丫頭。", "苔侵蘚剝風雨蝕，骨幹聳削如鑱鎪。", "不知何冤上訴帝，叫閽之勢難稽留。", "草木焦禿僅比髮，獨瞰平皋疑秀發。", "淺深丹頰耀晴霞，彷彿瓊梳掠初月。", "行人躊躇眸子眩，癡女垂羊亦何別。", "惜哉僞態苦冒真，土俗傳誇疑有神。", "陰崖黝黑崩脅腹，石眼六七流嵌根。", "君不見望夫嶄嶄亦頑石，似不徒然肖真魄。", "顢頇廟食爾何補，登進雞豚始乘隙。", "安得擲置八荒外，化作膏腴豐稼穡。"]'),
('bb9ffd8a-6e6a-40ba-ae34-488aef50e69f','車盤嶺','劉弇','宋','宋诗','song-poetry','','[]','去年踏雪車盤去，今年執熱車盤來。',160,'全唐诗/poet.song.59000.json','["去年踏雪車盤去，今年執熱車盤來。", "去年險澀自其分，車盤於我何有哉。", "道傍飛礫如積糝，幽蔓緣崖不盈攬。", "懸知到此客脛酸，愁絕雲舒與烟慘。", "半山棲匭擎華藏，旋覺陰機萬鈞壯。", "鐘梵時聞一兩聲，妙界還疑落天上。", "短褐頭陀揖我言，此途詰曲知何年。", "名情利態過萬計，未聞厭者仍紛然。", "造物驅人不留瞬，車盤有盡人無盡。", "勸君莫歌行路難，令人未老華雙鬢。"]'),
('d4db3bdd-a29f-44bb-a30f-f3ecbc3235ff','過紫溪驛讀黄安中中丞留題','劉弇','宋','宋诗','song-poetry','','[]','金鑾天仙才，滲漉膚寸管。',156,'全唐诗/poet.song.59000.json','["金鑾天仙才，滲漉膚寸管。", "由來風騷將，要出江謝遠。", "一生忠孝心，倫匹世所罕。", "曩聞奉安輿，駕言得茲館。", "喜先行輈動，榮入綵衣暖。", "他年逝波痛，故國松楸眼。", "春暉草心盡，日力烏哺短。", "銀鈎壁間字，刺落歸粉板。", "捉衿來孰復，如渴釂斝琖。", "顧我幺麽姿，辱公披沙揀。", "波瀾泝沿闊，藻火止覘矕。", "公今青雲上，功業壯圖滿。", "此詩落人間，鼎味纔一臠。"]'),
('b3770c85-968f-4302-a576-8a2b22ad90d3','宿孫彥傃舍居','劉弇','宋','宋诗','song-poetry','','[]','先生綠髮隠，爲己得能多。',108,'全唐诗/poet.song.59000.json','["先生綠髮隠，爲己得能多。", "瘠田止三稜，藷蔗紛陽坡。", "自言世情确，冰火相戛磨。", "刺身一不售，瞥去扃隨和。", "爾來人累輕，但起歸歟歌。", "青冥遥鴻賓，紛紛空雀羅。", "我來卧松檐，斗酒客顔酡。", "揮手勢利徒，寄之相諧呵。", "黎明又南首，其如梁鴻何。"]'),
('067486ed-f818-496e-9729-63fc1d42f360','宿法藏禪院二首  其一','劉弇','宋','宋诗','song-poetry','','[]','斜河左界懸朱提，冷燼掠天螢糝飛。',96,'全唐诗/poet.song.59000.json','["斜河左界懸朱提，冷燼掠天螢糝飛。", "高梧泣液凉參差，前村後村烏夜啼。", "雕甍綉栱絕坤維，知自在世張禪扉。", "有睆釋子龐兩眉，清梵一聲捎翠微。", "亂我心曲天之涯，寂歷故感迎新悲。", "歸歟誰是真忘機，獨鹿水深愁濁泥。"]'),
('949f3146-d609-4c70-8230-08a08457b3c2','宿法藏禪院二首  其二','劉弇','宋','宋诗','song-poetry','','[]','白汗泣珠霍如洗，桔槹聲噤松風死。',80,'全唐诗/poet.song.59000.json','["白汗泣珠霍如洗，桔槹聲噤松風死。", "班如匹馬客戾止，化人之宮矗天起。", "錯寞形骸寬一寄，天涯特地悲身世。", "齟齬由來真博齒，白頭區區忘男子。", "跋狼之胡疐狼尾，世路傷哉澀如砥。"]'),
('f446eab9-52c4-454a-803b-43a047f73995','清思','劉弇','宋','宋诗','song-poetry','','[]','羲和日車說其輻，白雨洗天泊煩促。',84,'全唐诗/poet.song.59000.json','["羲和日車說其輻，白雨洗天泊煩促。", "綠蒲紫荇媚回塘，搖搖瘦青環橚矗。", "景長臺榭翳復明，百尺虹腰粘浄淥。", "神觀翛然物外歸，一簪斑籜動凉颸。", "天上廣寒之宮不足羨，人間縹清百斛真吾師。"]'),
('0cd89c01-8604-46bd-a107-a75a9c156b80','憶黄天倪','劉弇','宋','宋诗','song-poetry','','[]','游絲罥空生別愁，我車欲駕羌無輈。',96,'全唐诗/poet.song.59000.json','["游絲罥空生別愁，我車欲駕羌無輈。", "驚風吹花濺紅雨，白日西注僚丸投。", "青春九十行過半，天脚空隨江水流。", "思君度日倚高閣，時把長懷寄寥廓。", "古人不願身後名，但願即時一杯樂。", "安得此身生羽翰，高鶱便似追飛鶴。"]'),
('3a0d6f73-6bd7-4442-9587-961f8e558d45','村南','劉弇','宋','宋诗','song-poetry','','[]','村南行吟踏新場，馬乘款段壺懸漿。',64,'全唐诗/poet.song.59000.json','["村南行吟踏新場，馬乘款段壺懸漿。", "稼如濃雲穟含黄，柿葉亞枝收趁霜。", "臘團鷄髀盤餚香，簫鼓下神巫正狂。", "呼兒往問當壚娘，清美何如顧建康。"]'),
('b23f502b-5bd2-45bc-8ad0-90f96b2c0da5','安成道中作六首  其一','劉弇','宋','宋诗','song-poetry','','[]','故家楚尾鄰三湘，粗有晴地麻與桑，利機未判身輕嘗。',40,'全唐诗/poet.song.59000.json','["故家楚尾鄰三湘，粗有晴地麻與桑，利機未判身輕嘗。", "生涯寄將一葉上，歸釣赬尾秋滄浪。"]'),
('4d14428c-040d-4e1f-81a9-6d9c5782b852','安成道中作六首  其二','劉弇','宋','宋诗','song-poetry','','[]','翠篠娟娟棲暗芳，半隠半見誰門牆，分曹戲兒嶷雁行。',40,'全唐诗/poet.song.59000.json','["翠篠娟娟棲暗芳，半隠半見誰門牆，分曹戲兒嶷雁行。", "今我垂垂老境逼，竹馬鳩車憐汝狂。"]'),
('a214220c-6d99-4050-aa8b-b030bb23cd13','安成道中作六首  其三','劉弇','宋','宋诗','song-poetry','','[]','波面擲鱗銀作刀，波裏陟釐紛暗□，清秋駛艑吳兒操。',40,'全唐诗/poet.song.59000.json','["波面擲鱗銀作刀，波裏陟釐紛暗□，清秋駛艑吳兒操。", "會待長風十萬里，躍入雲海翻驚濤。"]'),
('d66a631f-d3fd-41bf-8fe5-63494828d1f7','安成道中作六首  其四','劉弇','宋','宋诗','song-poetry','','[]','愚智紛紛同一朽，翦斷愁根莫如酒，誰是瓢齎不離手。',40,'全唐诗/poet.song.59000.json','["愚智紛紛同一朽，翦斷愁根莫如酒，誰是瓢齎不離手。", "但令秋秫登我場，不應它日羞牛後。"]'),
('33695cb5-2acd-4db8-9f72-5e48c60bba7f','安成道中作六首  其五','劉弇','宋','宋诗','song-poetry','','[]','新里當南義櫪北，一水中飛抹山帛，吳歈楚俚愁狂客。',40,'全唐诗/poet.song.59000.json','["新里當南義櫪北，一水中飛抹山帛，吳歈楚俚愁狂客。", "十年仍作𡾰嵼遊，羞拾靈蓍問通塞。"]'),
('b74d5108-38a4-41f4-94d3-f6de6e6d43b4','安成道中作六首  其六','劉弇','宋','宋诗','song-poetry','','[]','酸然軟雨吹空濛，忽掛萬丈橫霄虹，陰晴回互倏翕中。',40,'全唐诗/poet.song.59000.json','["酸然軟雨吹空濛，忽掛萬丈橫霄虹，陰晴回互倏翕中。", "由來天意不可測，惜哉庶物終鞠窮。"]'),
('2d2d13c4-ab6f-4d64-8caa-2f761670dbdb','夜歎','劉弇','宋','宋诗','song-poetry','','[]','丹鳥白鳥爭吞吐，還雲去雲無定度。',104,'全唐诗/poet.song.59000.json','["丹鳥白鳥爭吞吐，還雲去雲無定度。", "不無夏簟工熨體，况有秋螿競扶戶。", "一嘅三歎詎如許，客思紛紛野烟縷。", "宵明景晏掛斜河，叢萱苒蒻團清露。", "有美一人在西方，白玉珮環珠兩璫，明眸皓齒艷朝陽。", "企予望汝涕泗滂，安得捉汝羅衣裳。"]'),
('8d00330b-d072-4879-8a1f-ecdb51b2e814','送曾該','劉弇','宋','宋诗','song-poetry','','[]','紛紛夸毗子，什伯羅秦缶。',72,'全唐诗/poet.song.59000.json','["紛紛夸毗子，什伯羅秦缶。", "擊考非無聲，顧出俗物後。", "曾侯西昌來，穎拔殆天就。", "等閒發秀語，颯灑如振垢。", "渠黄爲世生，駿骨謝前朽。", "整頓萬里足，往矣擅天廄。"]'),
('e31089c1-4d3e-4cbb-88b0-5cab04f81d2a','畏日三首  其一','劉弇','宋','宋诗','song-poetry','','[]','畏日杲杲天東隅，盤餐逆旅進山膚。',64,'全唐诗/poet.song.59000.json','["畏日杲杲天東隅，盤餐逆旅進山膚。", "岑崟遠岫不知數，磊落近松如有須。", "旅人瑣瑣信物役，逝者滔滔皆利徒。", "目送長雲藉平隰，赤驥正愁青玉芻。"]'),
('f04ebdea-5ec4-4deb-82c6-0dc8ca9b25c5','畏日三首  其二','劉弇','宋','宋诗','song-poetry','','[]','畏日赫赫天南隅，漫漫白道盤鬰紆。',64,'全唐诗/poet.song.59000.json','["畏日赫赫天南隅，漫漫白道盤鬰紆。", "過蛇搖毒宿莽死，陰崖發赭懸泉枯。", "沉迷未省招楚些，激越可是歌吳趨。", "目送長雲指萋蒨，轍鮒愁絕西江濡。"]'),
('ebb06720-40b4-4d3b-8533-ff6b50f8ac44','畏日三首  其三','劉弇','宋','宋诗','song-poetry','','[]','畏日燥燥天西隅，半規銜山我僕痡。',64,'全唐诗/poet.song.59000.json','["畏日燥燥天西隅，半規銜山我僕痡。", "招提訪尋數里近，牛羊斷續前村孤。", "揚塵動滿垢膩爪，好風不借清凉軀。", "目送長雲下碕礒，鷔𩾐愁對陂陰鳬。"]'),
('98252a21-7e1a-4252-bef8-ea88c7bff884','杉溪驛','劉弇','宋','宋诗','song-poetry','','[]','竹巖杉溪道路長，道邊古驛開蒼茫。',64,'全唐诗/poet.song.59000.json','["竹巖杉溪道路長，道邊古驛開蒼茫。", "分流溪水薄枉渚，挨石人家環上方。", "王程星火懼將恐，霜冬草樹芸其黄。", "去來今昔幾男子，姓字喧傳兩女郎。"]'),
('dd72912d-7689-498d-9413-e2be56f7e0f0','送席延昌奉議','劉弇','宋','宋诗','song-poetry','','[]','章水如有情，爲君生層波。',48,'全唐诗/poet.song.59000.json','["章水如有情，爲君生層波。", "匡南萬岑玉，遥知清興多。", "四年一官去，擲此歲月梭。", "恨無青田核，遣君韶顔酡。"]'),
('52185b9d-c821-4e70-8b02-1c81a5379ec2','贈法雲守光上人','劉弇','宋','宋诗','song-poetry','','[]','日邊開神皋，古剎面青嶂。',216,'全唐诗/poet.song.59000.json','["日邊開神皋，古剎面青嶂。", "寂寥千年後，凜凜發孤壯。", "上人薝蔔英，絕軔超性相。", "獨鶴嶷瘦姿，層冰爛清尚。", "雲游始丁年，自副乃盂杖。", "鞭羊去智害，盡堊契郢匠。", "喉呀般若音，浩汗卷溟漲。", "衢尊灑法味，如取赤子餉。", "九夏天無雲，暑風濁於釀。", "汩吾眇西征，揮汗迷背項。", "耽耽清凉境，一榻岌相向。", "屨滿寧嫌猜，目擊自張王。", "禪場推選鋒，宛是喑嗚將。", "洗我苦空語，盡决濛羃盎。", "兜羅辭銛棘，何有挂諸妄。", "露地非端倪，灑灑白牛放。", "惜哉功名誤，未爾寄物當。", "它日虎溪傍，還期杖藜訪。"]'),
('0f2775a7-f180-49d1-b8b4-17e4e680fb5f','黄洴','劉弇','宋','宋诗','song-poetry','','[]','不出東城隅三月，今者忽作黄併遊。',160,'全唐诗/poet.song.59000.json','["不出東城隅三月，今者忽作黄併遊。", "渾渾大江刮海窟，黄併一水學潮頭。", "潮去潮來朝復暮，蕭索千里空滄洲。", "沙咿土唧亂人眼，分曹豈啻魚蝦稠。", "蠹粉飄霜縈折木，著水凍雲銀簏簌。", "老漁釣蟺踏新澱，嫠婦績草當空屋。", "總轡愁聞路人語，新年已非故年熟。", "故年麰麥破分收，新年未省飽饘粥。", "保丁催科不貸人，行且稅桑賣黄犢。", "向秋但無惡風濤，舍北相將拾穜稑。"]'),
('92f65aa9-f9c9-4ee4-8596-ead3db9312b3','北禪水閣走筆','劉弇','宋','宋诗','song-poetry','','[]','西風凉客衣，弭檝滄江潯。',108,'全唐诗/poet.song.59000.json','["西風凉客衣，弭檝滄江潯。", "晚吾事瀟灑，聊復此登臨。", "雲容不礙秋，清樾有餘陰。", "煩心洗東波，寸目明遥岑。", "樊籠脫鳥窘，搖落弔蛩吟。", "莽墟閱今昔，長慨撫孤鐔。", "故楚冠劍盡，物情幾浮沉。", "懷哉歲將月，無爲空滯淫。", "持語朱陵翁，須矣吾抽簪。"]'),
('75514336-f192-4eb6-bfcd-59444c74134c','感寓二十首  其一','劉弇','宋','宋诗','song-poetry','','[]','歲月忽其除，颯焉悲凜秋。',72,'全唐诗/poet.song.59000.json','["歲月忽其除，颯焉悲凜秋。", "商飆號晨林，脫葉舞梧楸。", "鳥邊下白道，木末揚寒流。", "閨人促幽杼，客子悵遠游。", "雲闊眇天半，俯景獨遲留。", "陰霾掃不得，千古空滄洲。"]'),
('73e4e749-789d-40f4-940b-6600b9c197be','感寓二十首  其二','劉弇','宋','宋诗','song-poetry','','[]','西方有佳人，弱齡三春蘭。',84,'全唐诗/poet.song.59000.json','["西方有佳人，弱齡三春蘭。", "一顧迷下蔡，再笑傾邯鄲。", "青樓十二曲，密睟勝廣寒。", "寸玉耿孤抱，時時寄哀彈。", "孟娵久不作，宿瘤騁朱丹。", "世道終如此，美惡隨所觀。", "吞聲勿復道，留與蹇修看。"]'),
('13c47014-b6b3-486a-8bea-bcbba0b94571','感寓二十首  其三','劉弇','宋','宋诗','song-poetry','','[]','日月跳雙丸，陰陽馳四騶。',84,'全唐诗/poet.song.59000.json','["日月跳雙丸，陰陽馳四騶。", "海水復清淺，萬古信悠悠。", "咄哉世俗子，真如貉一丘。", "三楚冠劍盡，空看逝波流。", "悲來俯長劍，沾臆淚不收。", "何事馬蹄間，非夫良足羞。", "終恐鄧禹笑，三十未封侯。"]'),
('c7f8d8df-82f4-46d7-aed5-3b87e436c74b','感寓二十首  其四','劉弇','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','廬山何崔嵬，直上九千尺。',120,'全唐诗/poet.song.59000.json','["廬山何崔嵬，直上九千尺。", "藤蘿翳蒼茫，猿鳥閱今昔。", "䆗窱飛甍開，了與塵垢隔。", "三十六騰虬，瓊扉挂空跡。", "中有墨漬翁，不飲亦不食。", "文鰩爲之使，侍衛羅白額。", "遺我一卷書，生平所不識。", "小兒其無忽，持以永朝夕。", "湔掌受翁賜，怳若吸月液。", "吾將稅椒丘，帔霓揮八極。"]'),
('87eb20f2-5b0d-4075-ae10-0c35468024a8','感寓二十首  其五','劉弇','宋','宋诗','song-poetry','','[]','㛹娟誰家子，粲粲生輝光。',72,'全唐诗/poet.song.59000.json','["㛹娟誰家子，粲粲生輝光。", "弄姿俯春蘭，臨風振微芳。", "秋水揚清矑，白玉雙明璫。", "問渠家何許，笑指南山陽。", "去去不輟軌，怳若游雲翔。", "遥看入縹緲，明月斷人腸。"]'),
('7be7e7d7-45a6-460f-a958-a6d594980f46','感寓二十首  其六','劉弇','宋','宋诗','song-poetry','','[]','蓬萊三神山，夜夢游其藩。',132,'全唐诗/poet.song.59000.json','["蓬萊三神山，夜夢游其藩。", "岧嶢黄金闕，白玉羅九閽。", "正見王子喬，卧把肘書繙。", "顧謂方瞳人，持我謁羨門。", "揮觴清露滋，行庖屑璵璠。", "一酌祛滯念，再酌洗冥昏。", "三酌陵紫烟，列宿已可捫。", "下觀人間世，參差舞丘樊。", "有客撫雲璈，長離眇飛翻。", "送我若有情，徂鑣儼長鯤。", "悵望不得留，東窗已朝暾。"]'),
('293f0def-2976-482b-b17c-6d3289aecc79','感寓二十首  其七','劉弇','宋','宋诗','song-poetry','','[]','我慕徐孺子，飄然不繫蹤。',120,'全唐诗/poet.song.59000.json','["我慕徐孺子，飄然不繫蹤。", "屢辟竟不起，三府爲一空。", "當時坐支黨，商飆掃萍蓬。", "或橫取鉗釱，或逃爲雅舂。", "南州卑薄地，斯人出其中。", "一丘與一壑，自謂過諸公。", "坐榻解陳蕃，生芻弔林宗。", "維顛非一繩，何獨識汙隆。", "至今清章湄，千載揚高風。", "寫懷寄白社，寂寞吾焉從。"]'),
('2f4e87d5-067b-43d3-867e-7f3fcd4dd401','感寓二十首  其八','劉弇','宋','宋诗','song-poetry','','[]','西山有靈丸，五色發光耀。',96,'全唐诗/poet.song.59000.json','["西山有靈丸，五色發光耀。", "餌之生羽翰，可以後天老。", "莊楊擲斗筲，宇宙决籠罩。", "往逢洪崖生，揖我顧我笑。", "手披真形圖，持杵剖丹竈。", "竦身跂雲烟，一息僅不到。", "終爲俗骨累，凜凜驚頭葆。", "咄嗟魏文帝，空悲跡如掃。"]'),
('6233161e-068c-4707-9a39-180a11049628','感寓二十首  其九','劉弇','宋','宋诗','song-poetry','','[]','士也方蹭蹬，愀愴不得官。',96,'全唐诗/poet.song.59000.json','["士也方蹭蹬，愀愴不得官。", "得官無幾何，日刷陵風翰。", "九衢無閒塵，暢轂走朱丹。", "一爲轍跡誤，翻身落波瀾。", "愁來歌黄鵠，凄感入脾肝。", "千載上東門，爾來誰掛冠。", "犬遺上蔡恨，鶴起華亭歎。", "冢間與林下，疏傅正蹣跚。"]'),
('246033e9-b7b2-4715-ba9b-5bad7ba0ac8e','感寓二十首  其一○','劉弇','宋','宋诗','song-poetry','','[]','驅車出郭門，四顧心茫茫。',96,'全唐诗/poet.song.59000.json','["驅車出郭門，四顧心茫茫。", "玄蟬不知愁，十百號枯桑。", "東北有故宮，云是許旌陽。", "旌陽昔仙去，雞犬亦隨翔。", "云何誇毗子，乾沒走康莊。", "徂年不可挽，綠髮忽已蒼。", "我欲拂衣垢，駐景吸晨光。", "駕言從朱陵，荒兮其未央。"]'),
('658b6672-c54c-4eb6-8fd2-2251e5d8e52c','感寓二十首  其一一','劉弇','宋','宋诗','song-poetry','','[]','鄭謂璞爲玉，周謂璞爲鼠。',72,'全唐诗/poet.song.59000.json','["鄭謂璞爲玉，周謂璞爲鼠。", "處物無定形，公議歸何許。", "子都斥弗御，世或貴嫫母。", "棄鼎寶康瓠，楚客非虛語。", "紉彼荃與蘅，臨風結雙組。", "吾將駕西崑，拾玉老懸圃。"]'),
('f6b325c6-441a-405c-a557-f6621d769f4b','感寓二十首  其一二','劉弇','宋','宋诗','song-poetry','','[]','富貴苦不常，忽則輒易人。',108,'全唐诗/poet.song.59000.json','["富貴苦不常，忽則輒易人。", "青門聚瓜客，曾是故侯身。", "金鏡失秦家，中原駭烟焚。", "屠狗販繒子，閭閻排氤氳。", "一逢泗水公，濯鱗清滄濱。", "信知天地間，虛橐鼓游塵。", "冥中有巨力，呼吸旋峨岷。", "肘股不輟弄，挈故還趨新。", "得失定有寄，無爲喪吾真。"]'),
('dd76e0ba-1c79-41af-ad33-a1217000d28b','感寓二十首  其一三','劉弇','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','穆滿騁八駿，濯濯萬里足。',108,'全唐诗/poet.song.59000.json','["穆滿騁八駿，濯濯萬里足。", "朝賓王母家，暮抵胥飦宿。", "揮觴謠白雲，擁雪歌黄竹。", "歸來七萃空，一舉亡漠曲。", "其樂安在哉，禍胎真瞬目。", "荒矣秦漢君，睢盱究前躅。", "射蛟長江波，寫涕之罘麓。", "彌年滄海傍，神仙杳難屬。", "頹年寄西崦，未必不爲福。"]'),
('a3a02d42-f012-4079-9777-307249a91607','感寓二十首  其一四','劉弇','宋','宋诗','song-poetry','','[]','翩翩外黄兒，片玉駐青春。',72,'全唐诗/poet.song.59000.json','["翩翩外黄兒，片玉駐青春。", "鏖兵彼項籍，菅艾視吾民。", "從容出談笑，桑梓脫沉堙。", "翻咄蹈海客，胡爲苦逃秦。", "射戟與弄丸，解粉竟勞神。", "生子不蚤慧，惜哉襄城人。"]'),
('754e9e92-8467-4ba9-9aef-37af64b32046','感寓二十首  其一五','劉弇','宋','宋诗','song-poetry','','[]','神器不可爲，天下乃大物。',96,'全唐诗/poet.song.59000.json','["神器不可爲，天下乃大物。", "唐堯禪虞舜，茲謂能事畢。", "奈何燕之噲，智詐窮晚出。", "子丕代衰漢，真情愈難詰。", "切雲鏤豐碑，豪誇灑雄筆。", "當時許昌事，埋沒十六七。", "那知石勒笑，正在騁欺術。", "茫茫千載間，高光竟誰匹。"]'),
('c400ae82-7437-4c0c-b5a0-9797f8294474','感寓二十首  其一六','劉弇','宋','宋诗','song-poetry','','[]','芒碭彼真人，元是赤帝子。',108,'全唐诗/poet.song.59000.json','["芒碭彼真人，元是赤帝子。", "游氛决秦餘，最後項籍死。", "青雲躋高衢，侯王興壯士。", "咸陽初置酒，猜似從中起。", "罇俎化胡越，對面邈千里。", "君王忽天贊，顧謂封雍齒。", "軍中相與言，事故易了耳。", "雍齒今且侯，吾屬無患矣。", "炎炎四百秋，安堵從此始。"]'),
('2b1af204-a835-4295-9204-3b22bc64c0a6','感寓二十首  其一七','劉弇','宋','宋诗','song-poetry','','[]','我聞迷塗說，未遠勝不還。',84,'全唐诗/poet.song.59000.json','["我聞迷塗說，未遠勝不還。", "云何之楚客，北首騖燕山。", "山魈獨足笑，短尾陰狐鸞。", "荆棘與風波，平地乃等閑。", "君平反初役，無爲跌其間。", "步兵足長慟，楊朱彫泣顔。", "經涂有九軌，聊以慰躋攀。"]'),
('c5a8a948-69f6-4608-b679-9fd9be9c4bfa','感寓二十首  其一八','劉弇','宋','宋诗','song-poetry','','[]','昔人泣崑崙，泣使變清流。',96,'全唐诗/poet.song.59000.json','["昔人泣崑崙，泣使變清流。", "嫠婦不恤緯，瑣瑣悲宗周。", "薄蝕叔輒號，負阻愚公愁。", "曾無百年身，浪自遺私憂。", "野馬襲日觀，蚍蜉控岑樓。", "齊客有高蹈，箕山無輟耰。", "足己不累物，一毛輕九牛。", "寄言悠悠子，毋貽尸祝羞。"]'),
('9c72e790-aa52-46aa-963c-0c747166617f','感寓二十首  其一九','劉弇','宋','宋诗','song-poetry','','[]','快牛爲犢時，數能破人車。',72,'全唐诗/poet.song.59000.json','["快牛爲犢時，數能破人車。", "駃騠生七日，超母每有餘。", "經奇本自天，豈直循斯須。", "里社有病樗，黔南有駮馿。", "一生便凡散，嗤彼衆所俱。", "下愚與上智，此理信不誣。"]'),
('3429d0fe-7232-4aff-a8ed-a0b5c31b2a14','感寓二十首  其二○','劉弇','宋','宋诗','song-poetry','','[]','疾雷疑車音，出門乃知非。',84,'全唐诗/poet.song.59000.json','["疾雷疑車音，出門乃知非。", "抱影長自明，流螢點霜幃。", "羅带翦秋水，黄金縷春衣。", "持看清夜闌，愁無故時輝。", "食葵心知傾，茹臘腸虛肥。", "纂纂棗下歌，惜此歲月違。", "因聲勸語儂，忽復遲遲歸。"]'),
('2333aef8-a85a-4930-b7a2-d99acdd14958','秋日儀真即事十首  其一','劉弇','宋','宋诗','song-poetry','','[]','秋風來從越天末，痛洗玻璃出明月。',64,'全唐诗/poet.song.59000.json','["秋風來從越天末，痛洗玻璃出明月。", "雲陴隠起玉龍眠，下有舂容萬濤雪。", "獨繭之綸欹一葉，半酣老漁棹歌發。", "客心寸許了無多，底事臨風吹欲折。"]'),
('0a46a2eb-0e75-4d84-803b-e3722c84624e','秋日儀真即事十首  其二','劉弇','宋','宋诗','song-poetry','','[]','野雲墮姿渾貼江，過雨罥風鬧斜行。',64,'全唐诗/poet.song.59000.json','["野雲墮姿渾貼江，過雨罥風鬧斜行。", "秋聲夜半洗遼廓，十萬屋瓦浮青鴦。", "樓頭縹緲下簫鼓，羅繻綺䙱暗行觴。", "紛紛傖楚不足數，更甚吳儂來去忙。"]'),
('69ea36b1-88aa-4f55-b64f-38e741be07fa','秋日儀真即事十首  其三','劉弇','宋','宋诗','song-poetry','','[]','兩兩飛來江上鷗，顔色自欲逼人頭。',64,'全唐诗/poet.song.59000.json','["兩兩飛來江上鷗，顔色自欲逼人頭。", "夢如一雨過疇昔，身似五銖輕轉流。", "紛披葦白狂不徹，糾結蓼紅嬌欲浮。", "五朐之脯一坩鮓，笑問鴟夷乾得不。"]'),
('bb2e14c0-23b0-42a5-960a-860771110cee','秋日儀真即事十首  其四','劉弇','宋','宋诗','song-poetry','','[]','湖海有士豪不除，坐客下床初若無。',64,'全唐诗/poet.song.59000.json','["湖海有士豪不除，坐客下床初若無。", "霜瀾洗出不埋魄，十里但見陳公湖。", "英雄身外亦何有，要使憎勿遷儲胥。", "彼羞杖晚唾遠者，似不名與天年俱。"]'),
('a95533e2-755b-4e87-9e5b-61acd6e2d04f','秋日儀真即事十首  其五','劉弇','宋','宋诗','song-poetry','','[]','丁字河頭文錦翼，似是東園故鸂鶒。',64,'全唐诗/poet.song.59000.json','["丁字河頭文錦翼，似是東園故鸂鶒。", "天風蕭蕭吹汝急，遣汝周章無好色。", "江蘺羃䍥過行人，一顧爲之三歎息。", "我願舴艋從溪翁，雙舂鉏邊作幽客。"]'),
('cc9acc37-08da-45f9-afcf-139925120e8f','秋日儀真即事十首  其六','劉弇','宋','宋诗','song-poetry','','[]','秋入前山瘦如刻，楚弄吳吹沸江國。',64,'全唐诗/poet.song.59000.json','["秋入前山瘦如刻，楚弄吳吹沸江國。", "魚龍爵馬安在哉，粉白黛黑埋真色。", "迎鑾誰是當時人，胚胎黄金仍掃迹。", "飛來蜀岡爾何事，似欲撞空爭岝峉。"]'),
('53c97655-1c00-4a1a-8c5d-cbc8174b5429','秋日儀真即事十首  其七','劉弇','宋','宋诗','song-poetry','','[]','客從南來一何癯，烏紗不屋非縵胡。',67,'全唐诗/poet.song.59000.json','["客從南來一何癯，烏紗不屋非縵胡。", "散堆亂帙覘午{釒厯}，穿穴殫殘真蠹魚。", "尋橦雖工亦未計，立仗不鳴甘豆芻。", "昔人舉肥我今爾，安得外澤如瓠壺。"]'),
('9eb20900-e0ce-4c3c-be4f-d366886ed36b','秋日儀真即事十首  其八','劉弇','宋','宋诗','song-poetry','','[]','艾宣蘆雁天下知，頃聞東園頗有之。',64,'全唐诗/poet.song.59000.json','["艾宣蘆雁天下知，頃聞東園頗有之。", "蕭蕭自含風雨韵，一一對峙江湖姿。", "隸丘呵護脫不謹，剝蝕挽裂遺松楣。", "由來藝固不逮德，突兀但有文忠碑。"]'),
('99fb8186-dd23-49ed-81ec-9dde776523ea','秋日儀真即事十首  其九','劉弇','宋','宋诗','song-poetry','','[]','無根濤頭萬瑶垤，曾是隨風起生滅。',64,'全唐诗/poet.song.59000.json','["無根濤頭萬瑶垤，曾是隨風起生滅。", "不應散裂汜人綃，大似半吞廣寒月。", "紛紛何用辨馬牛，皖皖相矜笑蛙鼈。", "會得秋時買野航，別看吳兒舞狂雪。"]'),
('fc6bb3c3-df84-4ec0-99f6-742977d20001','秋日儀真即事十首  其一○','劉弇','宋','宋诗','song-poetry','','[]','曲隄貫魚銜萬艘，戶有輕薄千金豪。',64,'全唐诗/poet.song.59000.json','["曲隄貫魚銜萬艘，戶有輕薄千金豪。", "瓦甌一引徑舍去，客主似獨心相高。", "利機舞眉手搖穽，鼠子乾沒窮銖毫。", "只今大門盡谿壑，死不盈厭寧此曹。"]'),
('7b31617a-f9f7-4a91-b17e-80b143eab683','過東流聖感寺','劉弇','宋','宋诗','song-poetry','','[]','客從西南來，明發倦流徙。',132,'全唐诗/poet.song.59000.json','["客從西南來，明發倦流徙。", "寅緣泊煩促，羈鳬染寒水。", "祇園開陽方，百年此經始。", "陂陀一水去，騰蹴數峰峙。", "軒楹仍東闢，晚秀皖如洗。", "物隨眄睞移，一息間三起。", "僧閒神自定，童野髮不理。", "平生腐儒計，鞍肉蝕兩髀。", "眼力耗蠅頭，半豁綴旒齒。", "崖澗飽所經，茲乃形性侈。", "疾走影不休，兼忘竟何是。"]'),
('eebf6945-e605-4ccc-942a-38821aa1fbd0','按田行','劉弇','宋','宋诗','song-poetry','','[]','野鳶蹲枯桑，白日忽西注。',108,'全唐诗/poet.song.59000.json','["野鳶蹲枯桑，白日忽西注。", "一水東南奔，驚雷洩濤怒。", "越聞淒涼弄，滯念劇攢蠹。", "歲時倦客身，雲窅前村路。", "應門白癡子，覘矕竊指顧。", "强黠笑官人，彌年此來去。", "田家不諱窮，誰者當豐阜。", "摘刔豈吾心，寬攸惟爾故。", "行矣渠未央，遑恤兒女語。"]'),
('8ab76617-c046-4e78-a592-abf776eb648d','持釣','劉弇','宋','宋诗','song-poetry','','[]','艇子悠揚打雨來，裊絲越箭青玫瑰。',96,'全唐诗/poet.song.59000.json','["艇子悠揚打雨來，裊絲越箭青玫瑰。", "昨聞古湫新雨足，漲波泛入西溪來。", "西溪兩岸行人少，白鷺對翹佳客陪。", "低雲弄嬌不成去，半與枉渚相縈回。", "藻間赬尾厠銀鯽，正爾作羣爭曝腮。", "故應沈餌得所置，行醉甕間新熟醅。"]'),
('33225b4e-ea2b-4ede-a01c-0c492e787a9b','宿長山寺二首  其一','劉弇','宋','宋诗','song-poetry','','[]','蒼山兩蟠虬，傑勢分夭矯。',84,'全唐诗/poet.song.59000.json','["蒼山兩蟠虬，傑勢分夭矯。", "不緣事幽尋，茲地終難到。", "破暝紫烟生，寫谷清樾好。", "村長下牛羊，雲綻入歸鳥。", "松風卷孤磬，夜半秋聲小。", "客懷方未央，千里漫白道。", "庭樹一鳥驚，愁看楚天曉。"]'),
('2f539f9e-881f-4cf2-9c9f-58adbbe80d18','宿長山寺二首  其二','劉弇','宋','宋诗','song-poetry','','[]','客心秋螢點，更覺永夜孤。',84,'全唐诗/poet.song.59000.json','["客心秋螢點，更覺永夜孤。", "龐眉彼上人，主禮良渠渠。", "揖我顧我笑，坐我庭之隅。", "飲我葉家白，怳與顥氣俱。", "玉露下金井，缺月低雲衢。", "擾擾百年身，終慚窘囚拘。", "黎明掉塵鞅，畢景真良圖。"]'),
('31d6915b-bb62-45b0-867d-50be8b5dd836','遊麻姑觀用黄道士韵','劉弇','宋','宋诗','song-poetry','','[]','鳥道參差掛空白，雲林曾是飛昇迹。',64,'全唐诗/poet.song.59000.json','["鳥道參差掛空白，雲林曾是飛昇迹。", "誰論滄海復揚塵，已識秋杉老岑寂。", "玉駕班龍飛九色，古殿崔巍遺石刻。", "會須揖彼丹丘人，掇拾頹年茲偃息。"]'),
('3ee2027d-dc66-4363-9bff-45f15551a2fd','夜泊玉湖口','劉弇','宋','宋诗','song-poetry','','[]','流溪一瀉驚磨垢，夜繫蒙衝玉湖口。',64,'全唐诗/poet.song.59000.json','["流溪一瀉驚磨垢，夜繫蒙衝玉湖口。", "青燈明外稍知村，白鳥飛邊初辨斗。", "風死波閑坐來久，短髮欲搔慵著手。", "一泓清淚墮吳雲，橫管叫秋龍子瘦。"]'),
('d4a1ef8d-a0a6-4811-923e-1e202a8bdcf1','桃葉行','劉弇','宋','宋诗','song-poetry','','[]','君如秋菊英，妾心流螢光。',60,'全唐诗/poet.song.59000.json','["君如秋菊英，妾心流螢光。", "擬吐方寸照，明月終相妨。", "桃葉聲亦苦，千秋斷人腸。", "渡江不用楫，遺讖乃在梁。", "報言青春子，慎勿學輕狂。"]'),
('655e4ea4-a4fc-4955-a754-1d468e3f428e','何塘精舍','劉弇','宋','宋诗','song-poetry','','[]','松閑竹淡清午陰，金地少塵門更深。',64,'全唐诗/poet.song.59000.json','["松閑竹淡清午陰，金地少塵門更深。", "忽從褷褵出重閣，飛梯十尺下瞰臨。", "有客觸熱來自東，汗媿鵩暑慳天風。", "赬龍揚鬐日轡緩，碧椀先愁井絲短。"]'),
('95a995ab-d09e-4c03-a7f4-6e5c47b93723','永新法雲上方','劉弇','宋','宋诗','song-poetry','','[]','石廊西頭物色好，別有浄界擎青蓮。',64,'全唐诗/poet.song.59000.json','["石廊西頭物色好，別有浄界擎青蓮。", "玉虹掛門一水割，碧雲差徑千家連。", "浩歌流年客尊酒，高卧白日僧華顛。", "夜凉散髮弄明月，更欲挽駕青翰仙。"]'),
('bd9865fa-c3a6-4c74-89b0-39d3d1d88c30','發廬陵','劉弇','宋','宋诗','song-poetry','','[]','不作釘根桑，翻爲凌飆蓬。',144,'全唐诗/poet.song.59000.json','["不作釘根桑，翻爲凌飆蓬。", "五年三羈旅，羞哭畏途窮。", "今者人事縛，宛然遊羿弓。", "誰尸造物柄，鼓我吹噓中。", "雲航鬧急槳，勢奪編蒲風。", "黄洲轉頭失，旋指墨潭東。", "旅雁聲其儔，四五翩書空。", "暝色天水接，俯仰雙青銅。", "幽情隨岸愜，眇與魚鳥通。", "酒力秋後葉，扶衰借霜紅。", "詩敵千蛇矛，稍取別愁攻。", "男兒貴健决，吾豈專棲雄。"]'),
('92777e48-a279-461d-89db-bb8597af71cf','鐵柱觀','劉弇','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','鐵柱聞故老，蟄根長江幽。',120,'全唐诗/poet.song.59000.json','["鐵柱聞故老，蟄根長江幽。", "高真此翩躚，瘡痏吾人憂。", "純鉤推三尺，斬蛟白濤頭。", "功成去人間，雞犬不得留。", "班龍駕九色，一別忽千秋。", "疊構開琳琅，夜壇空斗牛。", "寒梢碎凉月，縟綵燦文髹。", "紛吾感遺事，寫涕東南流。", "麻姑行老大，海變繞蛇丘。", "逝將理荃橈，弄睨眺滄洲。"]'),
('8cd3e3ea-b6da-4aba-aca0-c1941d481cb5','舟次生米值風作','劉弇','宋','宋诗','song-poetry','','[]','東北有雲如搜墨，舟子熟視無人色。',224,'全唐诗/poet.song.59000.json','["東北有雲如搜墨，舟子熟視無人色。", "忽然白氣變飛翻，拗怒波神起乘隙。", "初從下游架玉壘，須臾一望熬酥白。", "琳宮蒼茫失向背，野鳥高飛避漸翼。", "紛紛翻舞殊未酣，萬馬躍入朝周客。", "陽侯睢盱推選鋒，勢欲盡取奔鯨磔。", "崩騰豈啻陵谷改，刷滌似病津涯窄。", "大舟踉蹌愁失踞，小舟呼天手加額。", "間於盤渦拆腥沫，疑課鮫魚助奔擲。", "瀘川病客簸欲僵，頼是絙縻逃不測。", "等閒覼縷或衣襦，倉卒何功補淪溺。", "晚來風死回安瀾，由自漫空認飛礫。", "咄嗟鴻毛寄微命，一朝濱死真兒劇。", "明知屏翳不吾欺，何堪失便垂涎得。"]'),
('f6ddbbc6-880b-4b25-a936-f7839cd29b26','大孤山','劉弇','宋','宋诗','song-poetry','','[]','章貢西南來，銀濤白浮天。',289,'全唐诗/poet.song.59000.json','["章貢西南來，銀濤白浮天。", "揚瀾開泛濫，如剖大腹然。", "茲山遥相望，盤薄知何年。", "海風一何高，吹落蓬萊巔。", "浮根襲氣母，弄影白日邊。", "赴渴夸父奔，闊驀踵不旋。", "軒軒執法臣，立當天子前。", "穹螺出佛髻，青跗带秋蓮。", "瑠璃千丈簪，忽與冰箔連。", "鳴榔巖腹雨，挂席浦外烟。", "鶴駕控不返，空遺紫芝田。", "香罏初爭豪，落星纔一拳。", "擢秀蒼梧雲，發彩翼軫躔。", "上窺杳冥無極之層霄，下控瀰茫不測之重淵。", "松蘿參天歲月老，清瀾泛沫魚龍閒。", "中有神朅臨，䁹睨舟往還。", "流俗謂女子，彯纓來此山。", "香脂間綃繒，鵝豬捧羞盤。", "至以孤爲姑，考究初無端。", "可憐俗好怪，此語良大漫。", "神固不可誣，何得正以女子觀。", "吾言庶幾爲不妄，不然茲山徒與望夫、女几爭巑岏。"]'),
('cdac4185-3045-4601-b4ee-f561f63df2d4','贈知訓上人','劉弇','宋','宋诗','song-poetry','','[]','英英商顔芝，遠在青蒼岑。',300,'全唐诗/poet.song.59000.json','["英英商顔芝，遠在青蒼岑。", "雲烟適有寄，爲瑞本非心。", "往聞攀緣人，紆軫恣所尋。", "一落城市間，苾蒭護蕭森。", "鯨魚叩蒲牢，大吼洪鐘音。", "巖巖清冰骨，外垢不得侵。", "試從古人求，絳鉢中支林。", "定香發遠涘，慧劍韜長鐔。", "招提始嘗聆湊泊，塵端駛辨秋黄落。", "一見知非佁儗人，懲躁雪煩真刮膜。", "赤髭由來號該洽，况有新詩堪發藥。", "俊如驍壺輩中出，秀甚巉巉麟一角。", "卑枝雨過結留荑，曲汜萍開窺哺殻。", "紫茸緝春柔，輕屣不躡跟。", "白疊擁方袍，皖如崆峒雲。", "時時好事者，巾屨喜及門。", "隨緣綴香火，高謝乃世紛。", "齒先衆一飯，獨傲傾羲輪。", "顧我紛紛何所爲，年來病眼欲成眵。", "風情落莫非故時，未適棄去唯應詩。", "辱師勤請過六七，獨恨瑣瑣無經奇。", "强顔終篇使持去，著足成累庸非師。"]'),
('e13336c8-ea5a-4c00-9826-b16457f65e8a','寄李知章','劉弇','宋','宋诗','song-poetry','','[]','文章盛自元和間，誰其傑者柳與韓。',240,'全唐诗/poet.song.59000.json','["文章盛自元和間，誰其傑者柳與韓。", "二公秋鶚擅神俊，天使側翅摧誇謾。", "卷收萬象付寂默，神怪鬼篡皆殫殘。", "詩書並馳可終古，豈止唐世論不刊。", "陋儒睢盱百年後，摻筆仡仡愁脾肝。", "問津誰當語博望，初步竟笑非邯鄲。", "紛紛緗縹灑飛礫，埋沒理詣非一端。", "之子清才如振綺，綠髮照春容激丹。", "鄉評舊許擅螺水，文戰曾是鏖桑乾。", "自云從事二公者，用意能到衆所難。", "新詩遺我章江曲，百首洗出青琅玕。", "蒼梧雲生逼齒潤，溟海月借吹衣寒。", "由來青萍止三尺，天末斗牛曾上干。", "流塵不隔自爲快，寧與折鐵論淒酸。", "何由鞭鯨肅吾駕，看子切雲重整冠。"]'),
('182784a1-3f62-4d78-a5a1-97f04ed9fb87','贈善懽禪師','劉弇','宋','宋诗','song-poetry','','[]','劫塵吹冥冥，人乃萬物一。',216,'全唐诗/poet.song.59000.json','["劫塵吹冥冥，人乃萬物一。", "流浪苦趣中，奚啻燋豕蝨。", "爰有勇猛子，間以捷脛出。", "一念得西證，茲謂能事畢。", "誰其秀開士，懽也早奇崛。", "親更藥病師，熟寐驚孤叱。", "祖關决重鍵，法肆躪通術。", "顔顔空王臣，排嶂方山屹。", "又如富兒曹，百寶爛私室。", "况有清整姿，宛是青田匹。", "憶昨螺水曲，囅然契微密。", "眉宇殊津津，襟期洞無窒。", "詩成泣神姦，濉渙湧新帙。", "長驅筆陣閑，坐諷秋蛩唧。", "蕭條晝公後，微子吾幾失。", "方期汗漫遊，悵別念茲日。", "孤雲爾錫駐，過鳥吾帆疾。", "聊作魚相忘，無多嗤蚌鷸。"]'),
('567e9945-41c5-419d-9311-fe1bb37f7d49','送哲公禪老二首  其一','劉弇','宋','宋诗','song-poetry','','[]','有鶴青田來，骨傲九秋老。',144,'全唐诗/poet.song.59000.json','["有鶴青田來，骨傲九秋老。", "羽毛鷄鶩間，不復故時好。", "吳霜割清夢，一夕落幽島。", "哲乎開士秀，佛路著鞭早。", "世累糊空雲，一以凉飆掃。", "往聞琅琊覺，禪海卷狂潦。", "紛紛方袍子，未易艖䑰到。", "師如健噉兒，把握攫梨棗。", "爾來三十年，方寸不貲寶。", "鯨鐘人誰識，聊徇衆擊考。", "又作雲山行，方將同木槁。", "勿學斷緣人，時寄新詩藁。"]'),
('3be37983-48ce-4acf-9afb-665b565ad83a','送哲公禪老二首  其二','劉弇','宋','宋诗','song-poetry','','[]','我聞豫章境，勢勝所至生。',135,'全唐诗/poet.song.59000.json','["我聞豫章境，勢勝所至生。", "山皆撞空活，水有照骨清。", "其間佛老宮，往往聯飛甍。", "人王邑一隅，古屋纔數楹。", "塵點自不到，日飽松風聲。", "十丈挂溪影，虹橋插崢嶸。", "揶揄下{鬼夔}魖，踉蹌笑麏麖。", "師方得所欲，振錫了不攖。", "非如入流子，橫計多餘贏。", "秋畦蹲鴟老，晝飯宜香秔。", "由來介石身，忽作歸雲輕。"]'),
('07818d7a-e6a7-4641-8afb-c6bc017558dd','次韵酬蕭器之朝奉','劉弇','宋','宋诗','song-poetry','','[]','弇也培塿姿，狹識謝崇崛。',288,'全唐诗/poet.song.59000.json','["弇也培塿姿，狹識謝崇崛。", "策疲迷津梁，憂患醉心骨。", "魯酒笑薄圍，商聲慚後出。", "曾微剸犀效，澀鐵但緘室。", "濫紆元豐詔，經名掛千佛。", "中間困齏鹽，晚復椽丹筆。", "同時籋雲英，大半空冀匹。", "鄭衛正啾耳，冷落女媧瑟。", "勞生一瓢壺，風波信浮沒。", "幾欲定蝸居，歸歟訪葱蔚。", "甘齒婆娑民，庶可老縑帙。", "恩波從天傾，隨器到豐溢。", "例當薦員收，殆不止夔一。", "春根聊撥陳，敢議得償失。", "積薪無踰材，魚須暫囊笏。", "持此歲月閒，尚冀補終訖。", "蕭侯朝閨彥，憐我升斗秩。", "洗以古襟期，如鬯發新鬰。", "青天方睹樂，些語劇招屈。", "倒持珠璣囊，一寫非所恤。", "泠然蠲幽抱，海若發瓠窒。", "巴歈迫新賡，芹暄羞獻術。", "得喪雙騰虬，未易嬰長異。", "薄言遵醉鄉，庶我遨永日。"]'),
('72396e54-babf-475f-97cb-0b7fc6f91ecf','次韵和賈仲武同諸公遊狼山','劉弇','宋','宋诗','song-poetry','','[]','寒林羨朝暾，裸壤渴膏霂。',288,'全唐诗/poet.song.59000.json','["寒林羨朝暾，裸壤渴膏霂。", "昔聞三神山，噴薄擅疑獨。", "忽從六鼇頂，角起連天麓。", "我欲追幽尋，筇龍跨飛竹。", "呼吸沆瀣滋，六合歸蹂䠞。", "苦恨弱羽短，彌年胸憤蓄。", "朅來茲山遊，快甚焦得沃。", "幽岐纚脩带，僵木披刳腹。", "桐萼瑩圭姿，槐青收兔目。", "蘭風遞孤爽，天半落芬馥。", "捫蘿躡飛蹬，輕屣捷馳陸。", "窮探初未已，肯憚岡岑複。", "直欲駐頹陽，攬駕還若木。", "主人山南公，白面鬢雙綠。", "載酒邀我行，璀璨揮觥玉。", "雄誇倚馬白，高謝言詩卜。", "狄侯士林秀，智敏紛灸轂。", "江夏拔俗標，天驥脫羈束。", "合匝四座賓，匠手誰甘縮。", "嗟予早不偶，投足祗取黷。", "卑飛得海角，若畏官謗速。", "樊籠一灑濯，便覺榮願足。", "濫當新詩酬，奏雅慚終曲。", "行將秣予馬，更約相追逐。"]'),
('daad9464-7ec3-493e-8e79-8891d79b22a2','再和賈仲武遊狼山','劉弇','宋','宋诗','song-poetry','','[]','尋春古原頭，林梢過朝霂。',288,'全唐诗/poet.song.59000.json','["尋春古原頭，林梢過朝霂。", "狼山連東南，擅美此其獨。", "摶鵬岌駭勢，潑黛森孤麓。", "宜樵葉堆松，供茹萌抽竹。", "區區介丘北，回視一何䠞。", "渾疑杳靄中，爽氣每先蓄。", "掬泉弄幽清，渴肺初欣沃。", "噓雲出羽蓋，入鳥洞胸腹。", "茫茫宇宙間，千里得寸目。", "照髮射冷翠，襲裳來遠馥。", "根株吐乾坤，要會控水陸。", "高躋頂初絕，却轉道彌複。", "楩楠間桐櫧，干霄非一木。", "覃覃闢寶構，殿閣輝丹綠。", "禪客稻餌珠，騷人楮留玉。", "遊嫌後時追，賞貴前期卜。", "睠彼市井徒，乾沒走丹轂。", "老死不一到，動輟取攣束。", "誰知吾輩遊，趣尚非搐縮。", "拂衣便成往，握手不嫌黷。", "句外氣爭豪，禪中機鬭速。", "無爲苦役役，坐自絆馳足。", "紛紛簿領間，與物商直曲。", "會須擺紅塵，更著輕鞭逐。"]'),
('f1a9ef46-5f77-4ce3-9e57-9f5b8392af23','贈雪峰長老守超','劉弇','宋','宋诗','song-poetry','','[]','仰窺玉奩天面窄，頑碧顛青自天擲。',224,'全唐诗/poet.song.59000.json','["仰窺玉奩天面窄，頑碧顛青自天擲。", "祖禪不管地祇慳，十五百徒此其宅。", "流水聲中換今昔，粉抹頳糊老椽壁。", "枯木庵回舊日春，難提塔示重來坼。", "超公最後法席張，全機撲落輥毬場。", "曾令天花倏飄墜，况有庭橘符青黄。", "烏藤橫膝傲佛祖，熟識眉宇瞬且揚。", "天吳吹瀾洗霾垢，方諸挹月來清凉。", "東甌萬剎盡金布，咋舌誰堪論妙悟。", "賺殺參兒走衲雲，高枕無乃林泉負。", "廬峰南遠真西材，叩寂丈室慚宗雷。", "秀巔龐眉逼人爽，反疑不自塵中來。", "由來山興復不薄，畏途何計揮塵縛。", "詰朝匹馬汗羞顔，又作楊花無止泊。"]'),
('c5bf8707-c4f7-4060-b12a-9821cf444233','和仲武苦雨見寄','劉弇','宋','宋诗','song-poetry','','[]','君來通川居，朱門廕重屼。',192,'全唐诗/poet.song.59000.json','["君來通川居，朱門廕重屼。", "近聞值霖雨，匝舍野水淙。", "平地忽浩瀚，頓足疑涉江。", "猛風利如刀，觸紙無完窗。", "朝釜魚頭生，飄注旋抆缸。", "仰收墮案書，俯拾短焰釭。", "癡兒臨缺湫，往往駭影雙。", "我亦有此患，漏榻遶屋扛。", "塊如失羣鵠，感憤愁眉龐。", "孤膺紛填噎，更甚兩肘撞。", "辱君大句投，華旗揭脩杠。", "直欲却以心，不容苟且降。", "森披漢殿戟，縹緲梵天幢。", "蒼惶短兵接，豈暇輒淬鏦。", "區區苦吏役，展驥曾非庬。", "强亦歌巴歈，跛鼈慚驪駹。"]'),
('eb9fbe8b-c944-4355-b569-973c570e969f','晚晴','劉弇','宋','宋诗','song-poetry','','[]','翔飆拂層陰，孤鏡掛天脚。',180,'全唐诗/poet.song.59000.json','["翔飆拂層陰，孤鏡掛天脚。", "幽姿媚澄塘，俊活扶秋岳。", "饑烏下木末，啅雀喧簷角。", "落日銜半規，逗翳如新濯。", "海濤晚聲收，萬里卷冰箔。", "微颸襲疏櫺，輕靄躐叢薄。", "蛛絲裊如狂，虛隙野馬躍。", "病軀得愜適，更甚解攣縛。", "瀟灑萬籟并，沖融百飛却。", "熊經與鳥申，彷彿猶能學。", "蕭蕭寒砧弄，天半哀音落。", "客愁轉如蓬，萬緒入冥寞。", "不無臨風想，曬目歸領略。", "茹蔬味新腴，把酒蘸沉粕。", "明朝踏新泥，已有躋攀約。"]'),
('64f22f3d-18af-4491-acc5-94b1457d0499','贈黄成伯仇覽','劉弇','宋','宋诗','song-poetry','','[]','翔風攪客心，爛熳不可收。',180,'全唐诗/poet.song.59000.json','["翔風攪客心，爛熳不可收。", "隻舲揚層波，益信生計浮。", "滄洲澀歸迹，飄撇慚吳鷗。", "若人求自東，卓犖欣嘯儔。", "揖我暮川涘，疏明炯天球。", "掀髯藉芳草，閒則數魚鰍。", "詩書見孤詣，盤丸走軻丘。", "况有掃圍筆，可擅岐陽異。", "陰湖六尺轝，初恨不少留。", "梅根躍高檣，笑我仍回頭。", "繩床列短炬，相與枯春蒭。", "清狂到詼誹，券內嗤蜉蝣。", "女床無凡羽，渭曲皆清流。", "嘉實自彌望，直未斂以揫。", "須矣策高衢，稽句寧公羞。"]'),
('08704dfe-a612-45af-9bca-12574f9fe8fd','有詔遣移局實錄院因成古詩奉別同舍學士諸公聊佐一笑','劉弇','宋','宋诗','song-poetry','','[]','春秋謹嚴書，百史茲考信。',288,'全唐诗/poet.song.59000.json','["春秋謹嚴書，百史茲考信。", "晚周駕而東，弱魯猶足訓。", "低昂心權衡，與奪管膚寸。", "包羅三八祀，誣始蓋其慎。", "一言開慘舒，九地迴斧衮。", "密雖異鯤鮞，寬亦漏鯨蜃。", "姦魂負芒羞，忠骨蓋棺奮。", "肉角死西郊，風味一朝盡。", "千秋聖人經，寂寞風雨燼。", "三子豪未除，巧語終不近。", "早時遷固儔，雄誇掠秋隼。", "斧鑿謝前規，沙場出孤駿。", "森嚴雖時乏，猶足傲拘窘。", "黠兒何厚誣，乞米誑髫齓。", "至今汗青手，縮袖齎痛憤。", "此道竟寂寥，斯文有遺恨。", "於皇宋七世，輝赫到禹舜。", "起𧽼下祥祉，郁穆起聲聞。", "載祀盈十六，鏟滌無垢釁。", "斯民被醇和，淪浹酣九醖。", "冠劍趨夔皋，戈鋋老廉藺。", "君臣不朽計，邈與事功運。", "龍催鼎湖去，墨燥螭凹潤。", "際會風雲收，刀尺光景迅。"]'),
('a3b013a7-8b12-4e10-899e-c6125250ea8f','送李堯咨赴官山陽','劉弇','宋','宋诗','song-poetry','','[]','長離飛從丹穴傍，刷羽渤澥齎扶桑。',214,'全唐诗/poet.song.59000.json','["長離飛從丹穴傍，刷羽渤澥齎扶桑。", "旦經崑崙莫砥柱，玉山之黍聊充腸。", "歷覽五都遍九土，一朝翩然歸女床。", "夫子故家本山陽，憔悴一官纔故鄉。", "時人等閑得重糈，君家撲滿無餘藏。", "相逢海上真偶爾，畢趣論心良慨慷。", "不無幅巾遲蕭散，况有逸爵揮淋浪。", "酒酣調笑不嫌靳，共指{鼠鳥}{眾鳥}饑鳶翔。", "蕭晨八月渚紅香，水風泛入客衣凉。", "溪頭艇子送急槳，輕齎誰識王陽裝。", "恨無佳設綴行色，匣劍欲解慚非良。", "淮山刻作秋來瘦，淮水刮眼清如霜。", "謝公何日東南下，別浦應尋臨汝郎。"]'),
('7b7a6a19-66a0-4b97-93cc-02f9e8cb3133','送陳師益還建安','劉弇','宋','宋诗','song-poetry','','[]','南來海舶浮雲濤，上有游子千金豪。',192,'全唐诗/poet.song.59000.json','["南來海舶浮雲濤，上有游子千金豪。", "閩山左轉七千里，挂席六月天風號。", "俯窺虞淵弄白日，彤霞下爍波欲熬。", "陽侯嘯瀾罔象舞，出沒金背嬉鯨鼇。", "等閒推徙失向背，往往三山隨所遭。", "我欲懲幽驗荒忽，脫非值子終徒勞。", "吳牛喘月玉斗搖，金井芙蓉啼桔槹。", "一緣竹葉泛歸夢，別興斗與淮雲高。", "青蘋送客淒涼地，節物駸駸驚兩毛。", "家園柿栗行可拾，况有䆉稏蟠東皋。", "魯連蹈海徒虛語，尼父乘槎安所逃。", "它時作底投快便，與子去作滄波遨。"]'),
('83a8e509-3e00-4576-8391-e3d563b739f5','送曾靈永赴舉','劉弇','宋','宋诗','song-poetry','','[]','孟荀久不作，吾道竟茫茫。',228,'全唐诗/poet.song.59000.json','["孟荀久不作，吾道竟茫茫。", "滔滔天下人，生死名利韁。", "誇兒騁新學，剽竄摸青黄。", "爬羅盡砂礫，氣焰苦不揚。", "初如拆襪線，那復一條長。", "又如抄選客，十九爲琳琅。", "埋沒太古音，啾耳紛蜩螗。", "曾郎春不如，闊印眉間堂。", "十年讀書史，一日胸膽張。", "興來灑酣筆，落紙松丸香。", "摧頹鶖鶬間，識此雛鳳凰。", "梅天暑氣溼，江東潦聲狂。", "辭我歸袂擁，霜蒲挂高檣。", "飄翩不可留，橫槊赴文場。", "期子勿苟作，瓊瑶擷新芳。", "莫學下俚曲，黄花間折楊。", "由來玉山粒，梗澀在粃糠。", "河雖一掬波，曾是九秋潢。", "行行事斯語，看子摩天翔。"]'),
('3ae32a46-5677-4229-897c-61eda2ea7890','送新淦余宰虞卿','劉弇','宋','宋诗','song-poetry','','[]','時平循良用，墨綬紛委蛇。',144,'全唐诗/poet.song.59000.json','["時平循良用，墨綬紛委蛇。", "夫子西南英，三十朝紳拕。", "爰來慈衆兒，一掬芝眉和。", "里閭無愁嘆，卒歲知婆娑。", "牛解等是刃，恩染誰非波。", "神閑略朱墨，日永餘弦歌。", "及瓜賦歸歟，去去可奈何。", "舂容雲濤裏，一葉翩經過。", "羹魚飯香秈，凉衣送長哦。", "三年種桃李，留得春陰多。", "鄧挽徒虛語，禰翮方雲摩。", "行哉尚良食，吾君正卷阿。"]'),
('0347ee5b-1454-4ce2-92ee-6ed42c00a799','留題王公謨','劉弇','宋','宋诗','song-poetry','','[]','簷牙排青冥，眺聽脫蒙昧。',132,'全唐诗/poet.song.59000.json','["簷牙排青冥，眺聽脫蒙昧。", "居然人境寬，魚貫出萬態。", "坐疑天機緘，發露窮瑣碎。", "圓清入鳥哢，蕭灑送客慨。", "脫巾晚吾來，靜稱一榻對。", "睨雲發高興，勇欲决猨薈。", "胡爲淫書史，賸若嗜炙膾。", "長年馬如狗，埃𡏖顛毛改。", "茲趣恐長負，踽踽依儕輩。", "何當拾頹齡，相與寄耨耒。", "挽君醉鄉衣，枯肺時一溉。"]'),
('c8d144ed-c01e-4ce8-9f2e-8336d5ef6948','贈王隠居適中','劉弇','宋','宋诗','song-poetry','','[]','樗翁卧南郭，宛是逍遥鄉。',144,'全唐诗/poet.song.59000.json','["樗翁卧南郭，宛是逍遥鄉。", "朝餐止半菽，暮偃仍繩床。", "如松生磽陵，不害材資良。", "少也頓絕羈，駸駸躞雲莊。", "十出九不售，髭根半秋霜。", "他時轉蓬子，頑嬉過其傍。", "那知胸腹中，固自儲琳琅。", "我曾耳清警，灑落皆天潢。", "謂宜神明相，衎衎臻樂康。", "胡爲乞刀圭，彌年對清漳。", "曼容隠成僻，照鄰廢堪傷。", "睡虎與蟄虬，兒童勿輕嘗。"]'),
('18be581c-d695-49fd-b499-72ac6de30681','送元舉宮苑秀州鈐轄','劉弇','宋','宋诗','song-poetry','','[]','插犀頭角何崢嶸，紫棠色照長弓騂。',240,'全唐诗/poet.song.59000.json','["插犀頭角何崢嶸，紫棠色照長弓騂。", "不學蠹魚只浪死，聊因躍馬酬生平。", "奏書明光覓自試，臣有膽武前無勍。", "俞音一朝九天下，瑩膏瘦鐵虬鏗鳴。", "坐上少年勿遽起，請聽此日吳趨行。", "吳中風物妙絕殺，槜李髹碧輝連甍。", "紫崖陰洞泄神秘，霓旌羽帔嬉仙靈。", "鱸肥閟滑匕筯好，鷗眠鳬浴波瀾明。", "突烟晝恬夜柝死，元戎退案休千兵。", "詩成青天送白眼，由拳灑作千鴉驚。", "金船爛漫貯春色，葉底數花餘幾英。", "吳酸挨腸去宿滯，楚舞挑客留瘦情。", "功名成就付偶爾，要是行樂寬吾齡。", "迢迢汴水滴油駛，暖烟畫鷁酣雙旌。", "回頭應笑東方生，胡爲索米長安城。"]'),
('9f2e8ec6-8aca-44a0-b42d-0350d5695058','再繼權之嚴韵二首  其一','劉弇','宋','宋诗','song-poetry','','[]','庭椿摘初黄，畦韭翦柔綠。',144,'全唐诗/poet.song.59000.json','["庭椿摘初黄，畦韭翦柔綠。", "春盤巧飣餖，一堮生理足。", "今者鳴啾腸，饑花到雙目。", "終慚短豆戀，誰轉紫芝矚。", "青烟撲九衢，碧瓦酣萬屋。", "朝來好龍客，義動重裘燠。", "慇懃斗酒約，豪健賽楊僕。", "吹回麯車夢，鴇羽正肅肅。", "九天真龍飛，萬物彈冠沐。", "蕭短草木姿，窶賤衾裯宿。", "叨逾太官粟，敢計功利速。", "惟應杯中物，可仗詩筒趨。"]'),
('dbbc5bd4-2a36-4192-b24a-f39366b8ffc5','再繼權之嚴韵二首  其二','劉弇','宋','宋诗','song-poetry','','[]','東風入顛毛，非復故時綠。',144,'全唐诗/poet.song.59000.json','["東風入顛毛，非復故時綠。", "生涯蠹蟫裏，術智謾蛇足。", "晚作芸香游，頗復窺叢目。", "乾坤開清明，物色洗瞻矚。", "謬當匠石寄，楹桷翰夏屋。", "追隨金閨彥，懷抱鄒律燠。", "新詩閒模寫，勇若驅妾僕。", "千秋赤壁後，英爽得瑜肅。", "朝來牆頭花，皖皖弄膏沐。", "歸期莽難求，不啻襥被宿。", "端成心賞違，誰念客當速。", "聽取提壺聲，勿負慇懃趣。"]'),
('16b2002b-1bc9-4d12-86d2-76dbf1cd5394','送貫之縣丞解官還壽春','劉弇','宋','宋诗','song-poetry','','[]','西江客袂春風老，吹得歸心亂如草。',128,'全唐诗/poet.song.59000.json','["西江客袂春風老，吹得歸心亂如草。", "鯢浪三篙下晚艎，去程不學寒蓬掃。", "淮山蒼蒼淮水長，千里一官歸故鄉。", "舉世由來青眼少，孟賸破黛嫫母狂。", "緹巾十襲盡燕石，埋蝕太半雙明璫。", "干霄自是男兒氣，遭與不遭真偶爾。", "人非田文莫彈鋏，世有伯喈須倒屣。", "君其行矣重問津，蹀月騊駼寧絆死。"]'),
('e9674041-f8f1-41c8-b930-9b36941e2eba','次韵和彭道原元夕','劉弇','宋','宋诗','song-poetry','','[]','攙雲幄幕張流蘇，華輈夾道青氍毹。',160,'全唐诗/poet.song.59000.json','["攙雲幄幕張流蘇，華輈夾道青氍毹。", "黄昏天公下種榆，百萬星點成須臾。", "赤帝鞭車墮雲衢，燭龍駢頭浦還珠。", "競隨丹豹膏鳳雛，麟鬚拂蛾間數疏。", "弦嘈管唳聲鬰紆，櫛比百戲羅侏儒。", "輕紈綉履踏艷姝，灼灼巧笑聯芙蕖。", "有客年來倦著書，囊錢囷粟索無餘。", "短釵列桉擁弊襦，未看行樂誇睢盱。", "大奴聽響仆屋隅，小女行卜迎紫姑。", "子雲門巷正蕭疏，誰者載酒論區區。"]'),
('1a665721-528b-4457-a3c4-bc7dc1ceeacf','書新興羅漢室','劉弇','宋','宋诗','song-poetry','','[]','應真檀施者誰子，僧云福堂隴西李。',32,'全唐诗/poet.song.59000.json','["應真檀施者誰子，僧云福堂隴西李。", "亙無窮盡理則那，明明善根此其始。"]'),
('4e2c7230-ef14-4d72-93da-50cbac7b0ef2','次韵林錫遠食蜂兒之句','劉弇','宋','宋诗','song-poetry','','[]','世人嗜食心，專甚鼓記里。',168,'全唐诗/poet.song.59000.json','["世人嗜食心，專甚鼓記里。", "刳磔供嚼齧，誰計物生死。", "紛紛螷蠃蚳，晚亦列甘旨。", "况如茲蜂者，捃拾纔蠢爾。", "八月陰崖昏，戢戢若攢指。", "老房脫枯蓮，薦右方物美。", "翻嗟甘口鼠，橫使童角毀。", "吳蠶徒自僵，商賈斯遠矣。", "我思天地間，材死舉相似。", "鳥殪在澤羽，象焚緣插齒。", "梢梢撓雲幹，虸鋸入儀軌。", "豹胎及駝峰，日飽饞咽子。", "人方懷此憂，何暇多議彼。", "異時佳設張，更餉勿余鄙。"]'),
('a4a827b2-543d-4b68-8d94-604b0baa513d','題遠上人休老庵','劉弇','宋','宋诗','song-poetry','','[]','上人叢林秀，襟期支許越。',180,'全唐诗/poet.song.59000.json','["上人叢林秀，襟期支許越。", "往從湖山遊，發軔無留轍。", "轉身浮雲空，歸興飛鳥豁。", "故鄉得青海，下瞰鯨燦窟。", "結廬纔蝸牛，勝踐喧卑脫。", "叢殘翦荆棘，淚敝棲楣埒。", "蘭苕紛被逕，關鎖晝不掣。", "由來大慷生，卓錫果清絕。", "菅茅席三徑，虛榻掃凉月。", "不持一錢居，未省香火歇。", "鶴骨老亦輕，田衣故仍潔。", "高舂一飯過，野荈供嚼齧。", "笑作瘡剜肉，薦語畏饒舌。", "陽岡藷蔗稠，乳竇春泉冽。", "行當攬俗駕，滯念論一吷。"]'),
('17bbd892-fb9e-434a-9b3b-8d97ef04ee42','酒家逢徐逸人','劉弇','宋','宋诗','song-poetry','','[]','嚨唿馬子踏落花，落花盡頭逢酒家。',156,'全唐诗/poet.song.59000.json','["嚨唿馬子踏落花，落花盡頭逢酒家。", "酒翁破顔迎墨客，五雲冰漿發青帊。", "丹丘羽人笑揖我，餉我碧海雲琅芽。", "食之奇光襲兩腋，小哉天地自幕席。", "眼底不辨驪與騧，冷風時能借一快，便欲搴芝淩紫霞。", "且唱蹋銅汙，莫歌白浮鳩。", "躍沫寄頹年，陰陰馳四騶。", "雲璈駕閬風，茲約竟悠悠。", "却憶東皋醉鄉記，翻笑三閭非所憂。", "安得烏孫青田核，下變春江萬斛流。"]'),
('89e9d22e-2594-4a42-a1da-28675591b30c','志雁','劉弇','宋','宋诗','song-poetry','','[]','東道出海陵，儲水得故濼。',180,'全唐诗/poet.song.59000.json','["東道出海陵，儲水得故濼。", "野雁若烟海，於焉避繒繳。", "去來迷春冬，唼喋識領略。", "于時臘將殘，篝火彼童弱。", "霜葭揚飛熛，敦迫海風惡。", "崑陵卷大地，電笑牽霆搏。", "翩翩隨陽侶，照影起虛愕。", "嗚呼犯蓬勃，騰踐劇殞雹。", "捎捎青雲翮，寒㶼謝寥廓。", "莫知孰奴王，百萬歸一爝。", "有叟家青溪，三日舉不涸。", "赤肉羅岡陵，腥血灑叢薄。", "商人爭行錢，烟艇紛飄泊。", "蓬茨未改故，十倍富前昨。", "翻笑任公子，釣鯨滄海角。"]'),
('45ab6385-2f00-4975-8f68-b5f56019cb4c','海門故城','劉弇','宋','宋诗','song-poetry','','[]','故城邑東南，盤盤蟄脩蛇。',144,'全唐诗/poet.song.59000.json','["故城邑東南，盤盤蟄脩蛇。", "借問經始人，云是司徒家。", "唐季遭閔凶，羣盜紛如麻。", "淮海尤剽輕，時時起邀遮。", "甚者控壤地，相錯臨犬牙。", "斯人何爲者，尋兵嘯麏䴥。", "擅此一抔土，僅侔國於蝸。", "鍖鑕稽天誅，至以功爵加。", "百年去隨手，遺陼臨汀沙。", "牛羊閱朝昏，草木自萌芽。", "誰非化黄壤，此獨遺鷄笯。", "停驂一回首，浩歎空歌巴。"]'),
('3d82a523-4999-4719-9884-f316d3d14128','夜飲留李聖咨法曹走筆','劉弇','宋','宋诗','song-poetry','','[]','君不見東皋酒狂能放懷，醉鄉著家身去來。',134,'全唐诗/poet.song.59000.json','["君不見東皋酒狂能放懷，醉鄉著家身去來。", "又不見昔時西晉把螯客，隻手敵以黄金罍。", "流年驚鴻瞥眼過，爲君特地柴門開。", "鵝雛轉黄吹甕醅，紫蒲白薤雜芋魁。", "始知有神王歡伯，解卷霢霂蘇愁荄。", "玉繩挂閣爽氣回，烏樹不驚螢點苔。", "熱耳未厭雞聲催，玉山好約斜河頹。", "枯腸一掬君勿負，蓬行丸轉真悠哉。"]'),
('4c0cd4ca-aef6-4f00-b304-be394d9b6b15','我行','劉弇','宋','宋诗','song-poetry','','[]','我行適東陂，野色若可搴。',132,'全唐诗/poet.song.59000.json','["我行適東陂，野色若可搴。", "問津初無從，强驅良苦鞭。", "三𤃩貯客潦，冉冉吞吳天。", "故壘何崢嶸，荒凉非昔年。", "虹腰截海堰，蜃氣噓窯烟。", "霜封百草乾，回風時飆然。", "狐兔死欲盡，饑鷹空老拳。", "村深行人稀，落日下烏鳶。", "敗荷古毳衲，野菊金連錢。", "羈懷自騷屑，節物驚徂遷。", "投暮僧舍中，誰者同留連。"]'),
('c3808362-d698-419e-b022-26129c6b5a4a','雷塘','劉弇','宋','宋诗','song-poetry','','[]','磐嬉截長淮，聞自隋天子。',168,'全唐诗/poet.song.59000.json','["磐嬉截長淮，聞自隋天子。", "運丁大業末，役跨遼東始。", "洶湧溝濁河，赤血洗千里。", "江都天東南，歲閱翠華指。", "錦帆抹非烟，疊鼓蓬蓬起。", "紫幰朱絲絡，百萬羅衛士。", "璇房貯彩女，灼灼艷芳李。", "虞公正逢惡，何稠甘沒齒。", "一從水調奏，便識還聲已。", "浪傳遭閟春，不悟羊無尾。", "雷塘一掬土，僅足掩冠履。", "行人爲傷心，清淚墮如水。", "池荒九曲春，尚想迷樓倚。", "落日注蕪城，牛羊下坡觜。"]'),
('d351fcc2-8529-4086-9a81-c04867f6c2c0','依師小軒獨酌','劉弇','宋','宋诗','song-poetry','','[]','東籬粲佳英，依約圓錢帖。',144,'全唐诗/poet.song.59000.json','["東籬粲佳英，依約圓錢帖。", "西渚傲霜篔，瀟灑狻猊鬣。", "居然容膝地，况與蓬丘接。", "始余供煩使，浪謂素意愜。", "一當駭物機，局縮如跧摺。", "客塵不制人，脫去苦不捷。", "誰謂一日間，堮倚發蹀躞。", "椒漿淚玉瀝，蠹簡披往牒。", "兀爾自忘懷，少復進專輒。", "流年苦蹉跎，念咎真脫葉。", "皤皤彼禪客，趨尚未易躡。", "正應發再駕，萬念茲一攝。"]'),
('ef912be3-7074-425d-96b9-7c58d95e1a3f','早發臨川經回龍寺少刻因觀李供奉壁畫須菩提','劉弇','宋','宋诗','song-poetry','','[]','黎明出故壘，得此空王宮。',132,'全唐诗/poet.song.59000.json','["黎明出故壘，得此空王宮。", "結廬知何年，十里巒岡重。", "居然謝埃𡏖，䆗窱開房櫳。", "簁籬漏初日，雲木凉高風。", "直疑天邊秋，六月到此中。", "壁端故時筆，磊落空生容。", "詐言竺乾客，燕坐長年逢。", "我來偶拭目，滯念爲一空。", "野僧强留連，稻飯延高舂。", "王程迫星火，持語勿惱憹。", "方慚簡書畏，何計棲狂蓬。"]'),
('7e925f4f-08ac-494d-b34e-99d38b43e77a','留題疏山白雲禪院因呈長老秀公','劉弇','宋','宋诗','song-poetry','','[]','白雲去不還，空留白雲額。',108,'全唐诗/poet.song.59000.json','["白雲去不還，空留白雲額。", "至今飛山顔，片片盡秋色。", "蕭蕭事盤紆，刳石轉欹仄。", "觚稜騫古殿，粉墨昏絕壁。", "有客倦歸艎，瀟灑寄一適。", "松蘿青鳥哢，江影卷餘白。", "始時開山人，真意非無得。", "百年驚一吷，節物變今昔。", "誰是雲無心，翛然彼禪伯。"]'),
('744a1c96-b1cd-400a-ad73-32fbe8321e50','過昆陽城','劉弇','宋','宋诗','song-poetry','','[]','古聚少，荒蹊多，枯湟十尺餘陂陀。',110,'全唐诗/poet.song.59000.json','["古聚少，荒蹊多，枯湟十尺餘陂陀。", "絳霄南來赤龍子，叱吒此地揚天戈。", "虎據乃其始，鵲起寧須時。", "坐令劉宗半天下，尋邑百萬徒爾爲。", "今來玉壘半荆棘，但見蒼烟白日嬉樵兒。", "愁來商歌涉長道，澤國秋蘭紫莖老。", "九原蓬顆日益多，世事茫茫一飛鳥。"]'),
('1e06f80c-fc00-457a-b11f-26f5f71b9802','鄱陽湖四十韵','劉弇','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','巨浸連吳越，高躔直斗牛。',288,'全唐诗/poet.song.59000.json','["巨浸連吳越，高躔直斗牛。", "玄冥開別府，江伯匯支流。", "象緯元精逼，神姦秘怪裒。", "番君疏带礪，彭蠡壯襟喉。", "赴隙如無地，憑壖忽有州。", "津涯逾寫潤，窟宅定刳幽。", "島認瀛鼇戴，濤疑陣馬異。", "珠跳憐雨駛，鏡滑識風收。", "樹带喬枝隠，山餘短碧浮。", "窺覘波罔象，睥睨忲陽侯。", "漾月都迷皓，蒸雲間作油。", "涵濡均藻荇，冗長到蝦鰍。", "蜃幻晴噓閣，龍腥夜拔湫。", "萬尋懸圃玉，一带洞庭秋。", "盈縮知誰紀，吞并似力揫。", "鯉矜封赤鯶，龜笑斥朱眸。", "嵌竇扶桑齧，珍文匠石鎪。", "鷗羣馴野客，蚖肆傲潜虯。", "罟數筐零霰，檣輕弩激遶。", "孰分浮瓠澨，或訝繞蛇丘。", "弦索延商婦，舽艭送莫愁。", "陶朱誠得策，神禹想遺憂。", "端稱潺湲弄，非無隠伏搜。", "豆分高下渚，葦視去來舟。"]'),
('c6f76595-3d25-477c-a27b-93c565696314','蔣沙莊居十首  其一','劉弇','宋','宋诗','song-poetry','','[]','他日蓬蒿地，吾廬瓦數溝。',48,'全唐诗/poet.song.59000.json','["他日蓬蒿地，吾廬瓦數溝。", "井泉甘勝乳，庭竹冷先秋。", "村落時情淡，田疇歲計優。", "荆扉輪日掩，最喜近松楸。"]'),
('7a21760a-7ba1-4bb3-b377-f1810d014cd7','蔣沙莊居十首  其二','劉弇','宋','宋诗','song-poetry','','[]','黄嶺虹腰抱，鼇山食案橫。',48,'全唐诗/poet.song.59000.json','["黄嶺虹腰抱，鼇山食案橫。", "中非避世士，稍亦畏時名。", "傍晚澆慵酒，尋春濯足行。", "雞雛嬌底死，犢子健能生。"]'),
('833af51a-5e21-44d6-b9d5-fff2c90e32f8','蔣沙莊居十首  其三','劉弇','宋','宋诗','song-poetry','','[]','翳翳柔桑活，輝輝野水寬。',48,'全唐诗/poet.song.59000.json','["翳翳柔桑活，輝輝野水寬。", "藝蔬蒼芥甲，延客白蒲團。", "點綴花粘蔓，稀疏粉束竿。", "家風纔茗飲，一室聽冰寒。"]'),
('69362fb2-2e7d-4cec-8348-b410d8eac97b','蔣沙莊居十首  其四','劉弇','宋','宋诗','song-poetry','','[]','軟滑香秈顆，肥長紫蕨苗。',48,'全唐诗/poet.song.59000.json','["軟滑香秈顆，肥長紫蕨苗。", "盤餐殊不惡，鄰叟亦時邀。", "潘岳蕭條鬢，陶潜頡頏腰。", "巢枝得安穩，萬物一鷦鷯。"]'),
('fcb57452-7a71-4efd-9e7c-6cb613745a2f','蔣沙莊居十首  其五','劉弇','宋','宋诗','song-poetry','','[]','晴屋鳴鳩婦，春陂翳雉媒。',48,'全唐诗/poet.song.59000.json','["晴屋鳴鳩婦，春陂翳雉媒。", "堮頭甘野蔌，鋤力到陳荄。", "掠水千艘健，橫風一笛哀。", "最憐雙白鳥，解事等閒來。"]'),
('290c875a-2664-45a7-ac93-05c69503383f','蔣沙莊居十首  其六','劉弇','宋','宋诗','song-poetry','','[]','十里蛇原近，宜閟一畝金。',48,'全唐诗/poet.song.59000.json','["十里蛇原近，宜閟一畝金。", "亂酲眠暗術，嬌碧擁雲林。", "早晚歸歟計，因循愧此心。", "江南吾土樂，應得慰消沉。"]'),
('98e8a184-14e5-4e84-80c9-d927472f8521','蔣沙莊居十首  其七','劉弇','宋','宋诗','song-poetry','','[]','松種龍蛇子，栽培近著行。',48,'全唐诗/poet.song.59000.json','["松種龍蛇子，栽培近著行。", "有時窺北榻，不日暗東岡。", "淚落終含韵，輪囷未竟長。", "故應容足地，投老慰荒凉。"]'),
('0ab0d38a-dcad-42b7-834d-c04652569fde','蔣沙莊居十首  其八','劉弇','宋','宋诗','song-poetry','','[]','羊棧雞塒接，蔬畦麥壠傍。',48,'全唐诗/poet.song.59000.json','["羊棧雞塒接，蔬畦麥壠傍。", "蝸涎書老壁，苔陣澀高廂。", "家有青緗學，兒傳急就章。", "未甘騎瘦馬，跳蚤事乾忙。"]'),
('0a15389a-2f19-4ebd-adbe-cd1d368a9b42','蔣沙莊居十首  其九','劉弇','宋','宋诗','song-poetry','','[]','名愧周繁弱，材非魯孟勞。',48,'全唐诗/poet.song.59000.json','["名愧周繁弱，材非魯孟勞。", "蛙仍當鼓吹，徑任沒蓬蒿。", "紫芋新厨味，黄棖馥鱠刀。", "業詩何水部，耽酒阮兵曹。"]'),
('4a9a4a58-0734-4e77-9ca1-45684f92a8c8','蔣沙莊居十首  其一○','劉弇','宋','宋诗','song-poetry','','[]','劉宗墳墓國，金水眇縈回。',48,'全唐诗/poet.song.59000.json','["劉宗墳墓國，金水眇縈回。", "颭颭鴉巢覆，疏疏槿戶開。", "春風持贈柳，臘雪試妝梅。", "欲識塵埃少，元無俗物來。"]'),
('acccb87a-4c38-41df-9c64-5d9b30b017dd','莆田雜詩二十首  其一','劉弇','宋','宋诗','song-poetry','','[]','清樾陂陀外，春深四五家。',48,'全唐诗/poet.song.59000.json','["清樾陂陀外，春深四五家。", "叢祠下簫鼓，平楚暗桑麻。", "水國潜虯傲，天程去鳥賒。", "仙山仍在目，瀟洒送生涯。"]'),
('7f13ff92-909c-409d-aa8e-076a4ce42abf','莆田雜詩二十首  其二','劉弇','宋','宋诗','song-poetry','','[]','梅雨催農鎛，癡風泣海檣。',48,'全唐诗/poet.song.59000.json','["梅雨催農鎛，癡風泣海檣。", "魚龍波浪闊，燕雀戶庭凉。", "鰩柱春刳玉，蠔山夜鑿霜。", "家園兩痕淚，早晚促吾裝。"]'),
('51eaa5a3-ce24-4269-aa09-0dae06d5edb6','莆田雜詩二十首  其三','劉弇','宋','宋诗','song-poetry','','[]','南北分雙剎，公私限五塘。',48,'全唐诗/poet.song.59000.json','["南北分雙剎，公私限五塘。", "蚶祠開鎖碎，蟹井幕荒凉。", "酒熟傳紅泛，搶珍異墨黄。", "飄零晉耆舊，冠劍幾星霜。"]'),
('57a2267b-f375-4c23-9631-e025bbda9fcf','莆田雜詩二十首  其四','劉弇','宋','宋诗','song-poetry','','[]','梅井經疏鑿，如聞自昔人。',48,'全唐诗/poet.song.59000.json','["梅井經疏鑿，如聞自昔人。", "玉奩深貯月，雲乳暖藏春。", "桐葉誰新汲，葵芽好問津。", "端堪事杯酌，泠汰客襟塵。"]'),
('c26826f4-9781-4700-92af-c9590d79400c','莆田雜詩二十首  其五','劉弇','宋','宋诗','song-poetry','','[]','末麗娟娟妬，山丹灼灼姝。',48,'全唐诗/poet.song.59000.json','["末麗娟娟妬，山丹灼灼姝。", "暖烟喦養璞，沉碧鳳將雛。", "刀尺文章拙，巾㡚禮數迂。", "課成鷗鷺想，片夢落江湖。"]'),
('ee55d13f-9327-4f02-9f08-75f7ec405d6a','莆田雜詩二十首  其六','劉弇','宋','宋诗','song-poetry','','[]','十里壺公廟，喧傳像逼真。',48,'全唐诗/poet.song.59000.json','["十里壺公廟，喧傳像逼真。", "斧斤刳洞骨，風雨澀松鱗。", "氣象乾坤豁，涵濡草木春。", "的應雲鬧處，藏得武陵人。"]'),
('cb8fcd20-3f80-4aea-b3bb-81480193db2a','莆田雜詩二十首  其七','劉弇','宋','宋诗','song-poetry','','[]','鶗鴂青春晏，遶鼩白社驕。',48,'全唐诗/poet.song.59000.json','["鶗鴂青春晏，遶鼩白社驕。", "掠風雛燕翼，界雨晚虹腰。", "醥醁銀床瀝，蘴茸紫澗苗。", "到家幸無苦，浦溆有回潮。"]'),
('d93225f5-1475-4b0e-86a8-4f044590b8fa','莆田雜詩二十首  其八','劉弇','宋','宋诗','song-poetry','','[]','飽聞何氏子，遺跡在仙山。',48,'全唐诗/poet.song.59000.json','["飽聞何氏子，遺跡在仙山。", "節擁三清絳，龍騎九色班。", "曲屏明猨薈，哀玉走潺湲。", "好刷摩天翮，徂鑣試一攀。"]'),
('5111d079-5ee0-4a28-8c05-3bff3829dd8a','莆田雜詩二十首  其九','劉弇','宋','宋诗','song-poetry','','[]','香憶傳喦號，龜曾得寺名。',48,'全唐诗/poet.song.59000.json','["香憶傳喦號，龜曾得寺名。", "禽巢多越思，海錯盡南烹。", "接食烏兒墮，漫岡犢子獰。", "正憐盃酒賤，醉叟日縱橫。"]'),
('8176ea12-47dd-4b8a-8259-c158f7bfd71e','莆田雜詩二十首  其一○','劉弇','宋','宋诗','song-poetry','','[]','鶴唳歸雲急，龍移過雨腥。',48,'全唐诗/poet.song.59000.json','["鶴唳歸雲急，龍移過雨腥。", "桂清飄月岫，槎老卧烟汀。", "洞失壺公舊，雩傳妙應靈。", "不緣幽事隔，小復理篂箳。"]'),
('b2b0c985-3c1a-4cda-bb3e-3e3e13b20b7d','莆田雜詩二十首  其一一','劉弇','宋','宋诗','song-poetry','','[]','共樂超然構，躋攀一氣邊。',48,'全唐诗/poet.song.59000.json','["共樂超然構，躋攀一氣邊。", "蒼茫雲水國，清潤李梅天。", "碎白淙崖瀑，孤青煮海烟。", "三神山自邈，何至苦求旃。"]'),
('ce7599b6-9c69-4d45-9bc3-a96f7c533521','莆田雜詩二十首  其一二','劉弇','宋','宋诗','song-poetry','','[]','蠨蛸當戶綴，絡緯擁莎吟。',48,'全唐诗/poet.song.59000.json','["蠨蛸當戶綴，絡緯擁莎吟。", "詩魄干霄上，棋魔攪海深。", "忘機一飛鳥，藏拙萬黄金。", "昨有逃虛慰，支郎下北岑。"]'),
('88c54686-1709-4934-a0a2-0cfe49553625','莆田雜詩二十首  其一三','劉弇','宋','宋诗','song-poetry','','[]','直東無際海，萬水自朝宗。',48,'全唐诗/poet.song.59000.json','["直東無際海，萬水自朝宗。", "沃日纔分爝，浮天亦盪胸。", "吐吞何楚越，冗長到魚龍。", "好在乘桴客，吾安議適從。"]'),
('dd1ac531-54d1-41eb-8449-82fc19df4758','莆田雜詩二十首  其一四','劉弇','宋','宋诗','song-poetry','','[]','遠寺梢清梵，孤城咽晚笳。',48,'全唐诗/poet.song.59000.json','["遠寺梢清梵，孤城咽晚笳。", "稻畦眠堮淥，榕逕愕懸蛇。", "尊俎輝琮璧，詩書蟄鏌鋣。", "家家餘歲計，吉貝與蒸紗。"]'),
('869f1bbf-aa5b-4c63-9803-67518dc14a68','莆田雜詩二十首  其一五','劉弇','宋','宋诗','song-poetry','','[]','當日山南寺，層樓插蔽虧。',48,'全唐诗/poet.song.59000.json','["當日山南寺，層樓插蔽虧。", "龍蛇緘柳筆，風雨舛唐碑。", "遊淺雲吞液，山稀海襯眉。", "杖藜搘瘦鶴，白髮茂林緇。"]'),
('e788022a-df8f-4af6-b5a4-c4fd6ef9be4d','莆田雜詩二十首  其一六','劉弇','宋','宋诗','song-poetry','','[]','功名慚鶚瞬，龜組困鳩佻。',48,'全唐诗/poet.song.59000.json','["功名慚鶚瞬，龜組困鳩佻。", "元結郎終漫，劉安隠孰招。", "客塵關簿領，生計負漁樵。", "頼足尊中物，時將塊磊澆。"]'),
('8ba73fe3-a12e-4a10-a9f5-432b23155f19','莆田雜詩二十首  其一七','劉弇','宋','宋诗','song-poetry','','[]','傍海千塍稻，由來䆉稏蟠。',48,'全唐诗/poet.song.59000.json','["傍海千塍稻，由來䆉稏蟠。", "異時更虐颶，中夕舞驚瀾。", "竟使魚鼈有，不堪蛙黽讙。", "嗟吾無急策，坐視汝凋殘。"]'),
('82f361f3-0dcb-449d-bb8d-221f62e58047','莆田雜詩二十首  其一八','劉弇','宋','宋诗','song-poetry','','[]','荔子綃囊搐，蕉花玉糝駢。',51,'全唐诗/poet.song.59000.json','["荔子綃囊搐，蕉花玉糝駢。", "紫髯牽腰裊，紺{糹憲}走嬋娟。", "蕭寺千家幕，蘭盆七月天。", "壺公仙日月，乞汝送流年。"]'),
('3d98146d-4334-4d64-8c50-6ccaf40705d9','莆田雜詩二十首  其一九','劉弇','宋','宋诗','song-poetry','','[]','三縣圜扉閴，全閩道院傳。',48,'全唐诗/poet.song.59000.json','["三縣圜扉閴，全閩道院傳。", "夜濤慳夢寐，晡食厭腥羶。", "家塾儒風舊，牢盆利孔偏。", "塵埃如拂得，定作海鄉仙。"]'),
('57c466d3-8bfd-4044-92ad-ba9a89b01d44','莆田雜詩二十首  其二○','劉弇','宋','宋诗','song-poetry','','[]','雨露蕭茅浹，乾坤燕雀微。',48,'全唐诗/poet.song.59000.json','["雨露蕭茅浹，乾坤燕雀微。", "草萊鞭懶蟄，廊廟集橫飛。", "今者誠何補，吾其孰與歸。", "夜來天直北，劍魄繞星輝。"]'),
('e7d07bd9-ced3-47e0-a6c4-817784dba6be','早發赴蒙縣二首  其一','劉弇','宋','宋诗','song-poetry','','[]','草露垂垂白，溪泥脚脚深。',48,'全唐诗/poet.song.59000.json','["草露垂垂白，溪泥脚脚深。", "槿籬藏吠犬，桑蘙漏棲禽。", "食匕驚浮世，鞭梢度寸陰。", "利名幺麽得，會是死灰心。"]'),
('62a6a757-10f5-43d8-ab8e-9b0ccdc19edd','早發赴蒙縣二首  其二','劉弇','宋','宋诗','song-poetry','','[]','搖落秋無頼，追隨月結緣。',48,'全唐诗/poet.song.59000.json','["搖落秋無頼，追隨月結緣。", "褐衣寒未授，櫪馬老先顛。", "客思淮雲遠，鄉魂越鳥邊。", "荒唐故時叟，曳尾想遺阡。"]'),
('484f6251-4b74-438c-a001-a8768bec21d4','贈謝民師','劉弇','宋','宋诗','song-poetry','','[]','三語君爲掾，百罹吾厭生。',48,'全唐诗/poet.song.59000.json','["三語君爲掾，百罹吾厭生。", "江山共鄉思，蘭桂敵交情。", "黄卷真無負，龍淵恐不平。", "何當改初服，別約紐荃蘅。"]'),
('7c878c99-9d03-43c6-a9d1-dde591f2c761','臨江','劉弇','宋','宋诗','song-poetry','','[]','居然兩福地，首尾限清江。',48,'全唐诗/poet.song.59000.json','["居然兩福地，首尾限清江。", "䆗窱蘆州抱，晶熒石澗淙。", "潑雲秋䆉稏，割雨曉舽艭。", "愁絕村南舍，馴雞對小窗。"]'),
('c1e80bb4-62f7-439e-87bd-cf7aaaa5b057','贈李子從三十韵','劉弇','宋','宋诗','song-poetry','','[]','落落將家子，堂堂儒者宗。',288,'全唐诗/poet.song.59000.json','["落落將家子，堂堂儒者宗。", "虹蜺蟠志氣，天地貯心胸。", "骨秀霜含樹，神清瀑掛峰。", "才應過八斗，業已足三冬。", "燈壁曾聞鑿，螢紗屢聽縫。", "書從蒲葉寫，詩向錦囊封。", "醉把乾坤揖，吟將風月供。", "揮毫珠錯落，吐論玉錚鏦。", "逐逐儒林虎，昂昂墨海龍。", "文踰韓吏部，學切鄭司農。", "雨露恩將及，風雲運正逢。", "海深鯤定化，霄遠鶴須沖。", "汝乃今王粲，予非昔蔡邕。", "敬蒙修客刺，特辱造賓墉。", "遂闢膺門納，因施孺榻容。", "禮賢臺再築，待客黍頻舂。", "磨講詩千首，歡諧酒一鍾。", "笑談風對起，論難劍交鋒。", "篇什回環數，緘題往復重。", "共將諸子探，同把異端攻。", "聞見輸君博，賡酬愧我慵。", "便當思閣筆，何敢更撞鐘。", "堂舍經宵會，琴堂累日從。", "並行花縣密，同坐柳陰濃。"]'),
('1691a8ea-716a-41ee-b49a-68e779e849ff','傷段謙叔失意二十八韵','劉弇','宋','宋诗','song-poetry','','[]','場屋遺才日，英雄失意秋。',288,'全唐诗/poet.song.59000.json','["場屋遺才日，英雄失意秋。", "薦賢無北海，削迹有東丘。", "未遂圖南志，先貽敗北憂。", "曠弦多誤奏，卞玉却輕投。", "西逐慚秦客，南冠愧楚囚。", "天亡非戰罪，道喪是吾羞。", "命薄聞歌鳳，時窮見叩牛。", "丹山摧鸑鷟，虞阪困驊騮。", "落日千行淚，西風萬古愁。", "壯圖沉草莽，歸思動滄洲。", "是理皆前定，非人可豫謀。", "悶來宜自遣，勢去不須尤。", "消日棋千局，忘懷酒一甌。", "更宜思破釜，莫便欲乘桴。", "豹匪終藏霧，鯨非可在溝。", "此生如富貴，未死合公侯。", "子况才華妙，身兼學業優。", "文章思頓進，志意素加修。", "禹穴書曾探，嵩山澗亦搜。", "紗螢頻見聚，鄰燭屢聞偷。", "默記跡三篋，疏通貫九流。", "賦才肩賈馬，詩格駕曹劉。", "肯向清時廢，須膺紫詔求。", "不當三徑隠，未可五湖遊。"]'),
('f2a6d8a9-9736-4ef7-ab34-8f92e5681a21','傷蔡文仲秋闈失意四十韵','劉弇','宋','宋诗','song-poetry','','[]','側聽秋闈榜，君名又不傳。',288,'全唐诗/poet.song.59000.json','["側聽秋闈榜，君名又不傳。", "病龍頻失水，倦鳥久驚弦。", "有意期行道，無人肯薦賢。", "長沙傷鵩日，西狩獲麟年。", "失意應常理，嗟君最可憐。", "雙親堂上老，三釜養中偏。", "鬚有千莖雪，家無二頃田。", "甑中塵屢起，囊乏磬長懸。", "草木荒三徑，埃氛滿一廛。", "鶉衣傷子夏，蝸舍病焦先。", "雪冷袁安卧，風清靖節眠。", "謾誇五色筆，不及一囊錢。", "抱玉冤誰雪，沉舟恨自牽。", "翼摧雲外鵠，身絆駕頭鸇。", "憤氣高沖斗，悲號下入泉。", "未甘爲敗將，猶擬奮空拳。", "文喪思投筆，膠稀欲絕弦。", "悲彈三尺劍，悶釣五湖船。", "遷擯當修史，雄閑合草玄。", "張衡四愁什，杜甫八哀篇。", "臏刖兵書作，丘窮易道編。", "文人從坎坷，才子本迍邅。", "得失誠由命，窮通莫怨天。", "不須吟澤畔，何用餓山巔。"]'),
('b202c427-18a1-40fa-9d3c-ef12f599706c','傷友人潘鎮之失意七十韵','劉弇','宋','宋诗','song-poetry','','[]','念子多屯躓，秋闈又背馳。',288,'全唐诗/poet.song.59000.json','["念子多屯躓，秋闈又背馳。", "南陽龍卧久，東魯鳳何衰。", "刖足冤誰雪，傷弓翅已垂。", "有文須奪席，無地可容錐。", "破落三間屋，荒凉四壁籬。", "平生萍蕩漾，活計葉離披。", "磬掛囊多乏，塵生甑少炊。", "饑寒妻擬棄，憔悴嫂貽嗤。", "行古時稀合，身孤世早知。", "盡應嫌學僻，無不笑書癡。", "讀已周千卷，攀猶滯一枝。", "鷁因風緊退，蘭爲雪深萎。", "卞璞羞空獻，齊竽嘆失吹。", "未爲橫薦鶚，又作曳泥龜。", "東國頻遭黜，西山獨忍饑。", "皇皇行澤畔，寂寂卧漳湄。", "應下傷麟淚，還牽感鵩悲。", "著成孤憤傳，吟就八哀詩。", "道喪誰開眼，愁來自皺眉。", "迍邅真命也，險阻屢嘗之。", "清廟含三嘆，明時動五噫。", "野歌成匪虎，磯釣本非羆。", "事故多如此，心休苦怨咨。", "都緣名是累，須用道爲醫。"]'),
('6dc6eb44-d095-4fdc-91f0-ee2fd834de17','題仰山二十韵','劉弇','宋','宋诗','song-poetry','','[]','維南斗牛下，萬仞聳崔嵬。',240,'全唐诗/poet.song.59000.json','["維南斗牛下，萬仞聳崔嵬。", "日上光先占，江盤勢却迴。", "一方蒙雨露，幾處對樓臺。", "不逐秦鞭去，曾經禹載來。", "雲生風慘淡，冰泮谷喧豗。", "險外烟嵐變，深中洞府開。", "巖花春灼爍，溪鳥暖毰毸。", "飛瀑含清籟，乖龍走疾雷。", "平川蕭廟閟，半腹鄧壇摧。", "精縕瓊瑰寶，奇鍾杞梓材。", "僧軒宜薜荔，樵徑怯莓苔。", "旁睨龍洲橘，前瞻庾嶺梅。", "仙經饒地脈，賦筆讓天台。", "神物多靈貺，農田少旱災。", "隠居須獨行，吟咏亦難才。", "何客能依止，伊余敢語哉。", "一麾成繫滯，四友阻遊陪。", "未脫紅塵累，徒嗟白髮催。", "夢頻生枕席，賞每倒罇罍。", "預恐瓜時代，圖歸作醉媒。"]'),
('bae53510-44fb-4739-a561-e8a2aea9fe7a','覽唐元成詩因而有贈','劉弇','宋','宋诗','song-poetry','','[]','欲識君詩格，飄然人所難。',48,'全唐诗/poet.song.59000.json','["欲識君詩格，飄然人所難。", "清風生玉宇，白露滴金盤。", "吟嚼充腸冷，披開遶坐寒。", "迥無脂粉氣，字字是琅玕。"]'),
('fa20e6a6-e434-42b1-81fb-75d6c68b2c95','春日舟中即事','劉弇','宋','宋诗','song-poetry','','[]','墨綬蠻鄉去，青春瘴海行。',48,'全唐诗/poet.song.59000.json','["墨綬蠻鄉去，青春瘴海行。", "陋篷愁暴雨，小艇畏長鯨。", "灘惡舟難渡，風狂浪易生。", "不堪江上笛，時送兩三聲。"]'),
('d7b1dc23-7362-44a1-8e52-6d1c4425ba15','讀汪都講邵宮教擬試賦三十韵','劉弇','宋','宋诗','song-poetry','','[]','文效追前日，詞科急俊民。',288,'全唐诗/poet.song.59000.json','["文效追前日，詞科急俊民。", "儒風穆漢殿，家璞走荆珍。", "汪邵推高手，卿雲想後身。", "爭移初律暖，競撥老根陳。", "睥睨三都上，吹噓七子鄰。", "龍蛇開蟄戶，河漢洗天津。", "堂室誰升入，詩書迭主賓。", "剸犀鋒自倍，徹札手彌親。", "鼓吹丘軻外，波瀾屈宋新。", "巴歌徒里耳，燕石謾緹巾。", "美觀圭聯璧，和聲鼓間錞。", "駸駸新歷塊，喔喔舊司晨。", "爽實嗤烏有，阿時陋劇秦。", "鑿愁神秘露，搜恐物華貧。", "楚劍雙干斗，吳娃幾學顰。", "飛揚逼場屋，旁午動簪紳。", "傖父幾焚硯，修家舊有人。", "珠驚對還浦，角豈獨推麟。", "價比千瓊玖，文成一欠呻。", "鼻端論妙斲，使外得周詢。", "布瑞雲歊鼎，連深鯉挂緡。", "豈徒矜羽獵，直可絢郊禋。", "宛是隋唐舊，何分雅頌真。", "兩眸寬病客，一氣到洪鈞。"]'),
('5d843e46-0b2a-472d-a11e-836679bb8aa1','次韵奉酬邵美中奉議示同舍','劉弇','宋','宋诗','song-poetry','','[]','真太忙生苟一時，野情幽事每交馳。',64,'全唐诗/poet.song.59000.json','["真太忙生苟一時，野情幽事每交馳。", "同舟濟者聊傾蓋，吾黨歸歟盍指期。", "風日頻開友顔笑，珠璣間出洗愁詩。", "小儒坐耗大官食，羞學饑猿嗛兩頤。"]'),
('fa00405b-bf92-4d1d-80b7-18dcd611ddb5','覽邵美中擬試賦出詩三十韵紀之邵有詩謝復次其韵','劉弇','宋','宋诗','song-poetry','','[]','重棘初無課最書，春風破卷得三都。',64,'全唐诗/poet.song.59000.json','["重棘初無課最書，春風破卷得三都。", "千尋傑氣千霄上，一片降心免胄趨。", "藏室森羅公柱史，附庸幺麽我顓臾。", "正緣好語遥推借，跋扈猶能特百夫。"]'),
('a4a34f1c-4546-450b-b2d3-498af8613bfb','試院次韵奉酬趙達夫記室惜春之什  其一','劉弇','宋','宋诗','song-poetry','','[]','風酣雨軟裊簷絲，端負吾人痛飲師。',64,'全唐诗/poet.song.59000.json','["風酣雨軟裊簷絲，端負吾人痛飲師。", "使者嶺梅傳信遠，王孫芳草怨歸遲。", "釀成紫府無端夢，開到朱欄第幾枝。", "欲問東君挽流轉，顛狂好在曲江詩。"]'),
('44cd7ab8-87a2-4af4-970e-59b363cf680e','試院次韵奉酬趙達夫記室惜春之什  其二','劉弇','宋','宋诗','song-poetry','','[]','酷愛春如蜂蝶迷，還憂青帝學班師。',64,'全唐诗/poet.song.59000.json','["酷愛春如蜂蝶迷，還憂青帝學班師。", "愁城恨壘挨排到，酒約花期賭當遲。", "端負江湖歸去棹，最關桃李別來枝。", "松丸暖動蟾蠩滴，消殺風光盍付詩。"]'),
('4f9912a7-9497-4713-9e33-494ff6ba2cbe','次韵酬朱充仁示同舍','劉弇','宋','宋诗','song-poetry','','[]','絮撲花然鑰靚深，物華看即滿曾陰。',64,'全唐诗/poet.song.59000.json','["絮撲花然鑰靚深，物華看即滿曾陰。", "魯魚是正成何補，鶑燕勾牽著底禁。", "聲迹汾雎連漢鼎，報投綠綺間南金。", "到家禊事應非晚，孤劍懸知出水心。"]'),
('5a9acb51-0616-40c6-81de-fec18f9bcdee','張壽翁朝散有詩紀同舍名銜錄次其韵','劉弇','宋','宋诗','song-poetry','','[]','柳茸無力杏燒紅，春入愁腸不散窮。',64,'全唐诗/poet.song.59000.json','["柳茸無力杏燒紅，春入愁腸不散窮。", "千佛經慚名姓入，一尊酒愜笑言同。", "寫成懸圃新聯璧，分與秋風舊轉蓬。", "好樣醉鄉拋擲却，百錢輸與杖頭翁。"]'),
('86ccc7ac-aa01-4d96-80ba-e15e246d1ff3','貢院奏號奉呈同舍諸公','劉弇','宋','宋诗','song-poetry','','[]','朝來甲乙去聞天，喜色胚腪淡墨前。',64,'全唐诗/poet.song.59000.json','["朝來甲乙去聞天，喜色胚腪淡墨前。", "干斗已應千劍躍，摶風誰是一鵬騫。", "路歧穩步青霄近，閭里傾心古語傳。", "收拾春光終未晚，爛遊端屬綠衣鞭。"]'),
('c12ea2c0-28ed-4868-ab20-872e0c3b13b7','晉之太博同舍常愴六世外祖鄭氏苗裔中絕曩訪得丘墓所在歲時享祀不輟鄉里化之因有詩紀其事謀弇屬和云','劉弇','宋','宋诗','song-poetry','','[]','綢繆霜露他時感，零落昆雲幾葉孫。',64,'全唐诗/poet.song.59000.json','["綢繆霜露他時感，零落昆雲幾葉孫。", "原上有封吞馬鬣，道邊無石認羊蹲。", "黄粱暗換塵勞世，白草重歸血食魂。", "未論紛紛悲往逝，的應凜凜愧生存。"]'),
('fc6e2952-3bcf-41a4-9a2a-0ebb076ed336','次韵和汪道濟都講惜惜吟','劉弇','宋','宋诗','song-poetry','','[]','溫柔鄉定虛言耳，鑪火功真長物哉。',64,'全唐诗/poet.song.59000.json','["溫柔鄉定虛言耳，鑪火功真長物哉。", "疑別有天春不老，知誰爲雨夜曾來。", "滿移妃子三湯夢，暗奪仙家一息胎。", "燕玉浪傳思暖老，箇中消歇幾沉煤。"]'),
('7f6a7e0f-29d3-4fe1-9b45-d4ee6124bf20','題福州黄蘗山確禪師息老堂','劉弇','宋','宋诗','song-poetry','','[]','頃來法席如師少，老去生涯似此無。',160,'全唐诗/poet.song.59000.json','["頃來法席如師少，老去生涯似此無。", "直寄天年謾龜鶴，聊收化日到桑榆。", "蒼環作抱三臺壯，縞带明空一水紆。", "時拂東齋壞雲衲，更開南粵隠居圖。", "買山支遁初無費，示疾維摩本不徒。", "夜雨龍腥飛別澗，晝烟禽哢落高梧。", "齋餘短捉清生麈，坐久柔團暖稱蒲。", "三樂榮期猶俗物，二毛潘岳信拘儒。", "禪林彪虎新眠熟，覺海烏藤舊攪枯。", "不學昔人悲唾遠，已將茲世脫魚濡。"]'),
('522aa18a-c9b2-4c75-baa6-fa4fb2bef8ac','送林錫遠帳勾罷官北引二首  其一','劉弇','宋','宋诗','song-poetry','','[]','五月角黍江南天，驪駒送客黄金船。',64,'全唐诗/poet.song.59000.json','["五月角黍江南天，驪駒送客黄金船。", "悠悠別思不足道，去去宦情如欲仙。", "青萍由來異死鐵，綠綺未易論膠弦。", "强懷爲君歌短什，壯圖輒勿輕流年。"]'),
('521493dc-881c-490e-8fa2-88671bd48d22','送林錫遠帳勾罷官北引二首  其二','劉弇','宋','宋诗','song-poetry','','[]','由來不敵是清才，尚喜相逢契此懷。',64,'全唐诗/poet.song.59000.json','["由來不敵是清才，尚喜相逢契此懷。", "直把唯阿平笑語，更將爾汝外形骸。", "吾身方愧猿拘檻，君事何疑箭插靫。", "天子聖明思急策，試論弊事决陰霾。"]'),
('2fb79401-314e-4485-9611-7972b0a492c4','招季山還家','劉弇','宋','宋诗','song-poetry','','[]','蕭條門巷未足愧，晼晚歲時胡不歸。',64,'全唐诗/poet.song.59000.json','["蕭條門巷未足愧，晼晚歲時胡不歸。", "綠葵白芋故園老，黄頷赬尾前溪肥。", "浮名莫羨風過耳，久客可憎塵滿衣。", "約君對擁當戶榻，聊割一畝秋蟾輝。"]'),
('2de960ec-101e-41a8-a95a-3b93fc49b470','早發襄邑','劉弇','宋','宋诗','song-poetry','','[]','迢迢汴水吞窈冥，白榆多於天上星。',64,'全唐诗/poet.song.59000.json','["迢迢汴水吞窈冥，白榆多於天上星。", "林梢碎漏月痕白，草頭冷泣螢腰青。", "雲霄九重近在目，鵷鷺百翮誰趨庭。", "雞聲馬蹄正立敵，斷送垢褐疲吾形。"]'),
('9d30d35f-89b0-4023-b582-c9da97513175','夜泊建溪豐樂驛前三首  其一','劉弇','宋','宋诗','song-poetry','','[]','坐看雲葉洗昭回，磴束天仙玉宇開。',64,'全唐诗/poet.song.59000.json','["坐看雲葉洗昭回，磴束天仙玉宇開。", "水染東甌清到骨，客傷南浦釅於醅。", "雪萌正薦澆酲笋，粉色渾藏艷眼梅。", "稍覓暗芳窺熠燿，更從白石認毰毸。"]'),
('4aa82f4e-ea16-448e-90f3-f312addd8ecd','夜泊建溪豐樂驛前三首  其二','劉弇','宋','宋诗','song-poetry','','[]','鬖鬖彪弁吹頹鬢，戢戢懸鶉戒早寒。',64,'全唐诗/poet.song.59000.json','["鬖鬖彪弁吹頹鬢，戢戢懸鶉戒早寒。", "漂泊昔遊堪冷笑，悠颺短夢迫驚湍。", "霜潭傲險蒼虯嘯，月磧牽波翠篠團。", "十載南冠欹一葉，背人功業底無端。"]'),
('894073d3-2b1c-4353-8440-3f940ccde5a1','夜泊建溪豐樂驛前三首  其三','劉弇','宋','宋诗','song-poetry','','[]','溪靈覓罅吹灘聲，削木刺波舟逆行。',64,'全唐诗/poet.song.59000.json','["溪靈覓罅吹灘聲，削木刺波舟逆行。", "問津候館得豐樂，回首洞天無玉清。", "愁看迮纜疊石子，快是隔篷眠水晶。", "兒曹燈間動喜色，甑有滑白長腰粳。"]'),
('9301eb07-c06e-4ef4-bd14-126b46faa7b1','贈邑宰詹志行長官','劉弇','宋','宋诗','song-poetry','','[]','頭骨插犀冰照顔，胸襟元自漲清瀾。',64,'全唐诗/poet.song.59000.json','["頭骨插犀冰照顔，胸襟元自漲清瀾。", "吏歸申午緣無事，民卧田閭識以寬。", "晤語早傾程子蓋，評詩尤逼杜公壇。", "如論妙譽無留賞，合向驍壺作倚竿。"]'),
('01e5bfcf-befd-4fc2-b93c-cc6d9e75612d','清真觀步翠閣','劉弇','宋','宋诗','song-poetry','','[]','飛梯倒插玉螮蝀，危檻別刻青芙蕖。',64,'全唐诗/poet.song.59000.json','["飛梯倒插玉螮蝀，危檻別刻青芙蕖。", "送凉野水舊涵竹，借色春山擬滴裾。", "王喬過鳬可坐揖，蕭史鳴鳳徒紛如。", "眸子欲酸跂予望，弔世清淚橫方諸。"]'),
('75bad7f9-2068-4e6d-8f7b-b62a8cd1dd14','清真觀清軒','劉弇','宋','宋诗','song-poetry','','[]','向背仙宮總闢琳，茲軒仍出古城陰。',64,'全唐诗/poet.song.59000.json','["向背仙宮總闢琳，茲軒仍出古城陰。", "千年曾史長存魄，一片巢由不染心。", "秋闊雨高天洗翳，夜凉風軟月吹金。", "冰壺早訝貯人世，况復隔溪葱蒨深。"]'),
('e22b3a0f-19d4-4efe-9780-0dbeda500f98','清真觀齋軒','劉弇','宋','宋诗','song-poetry','','[]','物理相懸能幾何，是非得喪了無多。',64,'全唐诗/poet.song.59000.json','["物理相懸能幾何，是非得喪了無多。", "仙家日月閑庭戶，人世浮沉寄唯阿。", "矗橚曉聲來雜珮，漣漪春脈漲青羅。", "箇中故有天倪在，持語流光任擲梭。"]'),
('64103711-43b7-423a-8853-70d6bfd19886','月波樓','劉弇','宋','宋诗','song-poetry','','[]','玉魄冰魂萬頃連，曲欄仍在斗魁邊。',64,'全唐诗/poet.song.59000.json','["玉魄冰魂萬頃連，曲欄仍在斗魁邊。", "浮天自作通津去，洗客終疑爽氣偏。", "不比尋常閑水墨，最宜三五好嬋娟。", "翬飛穩蘸明河接，更擬憑虛逼島仙。"]'),
('e8991bda-0670-4eed-ac3a-1d7c34f31c4d','賀氏怡軒','劉弇','宋','宋诗','song-poetry','','[]','盤薄簷牙紫翠間，正緣天屬得恬安。',64,'全唐诗/poet.song.59000.json','["盤薄簷牙紫翠間，正緣天屬得恬安。", "已聞名教兼三樂，况有家聲到二難。", "棠棣萼留春色好，鶺鴒原占洞天寬。", "友于誰復知真適，拾穗榮期似太漫。"]'),
('3b1374bf-ff8e-4b14-a7f4-974da9cc3932','建德縣作','劉弇','宋','宋诗','song-poetry','','[]','銅官南部號無事，烟火蕭條數百家。',64,'全唐诗/poet.song.59000.json','["銅官南部號無事，烟火蕭條數百家。", "令尹印章希搭紙，里胥邦賦半催茶。", "山稠別限番君國，潦暗疑通海客槎。", "石磴落當蕭寺面，憐渠清絕好生涯。"]'),
('5bf0722c-7647-438f-91cd-9ee2684df1d7','新開湖詩  其一','劉弇','宋','宋诗','song-poetry','','[]','輸寫由來未易窮，渾疑天作水仙宮。',64,'全唐诗/poet.song.59000.json','["輸寫由來未易窮，渾疑天作水仙宮。", "浩無邊際藍吞野，散作霑濡雨卷空。", "末口潦收秋漲縮，汙溝波泛暮潮通。", "會當揮楫乘高興，盡把塵纓濯此中。"]'),
('2a047fe5-47f5-4fdd-8ec1-8ed1cef7c636','新開湖詩  其二','劉弇','宋','宋诗','song-poetry','','[]','平鋪縐縠幾千尋，瀟洒由來爽客襟。',64,'全唐诗/poet.song.59000.json','["平鋪縐縠幾千尋，瀟洒由來爽客襟。", "天借月華來海上，地蒸雲氣出波心。", "魚蝦澤國拋殘玉，燈火船窗點碎金。", "聞說蚌胎無纇顆，又憑風力舞秋陰。"]'),
('f3f9d3ec-1e9d-491a-97d1-5ecdcbf8757f','送廷允决曹解官舟行赴闕    其一','劉弇','宋','宋诗','song-poetry','','[]','由來佳掾推三語，故有能名擅一方。',64,'全唐诗/poet.song.59000.json','["由來佳掾推三語，故有能名擅一方。", "投分稠人期李郭，平心他日到于張。", "囹扉盡洗沉冤魄，貫索時分入夜光。", "舉世謾嗟岐路澀，只今騰踏見飛黄。"]'),
('b071bc1f-5683-4a01-9990-361945a1acd7','送廷允决曹解官舟行赴闕    其二','劉弇','宋','宋诗','song-poetry','','[]','春江活碧染衣濃，鬧櫓初挨鷁首東。',64,'全唐诗/poet.song.59000.json','["春江活碧染衣濃，鬧櫓初挨鷁首東。", "岸柳躍絲金稍重，渚梅收糝玉全空。", "腐儒糟粕迂疏後，上客風雲感慨中。", "好訪瀛洲綴仙客，家山無苦夢壺公。"]'),
('6de87ad0-ef07-4de3-af2b-036c89ca669b','次韵酬','劉弇','宋','宋诗','song-poetry','','[]','束書歸伴鶴頭遊，贏得髭根未雪如。',64,'全唐诗/poet.song.59000.json','["束書歸伴鶴頭遊，贏得髭根未雪如。", "春甽有田皆杜鄠，曉窗無岫不衡廬。", "糟床最與天真近，魚沫何妨世態疏。", "鞹足龜腰負芝朮，因君特地愧三餘。"]'),
('7649a750-2b64-4dba-84f7-7e64d48e8d21','次韵表民偶作','劉弇','宋','宋诗','song-poetry','','[]','紛紛儀覆與秦傾，何者竟爲吾道行。',64,'全唐诗/poet.song.59000.json','["紛紛儀覆與秦傾，何者竟爲吾道行。", "物外金朱猶土梗，興來詩酒亦功名。", "夢同秋棧縈紆入，分比春蘭馥郁生。", "他日未宜輕感慨，勸人歸是子規聲。"]'),
('1dfe7c73-61d0-426b-b84e-11812620783c','贈致政曾宣德十二韵','劉弇','宋','宋诗','song-poetry','','[]','自得逍遥物外情，肯將冠冕謾勞形。',192,'全唐诗/poet.song.59000.json','["自得逍遥物外情，肯將冠冕謾勞形。", "門前始種先生柳，斗下重添處士星。", "文豹霧中誰逐逐，飛鴻天外自冥冥。", "最憐孤竹人高卧，却訝三閭客獨醒。", "放曠七賢林下洞，棲遲六逸水邊亭。", "和烟買得花栽潤，带雨移來藥顆馨。", "鳬舄印殘蒼蘚綠，蝸廬築破遠山青。", "消磨日月棋千局，笑傲雲霞酒一瓶。", "隠几旋成招隠句，披衣新看養生經。", "小軒靜把琴開匣，幽苑深將鶴剪翎。", "明月有時來竹塢，紅塵無路到松扃。", "幾多九老圖中景，都爲丹青入障屏。"]'),
('9965af16-c395-45a5-919b-2b31420c6edb','上金陵黄尚書安中二首  其一','劉弇','宋','宋诗','song-poetry','','[]','南來踽踽拜前塵，雅睠仍從轍鮒新。',64,'全唐诗/poet.song.59000.json','["南來踽踽拜前塵，雅睠仍從轍鮒新。", "四照色溫初似玉，一時恩到總成春。", "非如學者論糟粕，須信人間得鳳麟。", "况有珠璣長滿把，冥搜終恐物華貧。"]'),
('443608ab-e595-484e-ba93-6795596890c5','上金陵黄尚書安中二首  其二','劉弇','宋','宋诗','song-poetry','','[]','千毫回斡自無旁，逸勁仍聞飲石梁。',64,'全唐诗/poet.song.59000.json','["千毫回斡自無旁，逸勁仍聞飲石梁。", "黄卷素心因事見，空門真味與閒長。", "扁舟尚錄袁臨汝，清酒無論顧建康。", "五載轉頭歸一瞬，門闌依舊笑羝羊。"]'),
('42d97899-4d59-4b61-8b06-95a2f975d0c5','和安中東樓會飲','劉弇','宋','宋诗','song-poetry','','[]','岧嶢飛觀决層雲，主意全傾合坐賓。',64,'全唐诗/poet.song.59000.json','["岧嶢飛觀决層雲，主意全傾合坐賓。", "談笑龍岡下白日，衣冠麟閣識功臣。", "欲窮人目逢山好，未老秋容到酒醇。", "忍對南鴻問寥廓，沉冥誰是蜀莊珍。"]'),
('cd63eb19-b35e-4675-9d41-60437fefec45','和安中鐵柱留題','劉弇','宋','宋诗','song-poetry','','[]','隠然平地起嶙峋，千古舂波此與瀕。',64,'全唐诗/poet.song.59000.json','["隠然平地起嶙峋，千古舂波此與瀕。", "九牧貢金殊夏后，三泉下錮笑秦人。", "力回坤軸陰機壯，妙灑銀鈎榜墨新。", "欲識當年鎔鑄意，莽蘆終恐更非真。"]'),
('8351d749-18c5-42f6-a83c-ea9bb3714f4b','王公濟四美樓','劉弇','宋','宋诗','song-poetry','','[]','寸心不與一物隔，遠目自爲千里期。',64,'全唐诗/poet.song.59000.json','["寸心不與一物隔，遠目自爲千里期。", "便共溪山有情分，更緣阡陌識參差。", "層雲異日雖輕舉，獨鳥長年可俯窺。", "緹騎到家春滿眼，庾公清興不應衰。"]'),
('30795837-3c7e-4d1b-b113-f8f26c0a2894','王公濟蘭荄亭','劉弇','宋','宋诗','song-poetry','','[]','閭里傳驚飽物華，此亭真是一生涯。',64,'全唐诗/poet.song.59000.json','["閭里傳驚飽物華，此亭真是一生涯。", "人知菽水歡終異，地比蓬蒿徑自佳。", "歲計黄雲千䆉稏，春心青玉幾龍蛇。", "不須分外開新畹，故有兒孫敵謝家。"]'),
('62a8d148-e41e-4aea-a2f4-1582c88a5558','李倅惠詩次元韵酬謝','劉弇','宋','宋诗','song-poetry','','[]','寸毫揮灑敵連城，想見仙標白玉京。',64,'全唐诗/poet.song.59000.json','["寸毫揮灑敵連城，想見仙標白玉京。", "周鼓直須論妙刻，陶琴初不費煩聲。", "他年浪許曾窺豹，此日誰堪與濯纓。", "寂寞蓬茨今有助，病軀那復愧登瀛。"]'),
('c3437757-0acc-4a26-b8bb-b2a9939d3a65','再次韵和酬','劉弇','宋','宋诗','song-poetry','','[]','俗眼紛紛少得青，獨君襟義富坻京。',64,'全唐诗/poet.song.59000.json','["俗眼紛紛少得青，獨君襟義富坻京。", "揮斤郢鼻時驚巧，持鼓雷門浪費聲。", "正喜珠璣生咳唾，敢期茅蕝被游纓。", "鯫生謭謭難論報，此日方知海是瀛。"]'),
('4e8f7bc9-8641-4f47-8da7-6738d19e2626','九曲池','劉弇','宋','宋诗','song-poetry','','[]','昔帝檣烏下日邊，曾留清蹕此蹁躚。',64,'全唐诗/poet.song.59000.json','["昔帝檣烏下日邊，曾留清蹕此蹁躚。", "魚龍窟暗浮春漲，鳬雁行低破暝烟。", "星閣摧頹空歲月，蕪城埋沒舊山川。", "後庭一曲陳家破，更看當年水調傳。"]'),
('683bb590-3804-4375-8c67-04e4725d0961','搘筇','劉弇','宋','宋诗','song-poetry','','[]','蹭蹬年來誰寄聲，靜搘筇竹了無營。',64,'全唐诗/poet.song.59000.json','["蹭蹬年來誰寄聲，靜搘筇竹了無營。", "照衣簷竹露逼冷，過耳海潮風送清。", "豈有稻粱驕雀鼠，終慚醅酒費瓶罌。", "請纓自是男兒事，咄咄胡爲過半生。"]'),
('c9296a81-c2fc-4ddb-b30d-c99559b6a507','和重陽感懷','劉弇','宋','宋诗','song-poetry','','[]','又逢佳節破牢愁，天卷微雲盡放秋。',64,'全唐诗/poet.song.59000.json','["又逢佳節破牢愁，天卷微雲盡放秋。", "一水孤飛臨汝槳，幾人清興庾公樓。", "螢腰亂試林塘點，蠅陣微收几案稠。", "黄菊紅萸滿烏帽，椒丘誰是醉鄉謀。"]'),
('42220c82-e859-40a6-9467-cb459f603f23','次韵酬錫遠孤坐有懷','劉弇','宋','宋诗','song-poetry','','[]','白簡差差長蠹魚，强顔那復計三餘。',64,'全唐诗/poet.song.59000.json','["白簡差差長蠹魚，强顔那復計三餘。", "長波不洗客愁去，脫葉似將官况疏。", "行樂醉鄉金欲盡，投身老境歲還除。", "因持舊史論窗燭，大半功名不是書。"]'),
('0ea0b905-6e3c-4840-9c8e-578c2ca18a42','次韵和劉次公以詩見贈','劉弇','宋','宋诗','song-poetry','','[]','格老辭嚴趣復新，百篇洗眼盡驚人。',64,'全唐诗/poet.song.59000.json','["格老辭嚴趣復新，百篇洗眼盡驚人。", "喑嗚自是東騷將，瀟洒疑非閥閱身。", "快甚天星秋炯炯，富於倉廩昔陳陳。", "終慚不敵齊呀喊，敢議肴羞與栗榛。"]'),
('446f0a10-720c-416e-9c48-3582a0874415','寄兜率悅禪師二首  其一','劉弇','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','三峽當年一錫飛，祖燈曾是密傳西。',64,'全唐诗/poet.song.59000.json','["三峽當年一錫飛，祖燈曾是密傳西。", "示徒端的只消指，灌頂分明別有醍。", "秋衲擁雲驚曉榻，病髭鑷雪照寒溪。", "知誰解吸西江水，頼有孤禪覺衆迷。"]'),
('0b08e298-6084-4f8b-996a-7a44cbf6580e','寄兜率悅禪師二首  其二','劉弇','宋','宋诗','song-poetry','','[]','箯輿曾約下山顔，白足塵緣等是慳。',64,'全唐诗/poet.song.59000.json','["箯輿曾約下山顔，白足塵緣等是慳。", "貪爲水雲留物外，劣容紙墨到人間。", "銀潢一掬愁枯肺，金鑰千重想上關。", "病客此身似籠鳥，何時毳衲對斕斑。"]'),
('040817a3-aa4b-4571-a52e-eddff673ebc7','次韵酬何伯修見貽','劉弇','宋','宋诗','song-poetry','','[]','學非歆向擅家聲，僮指仍慚左蜀程。',64,'全唐诗/poet.song.59000.json','["學非歆向擅家聲，僮指仍慚左蜀程。", "夢月自憐名舊識，屠龍何補技先成。", "悲纏風樹新創鉅，心折家園獨鳥驚。", "樵斧漁竿有真趣，不應鄰叟怪逃名。"]'),
('03398deb-ba39-4130-9b04-73d78416c9a1','次韵酬何伯修','劉弇','宋','宋诗','song-poetry','','[]','廣場較藝號肩摩，筆挫千人敏若梭。',64,'全唐诗/poet.song.59000.json','["廣場較藝號肩摩，筆挫千人敏若梭。", "共喜此聲傳烜赫，直應無物避爬羅。", "雅音尚汩多哇鄭，荆璞誰收屢獻和。", "洗眼今看色絲語，快於執熱濯東波。"]'),
('6eca7729-6043-40a3-8ec9-aa53c2d1bc00','次韵酬譚履常送致政徐朝奉','劉弇','宋','宋诗','song-poetry','','[]','拔迹朝閨太早生，不容餘藴付功名。',64,'全唐诗/poet.song.59000.json','["拔迹朝閨太早生，不容餘藴付功名。", "肯緣簪紱重回首，似共林塘別有情。", "恰恰冥鴻如素志，來來弊屣薄浮榮。", "留貲無有公何恃，贏得桑榆慰此行。"]'),
('f3d7ff54-558d-4f71-b0ce-3d5256798fea','王適中渝飲約以詩招之','劉弇','宋','宋诗','song-poetry','','[]','別君倒指倏旬日，顧我搖心如旆旌。',64,'全唐诗/poet.song.59000.json','["別君倒指倏旬日，顧我搖心如旆旌。", "滿引未應勤上客，高談聊欲破勞生。", "望梅終恐難酬渴，挹露懸知別得清。", "咫尺履綦猶惜到，可能無復故人情。"]'),
('407f0b9e-e49a-478d-97c9-e09d77c6aa88','送致政吳通直','劉弇','宋','宋诗','song-poetry','','[]','黑頭貪作隠中仙，高謝清時五兩綸。',64,'全唐诗/poet.song.59000.json','["黑頭貪作隠中仙，高謝清時五兩綸。", "物外收將閒日月，人間歸去好溪山。", "二疏等作揮金計，五柳猶遲倦鳥還。", "多少有車懸不得，規規鐘漏亦胡顔。"]'),
('1e568d1e-73ba-4634-87da-4b3536389e75','謝何舜庸見借畫舫還鄉','劉弇','宋','宋诗','song-poetry','','[]','好樣江邊青雀𦨵，愧君暫借不相妨。',64,'全唐诗/poet.song.59000.json','["好樣江邊青雀𦨵，愧君暫借不相妨。", "帆檣縹緲青天近，窗戶玲瓏白日長。", "濃綠迢迢春到水，衰顛種種客還鄉。", "却應耆舊遥知羨，况味渾如臨汝郎。"]'),
('d1ee1bbf-352e-41d4-b0a1-3167052f20d5','次韵奉酬何舜庸寄酒','劉弇','宋','宋诗','song-poetry','','[]','寄來何啻十千價，置處曾非六一身。',64,'全唐诗/poet.song.59000.json','["寄來何啻十千價，置處曾非六一身。", "自慚無足斗筲算，暫見已覺神形親。", "他年換得青田核，此日吹回紫府春。", "翦却愁根真外助，不妨功勝齒亡脣。"]'),
('a9b7ab74-7af6-413b-aa5a-24a2716b500c','贈致政李元古二首  其一','劉弇','宋','宋诗','song-poetry','','[]','膴仕委蛇四十秋，翻然歸作赤松遊。',64,'全唐诗/poet.song.59000.json','["膴仕委蛇四十秋，翻然歸作赤松遊。", "無瑕舊是千金璧，不繫今如一葉舟。", "舉世風霜空末路，此身芝朮最良謀。", "新篇晚更追騷雅，何計從公乞愈頭。"]'),
('f92c7468-1b35-412a-8d41-aacc51a35a40','贈致政李元古二首  其二','劉弇','宋','宋诗','song-poetry','','[]','興味高於鶴在雲，去留初不掛毫分。',64,'全唐诗/poet.song.59000.json','["興味高於鶴在雲，去留初不掛毫分。", "鄭公鄉里新門巷，謝氏芝蘭好子孫。", "瀟洒笑談寬日月，優游在世傲乾坤。", "鄰翁盛說歸歟美，曾是當年朱兩轓。"]'),
('1011ad13-6aaa-4934-b73e-c7cf4000f245','贈吳伯玉二首  其一','劉弇','宋','宋诗','song-poetry','','[]','少年騰踏屬驊騮，骨相疏明玉照秋。',64,'全唐诗/poet.song.59000.json','["少年騰踏屬驊騮，骨相疏明玉照秋。", "湓口猶傳舊令尹，豫章聊半古諸侯。", "一官身外真無負，百故胸中自不留。", "論薦由來公道在，誰將卓犖到需頭。"]'),
('1e4bcaac-95ef-4339-b2e2-648819a30c7e','贈吳伯玉二首  其二','劉弇','宋','宋诗','song-poetry','','[]','瞥去門闌兩換春，標規仍愜此來親。',64,'全唐诗/poet.song.59000.json','["瞥去門闌兩換春，標規仍愜此來親。", "能將官况爲餘事，別有陽和到後塵。", "衮衮何妨流水淡，紛紛誰數白頭新。", "擬論一報歸恩地，愧我猶爲欒棘人。"]'),
('9eccd7b8-0e68-473f-baeb-52971ce2750b','羅漢系南長老','劉弇','宋','宋诗','song-poetry','','[]','諸方喉舌卷舂容，直指慈幢信長雄。',64,'全唐诗/poet.song.59000.json','["諸方喉舌卷舂容，直指慈幢信長雄。", "翳盡全開捫海月，清多平挹洗天風。", "相望震旦傳衣後，別寄西兒妙斲中。", "好把沃洲論五老，囅然重此得支公。"]'),
('eb3793da-dabd-4117-bb9e-169f834e5646','送螺川張太守二首  其一','劉弇','宋','宋诗','song-poetry','','[]','西南五馬照青螺，衆惜班春未幾何。',64,'全唐诗/poet.song.59000.json','["西南五馬照青螺，衆惜班春未幾何。", "綠髮桑榆收太早，青雲岐路剩來多。", "仙家職事清閒好，逋客林泉取次過。", "正恐此身休不得，再看鄒律起陽和。"]'),
('a557baa8-0960-4540-9858-541181831636','送螺川張太守二首  其二','劉弇','宋','宋诗','song-poetry','','[]','凉颸一水漾清虛，畫鷁翩翩北去初。',64,'全唐诗/poet.song.59000.json','["凉颸一水漾清虛，畫鷁翩翩北去初。", "暫把壯圖收紱冕，只留和氣到閻閭。", "海邊有夢通琳闕，物外無心挂隼旟。", "寄語琅琊好泉石，使君不是賦歸歟。"]'),
('904dae6e-9ec5-4335-badc-218bc18481c0','和吳伯玉九日同會','劉弇','宋','宋诗','song-poetry','','[]','上林曾共見鶑遷，五百英豪氣戾天。',64,'全唐诗/poet.song.59000.json','["上林曾共見鶑遷，五百英豪氣戾天。", "鬭在並存嗟白髮，成空半已鎖黄泉。", "菊花酩酊同今日，桂籍風流記舊年。", "愧辱新詩無以報，誤煩褒筆比青錢。"]'),
('aaf61b37-6857-48e8-b96f-042190ce415d','次韵酬張商佐','劉弇','宋','宋诗','song-poetry','','[]','跧迹青綸木不春，洗君眉宇海津津。',64,'全唐诗/poet.song.59000.json','["跧迹青綸木不春，洗君眉宇海津津。", "江湖隔闊青螺夢，歲月飄零北固身。", "俯仰未應羞彼俗，漱銜仍喜屬吾人。", "嚼螯擘殻懷哉樂，又作秋風一笑新。"]'),
('db1e97af-65ac-4523-866b-e18a5cb2367c','清凉法和禪師','劉弇','宋','宋诗','song-poetry','','[]','東南誰是識彌天，覺海烏藤攪欲乾。',64,'全唐诗/poet.song.59000.json','["東南誰是識彌天，覺海烏藤攪欲乾。", "金色髯耏飛妙吼，雲間頭角傲秋蟠。", "觚稜勢逼嶙峋去，杖屨陰回矗櫹寬。", "十載洒然重洗我，一襟通底是清瀾。"]'),
('bf86ff4f-2679-49ec-a764-32ba57155b48','陪王純父燕歷陽連雲觀','劉弇','宋','宋诗','song-poetry','','[]','天門直北八公西，杏栱梅梁脫蔽虧。',64,'全唐诗/poet.song.59000.json','["天門直北八公西，杏栱梅梁脫蔽虧。", "金葉卷空飛鳥影，冰紈浮入茂林姿。", "裁雲麗服淮娥踏，熨齒紋綫楚客辭。", "十二玉簾渾軸水，瘦龍捎月叫參差。"]'),
('0e135895-4e67-4837-b8a7-b1ceac08add9','江館三首  其一','劉弇','宋','宋诗','song-poetry','','[]','山川定出書意外，魚鳥自閑眠對時。',64,'全唐诗/poet.song.59000.json','["山川定出書意外，魚鳥自閑眠對時。", "艇子黏天歸一葉，濤頭吹雨落千麾。", "截波尚欲論孤劍，應客初慚乏大兒。", "聽得漁郎隔溪語，夜來秋色暗江蘺。"]'),
('a62045ef-751d-4396-9c75-3f51a522fb11','江館三首  其二','劉弇','宋','宋诗','song-poetry','','[]','無塵一境好仙去，有夢九秋應鶴知。',64,'全唐诗/poet.song.59000.json','["無塵一境好仙去，有夢九秋應鶴知。", "弱篠嬋娟藏別塢，野葒高下補疏籬。", "秫田百畝堪供酒，膾手千刀間憶鯔。", "未愧鏡湖誇賀監，聊將星管覓桓伊。"]'),
('1c2b849b-a046-40f9-a5c3-74689c23d5c7','江館三首  其三','劉弇','宋','宋诗','song-poetry','','[]','連雲草樹縱橫幕，點水鳬鷗黑白棋。',64,'全唐诗/poet.song.59000.json','["連雲草樹縱橫幕，點水鳬鷗黑白棋。", "日晏厨烟青一穗，暑餘窗雨暗千絲。", "飽聞楊惲生行樂，懶賦張衡我所思。", "軟碧會須連月占，恣看飛檝界琉璃。"]'),
('898892db-74ab-4587-a19d-55f8e15994f4','贈高郵尉郭奉世','劉弇','宋','宋诗','song-poetry','','[]','好樣仙曹斗野西，不將顔色傍人低。',64,'全唐诗/poet.song.59000.json','["好樣仙曹斗野西，不將顔色傍人低。", "由來胸腹開濛汜，故有篇章照黑蹏。", "采捧掛門虛晝警，鴟夷浮客趁秋躋。", "風胡去世純鉤蟄，誰取吹毛瑩鸊鵜。"]'),
('f9acaa78-fab3-4f2f-9fd8-44bca7f774ae','靈鷲寺','劉弇','宋','宋诗','song-poetry','','[]','蠹粉侵侵抱繚牆，佛祠仍是舊仙鄉。',64,'全唐诗/poet.song.59000.json','["蠹粉侵侵抱繚牆，佛祠仍是舊仙鄉。", "晴雷殷地溪聲轉，頑橐吞空洞脈長。", "旦過客分雲卧冷，臘高僧煮澗毛香。", "須知剩得天龍護，別繞森嚴十萬岡。"]'),
('fcb58544-6973-4557-936e-b36f10ba177f','光相洞','劉弇','宋','宋诗','song-poetry','','[]','仙客當年蛻塵土，洞天此地老烟霞。',64,'全唐诗/poet.song.59000.json','["仙客當年蛻塵土，洞天此地老烟霞。", "頃來雞犬如無跡，裏許山川別是家。", "遼海不歸千歲鶴，武陵頻換一番花。", "可能匕上胡麻飯，變得勞生兩鬢華。"]'),
('9c1f4001-4a73-4c7a-927e-0a04adb58eb2','自竹巖至杉溪','劉弇','宋','宋诗','song-poetry','','[]','曉尋葱蒨踏頑雲，越俗閩風雜楚民。',64,'全唐诗/poet.song.59000.json','["曉尋葱蒨踏頑雲，越俗閩風雜楚民。", "天窄定藏巫峽雨，溪深疑有武陵春。", "驅寒萬籟爭奔壑，競秀千峰自逼人。", "斷送殘年歸馬首，却羞頭著故綸巾。"]'),
('f5380586-7c92-49c7-82fc-5674d6018ee7','送狄太守清明日燕莆田共樂亭三首  其一','劉弇','宋','宋诗','song-poetry','','[]','青幢翠葆抱參差，浮客黄金鑿落暉。',64,'全唐诗/poet.song.59000.json','["青幢翠葆抱參差，浮客黄金鑿落暉。", "一日山川如得主，兩眸天地不藏機。", "華胥有國真稀闊，齊物名篇孰是非。", "澀道直西暄絳蠟，卷空簫鼓使君歸。"]'),
('47e11fb5-caf9-4857-bb4c-b27fb6a98959','送狄太守清明日燕莆田共樂亭三首  其二','劉弇','宋','宋诗','song-poetry','','[]','赤白觚稜插戾翰，東南重此識多盤。',64,'全唐诗/poet.song.59000.json','["赤白觚稜插戾翰，東南重此識多盤。", "起從海若三山外，分得壺公一境寬。", "世事升沉隨過鳥，物情瀟洒屬層巒。", "畫圖恐是天拋擲，乞與莆人恣展看。"]'),
('9a1f4d2a-8dad-4be0-8a42-ac6b9ab6a408','送狄太守清明日燕莆田共樂亭三首  其三','劉弇','宋','宋诗','song-poetry','','[]','他年勝踐歸林記，大半豪誇落蔡篇。',64,'全唐诗/poet.song.59000.json','["他年勝踐歸林記，大半豪誇落蔡篇。", "快甚躍壺窺日月，淚疑枯海變桑田。", "觥船照客吹紅液，軒檻嬌春撲紫烟。", "到得無雲剩寥廓，此身仍在鳥飛邊。"]'),
('4e5bece0-633e-4ad4-a4ab-22851473bc6c','宿泗洲院','劉弇','宋','宋诗','song-poetry','','[]','羸驂戢束來閩嶺，晚歲崢嶸宿泗洲。',64,'全唐诗/poet.song.59000.json','["羸驂戢束來閩嶺，晚歲崢嶸宿泗洲。", "一縷蟬聯通鳥道，萬鞓層疊掛民疇。", "林標入夜梢雲梵，暖色先春動毳裘。", "誰把地祇金鏁掣，踏開行客古今愁。"]'),
('9abd711b-abb3-486c-85d0-f2454c061604','建州試院次韵和林原叔監試','劉弇','宋','宋诗','song-poetry','','[]','鷺袍粉白筆摩秋，餘地爭看衆刃游。',64,'全唐诗/poet.song.59000.json','["鷺袍粉白筆摩秋，餘地爭看衆刃游。", "堅壁頼公專細柳，得壺如我愧中流。", "僕姑此日先穿札，綠綺何心曉報鏐。", "恰恰豐隆通蟄戶，論功相與副旁求。"]'),
('6ab81181-122e-4420-8c16-78256488ed23','出試院次韵和酬鄭通直二首  其一','劉弇','宋','宋诗','song-poetry','','[]','吏役區區病足酸，愁聞三十六盤山。',64,'全唐诗/poet.song.59000.json','["吏役區區病足酸，愁聞三十六盤山。", "偶從物外抽身去，又作人間行路難。", "主意十分濃似酒，客心一縷急於灘。", "夜光莫道無因至，乞與扁舟洗眼看。"]'),
('e7e6d084-218a-4320-9cce-56ad6ded2a0b','出試院次韵和酬鄭通直二首  其二','劉弇','宋','宋诗','song-poetry','','[]','百粵東頭倦客身，秋風溪鱠正堪論。',64,'全唐诗/poet.song.59000.json','["百粵東頭倦客身，秋風溪鱠正堪論。", "塵埃洗盡生風語，粉黛仍傳到手罇。", "吹劍自應超世味，曳裾誰復羨侯門。", "臨流更擬張胸膽，終恐精微未易言。"]'),
('469309fd-06d1-409d-912a-49c960f4de0f','芝山','劉弇','宋','宋诗','song-poetry','','[]','當年曾此爛芝英，山半樓臺矗化成。',64,'全唐诗/poet.song.59000.json','["當年曾此爛芝英，山半樓臺矗化成。", "一點有情懸客望，三休疑路與雲平。", "冷吹蘿蔓陰晴變，景落魚龍窟穴清。", "擬禿謝公前却屐，生憎併日計江程。"]'),
('372737f2-144f-41d6-bd6c-c0d850f47277','澄心亭','劉弇','宋','宋诗','song-poetry','','[]','心本虛明亭更幽，亭澄心外復何求。',64,'全唐诗/poet.song.59000.json','["心本虛明亭更幽，亭澄心外復何求。", "高堂掛鏡來斯照，素月流天翳盡收。", "道力定僧堪默對，我忘吟客快冥搜。", "風痕不動玻璃軟，十萬人家一色秋。"]'),
('cc0fef03-181b-45b4-9bd5-b2c2c4b6a1c1','贈饒倅陳伯模朝奉二首郡事  其一','劉弇','宋','宋诗','song-poetry','','[]','畫戟東南第一州，番君斥大漢家侯。',64,'全唐诗/poet.song.59000.json','["畫戟東南第一州，番君斥大漢家侯。", "王祥別乘開風采，顔駟潜郎識滯留。", "投缿里豪空兩獄，發硎刀刃失全牛。", "昨聞鈴閣仍豐暇，身卧雲濤最上頭。"]'),
('19f75dbe-d97e-448f-960c-0af7df4fb3cd','贈饒倅陳伯模朝奉二首郡事  其二','劉弇','宋','宋诗','song-poetry','','[]','早窺安定先生奧，晚刻慈恩塔下名。',48,'全唐诗/poet.song.59000.json','["早窺安定先生奧，晚刻慈恩塔下名。", "宜有璽書旌治狀，飽聞玉筍數門生。", "紙翔市價抄書癖，壇逼詩流覓句精。"]'),
('11546594-291c-44fb-8120-dd8c5fedded1','次韵陳伯模見贈之什','劉弇','宋','宋诗','song-poetry','','[]','秀語驚人自昔年，津涯今見浩無邊。',64,'全唐诗/poet.song.59000.json','["秀語驚人自昔年，津涯今見浩無邊。", "情逾玉璧虞卿贈，味賽鮧魚宋帝便。", "易駟始慚中且下，鏖兵信是一當千。", "端應消得鄉閭賀，橐楮新藏朱鷺篇。"]'),
('f29b1c12-5c4f-40ec-9b3b-7aa1a8e0fc22','白鷺亭逢胡仙尉晉侯二首  其一','劉弇','宋','宋诗','song-poetry','','[]','漲天絲雨欲肥梅，江上相逢秀色開。',64,'全唐诗/poet.song.59000.json','["漲天絲雨欲肥梅，江上相逢秀色開。", "白髮十年歸夢寐，青衫一笑洗塵埃。", "雲邊活碧山圍健，汀末疏明鳥陣回。", "獨向稠人見高義，此情須敵萬瓊瑰。"]'),
('32e605e6-fd62-4462-aae3-2da23629788a','白鷺亭逢胡仙尉晉侯二首  其二','劉弇','宋','宋诗','song-poetry','','[]','老雄冠距舊鳴將，他日文闈果擅場。',64,'全唐诗/poet.song.59000.json','["老雄冠距舊鳴將，他日文闈果擅場。", "聊佐縣章紆墨綬，飽聞家學富青緗。", "占春桃李須慚早，駐日桑榆自審長。", "流水高山空逼耳，有誰論列到需章。"]'),
('c4580d08-ec63-43f9-a629-55349fa0d2d5','過合肥會黄天倪','劉弇','宋','宋诗','song-poetry','','[]','白狼峰頂共留連，一紀于茲剩四年。',64,'全唐诗/poet.song.59000.json','["白狼峰頂共留連，一紀于茲剩四年。", "事過已如炊黍夢，鬢催難著買春錢。", "飄零慚說相思駕，淚落仍傳到手篇。", "梨栗果盤魚蟹飣，怳疑身世上通川。"]'),
('06e2232b-5116-43b8-8f4e-8e654adb8a42','上王提刑二首  其一','劉弇','宋','宋诗','song-poetry','','[]','峨峨名節重於山，舊作朝廷耳目官。',64,'全唐诗/poet.song.59000.json','["峨峨名節重於山，舊作朝廷耳目官。", "鳳闕幾聞隨仗入，龍顔曾許捲簾看。", "昔年白筆驚人凜，今日清風過嶺寒。", "直指近來新有例，出疆回使侍金鑾。"]'),
('5627426b-444e-4af8-8adf-9bd7ad1d0e83','上王提刑二首  其二','劉弇','宋','宋诗','song-poetry','','[]','獬豸冠中筆罷簪，却乘驄馬出駸駸。',64,'全唐诗/poet.song.59000.json','["獬豸冠中筆罷簪，却乘驄馬出駸駸。", "手提國憲風霜重，口布王言雨露深。", "古劍夜光衝斗氣，甘棠春有遶庭陰。", "澄清好把冰壺水，洗却天涯濫濁心。"]'),
('1ae41524-2a2e-46f5-95a0-9cbd63ba277e','贈致政劉大夫','劉弇','宋','宋诗','song-poetry','','[]','一章飛達九重天，求解黄堂石二千。',64,'全唐诗/poet.song.59000.json','["一章飛達九重天，求解黄堂石二千。", "甘守綠園三畝宅，肯貪紅藥八花磚。", "利名擺去灰心定，功行修來月性圓。", "尤喜掛冠歸第後，生涯非欠買山錢。"]'),
('37919144-f865-46c8-b305-388538c3057a','贈連州致政蔡宣德','劉弇','宋','宋诗','song-poetry','','[]','挂冠歸慕赤松遊，不羨金門萬戶侯。',64,'全唐诗/poet.song.59000.json','["挂冠歸慕赤松遊，不羨金門萬戶侯。", "一枕清風三徑曉，滿船明月五湖秋。", "冥冥宛若高飛雁，泛泛渾如不繫舟。", "幾向夜深南極望，老人星見照連州。"]'),
('aa716a08-926f-445c-9a7e-8f5979f4f2b7','贈致政曾宣德','劉弇','宋','宋诗','song-poetry','','[]','何得清時便挂冠，歸來高卧水雲間。',64,'全唐诗/poet.song.59000.json','["何得清時便挂冠，歸來高卧水雲間。", "一輪白日易催老，百斛明珠難買閒。", "行止盡將隨野鶴，生涯都付與青山。", "庭前烏影高三丈，見說朱扉尚閉關。"]'),
('8801f60a-c02c-4935-943a-232e8f1734bd','送友人赴省','劉弇','宋','宋诗','song-poetry','','[]','佩劍携書入帝京，秋容如畫照行程。',64,'全唐诗/poet.song.59000.json','["佩劍携書入帝京，秋容如畫照行程。", "三千道路雖迢遞，萬里烟霄絕坦平。", "丹漢風高鵬翼健，曉天霜淺馬蹄輕。", "好將擲地金聲賦，奪取前春榜上名。"]'),
('950b0348-95dc-47d6-9a4b-aa3d5059f945','送友人赴省二首  其一','劉弇','宋','宋诗','song-poetry','','[]','飄飄勒馬出城闉，篋裏還爲席上珍。',64,'全唐诗/poet.song.59000.json','["飄飄勒馬出城闉，篋裏還爲席上珍。", "荆玉始分三獻日，瓊林終折一枝春。", "驚天動地文堪擲，捉月拏雲手定伸。", "正遇漢庭新用賦，子虛須屬茂陵人。"]'),
('6e17a4af-dcad-4e85-b061-7ee830921633','送友人赴省二首  其二','劉弇','宋','宋诗','song-poetry','','[]','久藴驚天動地文，乘秋得志正逢辰。',64,'全唐诗/poet.song.59000.json','["久藴驚天動地文，乘秋得志正逢辰。", "青錢萬選終須中，白玉三投始辨真。", "鶚薦比聲鄉貢日，鶑遷前試帝城春。", "漢庭方尚春秋學，須作平津第一人。"]'),
('0addac77-86c0-4ec6-8af6-13fab6cfcd71','冬日呈郭明遠二首  其一','劉弇','宋','宋诗','song-poetry','','[]','騷雅亡來幾百年，不圖今日見君篇。',64,'全唐诗/poet.song.59000.json','["騷雅亡來幾百年，不圖今日見君篇。", "遒豪壓倒元才子，清麗追回李謫仙。", "風月吟窮三寸舌，江山歸欠一囊錢。", "此時長嘯出門去，但覺遶梁遺韵傳。"]'),
('a56a5d2a-f612-4b2a-91bb-4f26866fb9d1','冬日呈郭明遠二首  其二','劉弇','宋','宋诗','song-poetry','','[]','底事遑遑不見容，秋來又見走西東。',64,'全唐诗/poet.song.59000.json','["底事遑遑不見容，秋來又見走西東。", "四時花月搜吟內，萬里江山險阻中。", "歸去但應存舌在，愁來莫更笑途窮。", "從今賈馬休談詠，恐起霜天刮面風。"]'),
('5ec4321a-6e85-470d-ace0-8b461dbd6842','春日送簽判陽承議','劉弇','宋','宋诗','song-poetry','','[]','春山野思萬千重，那更江頭來送公。',64,'全唐诗/poet.song.59000.json','["春山野思萬千重，那更江頭來送公。", "別淚滴流紅杏雨，離情搖曳綠楊風。", "一枝易遶南飛鵲，隻字難憑北塞鴻。", "惟有感恩情不斷，夜深長入夢魂中。"]'),
('4eff77c4-ace6-458a-aea6-22cf4a9be978','春日送林推官','劉弇','宋','宋诗','song-poetry','','[]','送君南浦忍分襟，注目春江烟水深。',64,'全唐诗/poet.song.59000.json','["送君南浦忍分襟，注目春江烟水深。", "思亂似雲無所著，情濃如酒不堪斟。", "杏花燒斷離人恨，杜宇啼穿去客心。", "別後願爲深夜蝶，翩翩飛夢去相尋。"]'),
('33a617c6-b29d-425f-ae5b-cd75255f67b1','贈柳秀才三首  其一','劉弇','宋','宋诗','song-poetry','','[]','應被功名誤一身，卜居歸就水雲耕。',64,'全唐诗/poet.song.59000.json','["應被功名誤一身，卜居歸就水雲耕。", "詩題招隠同誰和，賦奏閒居獨自成。", "三徑蓬蒿貧處士，五車經史富書生。", "幾回醉後顛狂甚，便擬騎鯨上太清。"]'),
('fb9760c2-c57d-40e2-8eed-c4a59c5d29f7','贈柳秀才三首  其二','劉弇','宋','宋诗','song-poetry','','[]','奔走文場十載勞，歸來三徑滿蓬蒿。',64,'全唐诗/poet.song.59000.json','["奔走文場十載勞，歸來三徑滿蓬蒿。", "麟窮西狩人誰念，龍卧南陽節自高。", "貧裏田園居四壁，吟中風月筆千毫。", "早知今日詩書誤，悔不當初學六韜。"]'),
('c704bace-556a-46f0-9c6a-4c69d43de20d','贈柳秀才三首  其三','劉弇','宋','宋诗','song-poetry','','[]','萬丈飛泉落筆端，源流渾覺海波寬。',64,'全唐诗/poet.song.59000.json','["萬丈飛泉落筆端，源流渾覺海波寬。", "若非學造淵騫寢，焉得詩登李杜壇。", "文苑春開紅芍藥，詞林秋削碧琅玕。", "篇成底事猶多困，只爲名高折却官。"]'),
('4ffc9f82-e7bf-49d2-b014-17420c4afc42','題蓮花市客肆壁二首  其一','劉弇','宋','宋诗','song-poetry','','[]','男子謀身豈易知，魚蝦燕雀莫相欺。',64,'全唐诗/poet.song.59000.json','["男子謀身豈易知，魚蝦燕雀莫相欺。", "蛟龍翻海非無日，鴻鵠沖天自有時。", "直把寸心睎孔孟，終攄餘藴繼皋夔。", "當年張禹荒唐輩，猶作炎劉帝者師。"]'),
('179dc88c-c977-45bf-9220-f61c98125628','題蓮花市客肆壁二首  其二','劉弇','宋','宋诗','song-poetry','','[]','片心長是樂清虛，一到蓮花喜有餘。',64,'全唐诗/poet.song.59000.json','["片心長是樂清虛，一到蓮花喜有餘。", "柳倚古溪風不斷，路迷芳草客來疏。", "樽無美酒難浮蟻，手有文竿未食魚。", "細草晚天時躍馬，紅塵無復上衣裾。"]'),
('02ae8b7b-484d-49df-8c68-e8074aa45995','真陽阻水','劉弇','宋','宋诗','song-poetry','','[]','真陽城下漲春濤，船覆車摧滿眼愁。',64,'全唐诗/poet.song.59000.json','["真陽城下漲春濤，船覆車摧滿眼愁。", "泛泛我非援溺手，滔滔誰是濟川舟。", "一城直恐爲魚鼈，四境何緣辨馬牛。", "焉得長鯨浮到海，吸乾狂浪得安流。"]'),
('83647ea3-ab72-458e-a3dd-9838e6547a58','春日舟中即事','劉弇','宋','宋诗','song-poetry','','[]','不因門有北堂親，肯泛孤舟瘴海濱。',64,'全唐诗/poet.song.59000.json','["不因門有北堂親，肯泛孤舟瘴海濱。", "萬里江湖愁去客，一春風雨厭行人。", "花朝水國留題懶，月夜鄉園入夢頻。", "每被烟波驚破膽，却思雲石自由身。"]'),
('c8d89054-e59e-4543-8ba7-583a4d0f2ce4','春日舟中喜晴三首  其一','劉弇','宋','宋诗','song-poetry','','[]','霧斂雲回雨却殘，衣單猶尚怯朝寒。',64,'全唐诗/poet.song.59000.json','["霧斂雲回雨却殘，衣單猶尚怯朝寒。", "烟塵暗處江山窄，日月光來宇宙寬。", "漁棹不憂灘浪險，客輪惟喜路程乾。", "關關珍重梢頭鳥，每到晴中語亦懽。"]'),
('f0d18b49-cac5-4421-9e76-95a5a1763b5d','春日舟中喜晴三首  其二','劉弇','宋','宋诗','song-poetry','','[]','久厭梅蒸蠹客袍，一逢晴色喜陶陶。',64,'全唐诗/poet.song.59000.json','["久厭梅蒸蠹客袍，一逢晴色喜陶陶。", "嵐烟散後青山出，海霧開來日月高。", "四海廓成清世界，五湖消滅惡風濤。", "九衢來往趨名者，遂免泥塗僕僕勞。"]'),
('6b7d25d3-a852-4468-9586-ae06fd0aea28','春日舟中喜晴三首  其三','劉弇','宋','宋诗','song-poetry','','[]','安得繩絲萬丈長，絆留烏影在扶桑。',64,'全唐诗/poet.song.59000.json','["安得繩絲萬丈長，絆留烏影在扶桑。", "三春厭倦泥塗走，一旦親逢日月光。", "山有晚烟青鬰鬰，天無陰霧碧蒼蒼。", "雨餘更荷風相照，吹送殘花滿院香。"]'),
('a3ee070f-a5fb-41ef-9c3e-e35e2c776e08','題清風亭','劉弇','宋','宋诗','song-poetry','','[]','四面無塵一徑深，嵐烟吹盡好披襟。',64,'全唐诗/poet.song.59000.json','["四面無塵一徑深，嵐烟吹盡好披襟。", "寒生醉榻宜春睡，冷入詩窗豁夜吟。", "坐有清凉非待扇，夏無煩慍不須琴。", "泠然試把闌干倚，頓起飄飄物外心。"]'),
('b3c605df-8e17-45a9-ac7d-6caf22a4cc54','題韶州宣溪亭','劉弇','宋','宋诗','song-poetry','','[]','片帆西下泊江亭，風物蕭疏慘暮程。',64,'全唐诗/poet.song.59000.json','["片帆西下泊江亭，風物蕭疏慘暮程。", "山色尚凝遷謫恨，溪流猶瀉怨嗟聲。", "一朝逐客仙舟過，萬古行人玉筯傾。", "不待鷓鴣啼落日，自然臨景易牽情。"]'),
('52a0858d-4752-4e81-b9e2-6cb754463540','題廣州浴日亭','劉弇','宋','宋诗','song-poetry','','[]','誰識咸池萬頃中，源流窮處與天通。',64,'全唐诗/poet.song.59000.json','["誰識咸池萬頃中，源流窮處與天通。", "氣蒸古木千巖曉，浪拍扶桑四遠紅。", "焰焰驪珠初出海，騰騰烏翼漸摩空。", "不須更問乘槎客，只此波間是月宮。"]'),
('20f63efd-9489-43fa-9c4d-f53b975ca12e','海山樓晚望','劉弇','宋','宋诗','song-poetry','','[]','登高懷遠思依依，目斷滄洲舊釣磯。',64,'全唐诗/poet.song.59000.json','["登高懷遠思依依，目斷滄洲舊釣磯。", "城上兩三聲畫角，天涯千萬里斜暉。", "烟抽綠草隨洲轉，風遞輕烟貼水飛。", "到此自然堪下淚，不須啼鳥勸如歸。"]'),
('f3fa9a0b-e2c3-4efa-b38f-6b442d469c37','春日即事','劉弇','宋','宋诗','song-poetry','','[]','歲月催人誤壯圖，風清官况强支吾。',64,'全唐诗/poet.song.59000.json','["歲月催人誤壯圖，風清官况强支吾。", "春來酒病尋常有，老去花迷大殺無。", "慵裏盛添詩債負，閒中贏得睡工夫。", "誰知到此扁舟內，白面書生瘦矣乎。"]'),
('5dcb4553-5acc-40a2-a594-c5f1d37e308a','舟中驚夏','劉弇','宋','宋诗','song-poetry','','[]','牡丹纔過石榴開，歲月驚人老易催。',64,'全唐诗/poet.song.59000.json','["牡丹纔過石榴開，歲月驚人老易催。", "一面紅顔春遞去，滿簪華髮夏催來。", "蠅頭利祿徒勞耳，麟閣功名大晚哉。", "不必更增川上嘆，及時行樂且銜盃。"]'),
('6ee166da-abfa-47c8-91df-d89b3d42c54a','觀劉禹錫題湟川記','劉弇','宋','宋诗','song-poetry','','[]','誰道連州海瘴邊，只消禹錫一雄篇。',64,'全唐诗/poet.song.59000.json','["誰道連州海瘴邊，只消禹錫一雄篇。", "江山草木皆增價，風月烟霞總直錢。", "十二亭臺塵外境，一千疆界洞中天。", "自經大筆留題後，從此湟川勝洛川。"]'),
('a668ba73-3878-4f22-a14f-a8eb0a9a20a6','贈錢承務吟翁','劉弇','宋','宋诗','song-poetry','','[]','何事新霜上鬢毛，從前都爲作詩勞。',64,'全唐诗/poet.song.59000.json','["何事新霜上鬢毛，從前都爲作詩勞。", "老松經歲材方勁，古檜吟風韵更高。", "可播管弦升樂府，自堪奴僕命離騷。", "冥搜直到窮源處，驚得神啼與鬼號。"]'),
('6bfad4df-a2af-4287-aa90-3f735f6863a9','題清漪亭','劉弇','宋','宋诗','song-poetry','','[]','平昔江流清得名，只今池面勝江清。',64,'全唐诗/poet.song.59000.json','["平昔江流清得名，只今池面勝江清。", "人間有鏡磨秋骨，天上無宮敵水晶。", "月借嬋娟相表裏，路分瀟洒入逢迎。", "會雖飽占銀潢魄，莫似滄浪濯垢纓。"]'),
('d4e2c302-1179-41e5-9168-e2304f142321','次韵譚令尹茅庵十詠  其一','劉弇','宋','宋诗','song-poetry','','[]','雲卷公餘迹，鋒藏用外神。',24,'全唐诗/poet.song.59000.json','["雲卷公餘迹，鋒藏用外神。", "故將容足地，聊學坐禪人。"]'),
('c7b8d9a9-edc5-4937-8edb-34c44b9f53c4','次韵譚令尹茅庵十詠  其二','劉弇','宋','宋诗','song-poetry','','[]','物華他日好，歲月箇中延。',24,'全唐诗/poet.song.59000.json','["物華他日好，歲月箇中延。", "欲識無餘事，纔如一指禪。"]'),
('ca4d2233-07be-4021-a50b-54f91ef42c94','次韵譚令尹茅庵十詠  其三','劉弇','宋','宋诗','song-poetry','','[]','歊風青苯䔿，浴月碧漣漪。',24,'全唐诗/poet.song.59000.json','["歊風青苯䔿，浴月碧漣漪。", "僅比蝸廬客，肯慚衡泌詩。"]'),
